import type { Article } from '../../../common/types/law.types';

export const ARTICLES_CONST_FORMOSA: Article[] = [
  { id: 'const-formosa-art-1', lawId: 'const-formosa', number: '1', title: 'Forma de gobierno republicana y democrático-participativa', originalText: `La Provincia de Formosa, en ejercicio de su autonomía y como parte integrante e inescindible de la Nación Argentina adopta para su gobierno el sistema representativo, republicano, democrático-participativo y social, y se reserva para sí todos los poderes no delegados expresamente al Gobierno Federal en la Constitución Nacional, incluyendo a los que sean de ejercicio compartido, concurrente o conjunto.`, currentText: `La Provincia de Formosa, en ejercicio de su autonomía y como parte integrante e inescindible de la Nación Argentina adopta para su gobierno el sistema representativo, republicano, democrático-participativo y social, y se reserva para sí todos los poderes no delegados expresamente al Gobierno Federal en la Constitución Nacional, incluyendo a los que sean de ejercicio compartido, concurrente o conjunto.`, plainLanguageExplanation: 'Formosa adopta el gobierno republicano, representativo, democrático-participativo y social. Se reserva todos los poderes no delegados expresamente a la Nación, incluyendo los de ejercicio compartido o concurrente.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['forma de gobierno', 'autonomía provincial', 'poderes no delegados', 'sistema republicano'], order: 0, segments: [], amendments: [] },
  { id: 'const-formosa-art-2', lawId: 'const-formosa', number: '2', title: 'Límites territoriales de la Provincia', originalText: `Los límites territoriales de la Provincia son los del ex-territorio nacional de su nombre, determinados por la Ley nacional Nº 1532, a saber: por el Norte, el río Pilcomayo y la línea divisoria con Bolivia; por el Oeste, una línea con rumbo Sur, que partiendo de la línea anterior, pase por el Fuerte Belgrano, hasta tocar el río Bermejo; por el Sur, este río siguiéndolo por el brazo llamado Teuco, hasta su desembocadura en el Paraguay; y por el Este, el río Paraguay, que la separa de la República de ese nombre, sin perjuicio de los reclamos que por derechos históricos y geopolíticos correspondan. Toda ley que autorice su modificación requerirá el voto favorable de la unanimidad de los miembros que integran la Legislatura, cuando ello signifique un desmembramiento de su territorio.`, currentText: `Los límites territoriales de la Provincia son los del ex-territorio nacional de su nombre, determinados por la Ley nacional Nº 1532, a saber: por el Norte, el río Pilcomayo y la línea divisoria con Bolivia; por el Oeste, una línea con rumbo Sur, que partiendo de la línea anterior, pase por el Fuerte Belgrano, hasta tocar el río Bermejo; por el Sur, este río siguiéndolo por el brazo llamado Teuco, hasta su desembocadura en el Paraguay; y por el Este, el río Paraguay, que la separa de la República de ese nombre, sin perjuicio de los reclamos que por derechos históricos y geopolíticos correspondan. Toda ley que autorice su modificación requerirá el voto favorable de la unanimidad de los miembros que integran la Legislatura, cuando ello signifique un desmembramiento de su territorio.`, plainLanguageExplanation: 'Los límites de Formosa están fijados por la Ley nacional 1532: el río Pilcomayo al norte, el Bermejo al sur, el Paraguay al este y una línea al oeste. Cualquier modificación que implique desmembramiento territorial requiere el voto unánime de la Legislatura.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['límites territoriales', 'Ley 1532', 'río Pilcomayo', 'desmembramiento territorial'], order: 1, segments: [], amendments: [] },
  { id: 'const-formosa-art-3', lawId: 'const-formosa', number: '3', title: 'Capital provincial: ciudad de Formosa', originalText: `Declárase capital de la Provincia y asiento de los órganos de su gobierno, a la ciudad de Formosa.`, currentText: `Declárase capital de la Provincia y asiento de los órganos de su gobierno, a la ciudad de Formosa.`, plainLanguageExplanation: 'La ciudad de Formosa es la capital de la Provincia y sede de todos sus órganos de gobierno.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['capital provincial', 'ciudad de Formosa', 'sede del gobierno'], order: 2, segments: [], amendments: [] },
  { id: 'const-formosa-art-4', lawId: 'const-formosa', number: '4', title: 'Soberanía popular y democracia directa', originalText: `La soberanía reside en el pueblo de la Provincia, quien delibera y gobierna a través de sus representantes y autoridades establecidas en esta Constitución, y por medio del plebiscito, el referéndum y la consulta popular según las leyes que reglamenten su ejercicio.`, currentText: `La soberanía reside en el pueblo de la Provincia, quien delibera y gobierna a través de sus representantes y autoridades establecidas en esta Constitución, y por medio del plebiscito, el referéndum y la consulta popular según las leyes que reglamenten su ejercicio.`, plainLanguageExplanation: 'La soberanía pertenece al pueblo de Formosa, que ejerce el poder a través de sus representantes y también directamente mediante plebiscito, referéndum y consulta popular.', practicalEffects: [], examples: ['Un referéndum provincial para ratificar una reforma constitucional es una forma de ejercicio directo de la soberanía popular.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['soberanía popular', 'plebiscito', 'referéndum', 'consulta popular', 'democracia participativa'], order: 3, segments: [], amendments: [] },
  { id: 'const-formosa-art-5', lawId: 'const-formosa', number: '5', title: 'Derechos no enumerados y derecho a la vida', originalText: `Los derechos, declaraciones y garantías enumerados en la Constitución Nacional y que esta Constitución da por reproducidos, no serán entendidos como negación de otros derechos y garantías no enumerados, pero que nacen del principio de la soberanía del pueblo, de la forma republicana de gobierno y que corresponden al hombre en su calidad de tal, como individuo y como integrante de las formaciones sociales en donde desarrolla su personalidad y busca el cumplimiento de los deberes ineludibles de solidaridad y seguridad política, económica y social, siendo los mismos operativos. Todo ser humano tiene derecho a la vida desde el momento de su concepción y a su integridad psicofísica, espiritual y moral. El Estado Provincial propenderá a la concientización de las responsabilidades inherentes a la generación de la vida.`, currentText: `Los derechos, declaraciones y garantías enumerados en la Constitución Nacional y que esta Constitución da por reproducidos, no serán entendidos como negación de otros derechos y garantías no enumerados, pero que nacen del principio de la soberanía del pueblo, de la forma republicana de gobierno y que corresponden al hombre en su calidad de tal, como individuo y como integrante de las formaciones sociales en donde desarrolla su personalidad y busca el cumplimiento de los deberes ineludibles de solidaridad y seguridad política, económica y social, siendo los mismos operativos. Todo ser humano tiene derecho a la vida desde el momento de su concepción y a su integridad psicofísica, espiritual y moral. El Estado Provincial propenderá a la concientización de las responsabilidades inherentes a la generación de la vida.`, plainLanguageExplanation: 'Los derechos que no están enumerados en la Constitución también son reconocidos si emergen de la soberanía popular o de la forma republicana de gobierno. Todo ser humano tiene derecho a la vida desde su concepción y a su integridad psicofísica, espiritual y moral.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos no enumerados', 'derecho a la vida', 'integridad personal', 'garantías constitucionales'], order: 4, segments: [], amendments: [] },
  { id: 'const-formosa-art-6', lawId: 'const-formosa', number: '6', title: 'Cláusulas federales: política hacia la Nación', originalText: `El Gobierno Provincial promueve: 1) Un federalismo de integración y concertación que facilite el desarrollo armónico de la Provincia y de la Nación. 2) Una equitativa y eficiente distribución de competencias entre el Estado Provincial y el Nacional, para afirmar el poder de decisión en las facultades propias, delegadas y concurrentes. 3) La descentralización geográfica y administrativa de las empresas u organismos del Estado federal, su asentamiento en la Provincia o en la región donde realizan su principal actividad y la participación de éstas en la dirección y explotación de aquéllas. 4) La federalización del sistema financiero a fin de orientar el ahorro provincial a la inversión productiva local. 5) La revisión de las relaciones con la Nación en materia de coparticipación impositiva y de las políticas económicas, financieras y aduaneras. 6) La compatibilización de las acciones que, en los ámbitos económico-social y cultural, realicen entes públicos nacionales con las que, de igual carácter, cumplen los organismos del Estado Provincial. 7) El acceso y participación de la Provincia en estudios, planes y decisiones de la administración federal, y el control de su ejecución cuando se encuentren comprometidos sus legítimos intereses. 8) La realización de gestiones y acuerdos en el orden internacional con fines de satisfacer sus objetivos e intereses, sin perjuicio de las facultades del Gobierno Federal en la materia.`, currentText: `El Gobierno Provincial promueve: 1) Un federalismo de integración y concertación que facilite el desarrollo armónico de la Provincia y de la Nación. 2) Una equitativa y eficiente distribución de competencias entre el Estado Provincial y el Nacional, para afirmar el poder de decisión en las facultades propias, delegadas y concurrentes. 3) La descentralización geográfica y administrativa de las empresas u organismos del Estado federal, su asentamiento en la Provincia o en la región donde realizan su principal actividad y la participación de éstas en la dirección y explotación de aquéllas. 4) La federalización del sistema financiero a fin de orientar el ahorro provincial a la inversión productiva local. 5) La revisión de las relaciones con la Nación en materia de coparticipación impositiva y de las políticas económicas, financieras y aduaneras. 6) La compatibilización de las acciones que, en los ámbitos económico-social y cultural, realicen entes públicos nacionales con las que, de igual carácter, cumplen los organismos del Estado Provincial. 7) El acceso y participación de la Provincia en estudios, planes y decisiones de la administración federal, y el control de su ejecución cuando se encuentren comprometidos sus legítimos intereses. 8) La realización de gestiones y acuerdos en el orden internacional con fines de satisfacer sus objetivos e intereses, sin perjuicio de las facultades del Gobierno Federal en la materia.`, plainLanguageExplanation: 'El gobierno provincial impulsa un federalismo de integración con la Nación, procura una distribución equitativa de competencias y coparticipación impositiva, y busca descentralizar organismos federales hacia las provincias. También puede celebrar acuerdos internacionales para satisfacer sus intereses, sin afectar las facultades federales.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['federalismo', 'coparticipación impositiva', 'competencias provinciales', 'descentralización', 'acuerdos internacionales'], order: 5, segments: [], amendments: [] },
  { id: 'const-formosa-art-7', lawId: 'const-formosa', number: '7', title: 'Deber de representantes ante organismos nacionales', originalText: `Todo representante provincial ante el Gobierno, Congreso o Convención Constituyente Nacionales, así como ante organismos federales, regionales o interprovinciales, propenderá a desarrollar las acciones pertinentes para la defensa, instrumentación y cumplimiento de las Cláusulas Federales del artículo 6º y de los principios y normas sancionados en esta Constitución.`, currentText: `Todo representante provincial ante el Gobierno, Congreso o Convención Constituyente Nacionales, así como ante organismos federales, regionales o interprovinciales, propenderá a desarrollar las acciones pertinentes para la defensa, instrumentación y cumplimiento de las Cláusulas Federales del artículo 6º y de los principios y normas sancionados en esta Constitución.`, plainLanguageExplanation: 'Quienes representen a Formosa ante el gobierno nacional, el Congreso u organismos federales o interprovinciales tienen el deber de defender y promover los principios federales establecidos en el artículo 6 y en esta Constitución.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['representantes provinciales', 'cláusulas federales', 'defensa de intereses provinciales'], order: 6, segments: [], amendments: [] },
  { id: 'const-formosa-art-8', lawId: 'const-formosa', number: '8', title: 'Causas Malvinas, Pilcomayo y reparación histórica', originalText: `Las causas Malvinas y Río Pilcomayo constituyen para la Provincia, una causa nacional. La reparación histórica es una causa provincial. Ambas son irrenunciables e imprescriptibles.`, currentText: `Las causas Malvinas y Río Pilcomayo constituyen para la Provincia, una causa nacional. La reparación histórica es una causa provincial. Ambas son irrenunciables e imprescriptibles.`, plainLanguageExplanation: 'Formosa declara irrenunciables e imprescriptibles la causa Malvinas y la causa del río Pilcomayo (como causa nacional), así como la reparación histórica de la Provincia (como causa provincial).', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Malvinas', 'Río Pilcomayo', 'reparación histórica', 'irrenunciable', 'imprescriptible'], order: 7, segments: [], amendments: [] },
  { id: 'const-formosa-art-9', lawId: 'const-formosa', number: '9', title: 'Igualdad y prohibición de discriminación', originalText: `Todos los habitantes de la Provincia son por su naturaleza, libres, independientes e iguales en dignidad y en derecho. Queda prohibida toda discriminación por razones de raza, lengua o religión.`, currentText: `Todos los habitantes de la Provincia son por su naturaleza, libres, independientes e iguales en dignidad y en derecho. Queda prohibida toda discriminación por razones de raza, lengua o religión.`, plainLanguageExplanation: 'Todos los habitantes de Formosa son libres e iguales en dignidad y derechos. Está expresamente prohibida la discriminación por raza, lengua o religión.', practicalEffects: [], examples: ['Una persona no puede ser excluida de un servicio público por su origen étnico o por la religión que profesa.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['igualdad', 'no discriminación', 'dignidad', 'libertad', 'derechos humanos'], order: 8, segments: [], amendments: [] },
  { id: 'const-formosa-art-10', lawId: 'const-formosa', number: '10', title: 'Libertad de expresión e información', originalText: `Es inviolable el derecho que toda persona tiene de expresar libremente sus ideas y opiniones y de difundirlas por cualquier medio, sin censura de ninguna clase. Ninguna ley, ni autoridad, podrán restringir la libre expresión y difusión de las ideas, ni trabar, impedir, ni suspender por motivo alguno, el funcionamiento de los talleres tipográficos, difusoras radiales y demás medios idóneos para la emisión y propagación del pensamiento, ni secuestrar sus maquinarias o enseres, ni clausurar sus locales. Aquel que abusare de este derecho será responsable de los delitos comunes en que incurriere a su amparo y de la lesión que causare a quienes resultaren afectados. Todos los habitantes de la Provincia gozan del derecho al libre acceso a las fuentes de información.`, currentText: `Es inviolable el derecho que toda persona tiene de expresar libremente sus ideas y opiniones y de difundirlas por cualquier medio, sin censura de ninguna clase. Ninguna ley, ni autoridad, podrán restringir la libre expresión y difusión de las ideas, ni trabar, impedir, ni suspender por motivo alguno, el funcionamiento de los talleres tipográficos, difusoras radiales y demás medios idóneos para la emisión y propagación del pensamiento, ni secuestrar sus maquinarias o enseres, ni clausurar sus locales. Aquel que abusare de este derecho será responsable de los delitos comunes en que incurriere a su amparo y de la lesión que causare a quienes resultaren afectados. Todos los habitantes de la Provincia gozan del derecho al libre acceso a las fuentes de información.`, plainLanguageExplanation: 'La libertad de expresión es inviolable: ninguna ley ni autoridad puede censurar ideas ni cerrar medios de comunicación. Quien abuse del derecho responde penalmente. Además, todos tienen derecho al libre acceso a las fuentes de información.', practicalEffects: [], examples: ['Un medio periodístico no puede ser clausurado por el gobierno provincial por su línea editorial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad de expresión', 'censura', 'libertad de prensa', 'acceso a la información'], order: 9, segments: [], amendments: [] },
  { id: 'const-formosa-art-11', lawId: 'const-formosa', number: '11', title: 'Prohibición de monopolio de medios de comunicación', originalText: `Queda terminantemente prohibido el acaparamiento de las existencias de papel y el monopolio de cualquier medio de difusión por parte de los organismos gubernamentales o grupos económicos de cualquier naturaleza, así como la financiación de tales empresas, por medio de fuentes económicas que, como las subvenciones secretas o la publicidad comercial condicionada, coarten, por omisión o deformación de la verdad, la libre expresión de la noticia y el comentario.`, currentText: `Queda terminantemente prohibido el acaparamiento de las existencias de papel y el monopolio de cualquier medio de difusión por parte de los organismos gubernamentales o grupos económicos de cualquier naturaleza, así como la financiación de tales empresas, por medio de fuentes económicas que, como las subvenciones secretas o la publicidad comercial condicionada, coarten, por omisión o deformación de la verdad, la libre expresión de la noticia y el comentario.`, plainLanguageExplanation: 'Está prohibido que el Estado o grupos económicos monopolicen medios de comunicación o acaparen papel de prensa. También se prohíbe financiar medios con subvenciones secretas o publicidad condicionada que limiten la libertad de información.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['monopolio de medios', 'libertad de prensa', 'subvenciones secretas', 'pluralismo informativo'], order: 10, segments: [], amendments: [] },
  { id: 'const-formosa-art-12', lawId: 'const-formosa', number: '12', title: 'Derecho de réplica y protección del honor', originalText: `La libertad de expresión comprende también el derecho de las publicaciones a obtener los elementos necesarios a tal fin y la facultad que tiene toda persona a la réplica o rectificación ante una referencia o información susceptible de afectar su reputación personal, familiar o social, la que deberá publicarse gratuitamente, en igual forma y con el mismo medio utilizado. Una ley especial asegurará la protección debida a toda persona o entidad contra los ataques a su honra, reputación, vida privada y familiar, cuando ésta sea lesionada por cualquiera de los medios de difusión de las ideas del pensamiento, determinado en el artículo 10.`, currentText: `La libertad de expresión comprende también el derecho de las publicaciones a obtener los elementos necesarios a tal fin y la facultad que tiene toda persona a la réplica o rectificación ante una referencia o información susceptible de afectar su reputación personal, familiar o social, la que deberá publicarse gratuitamente, en igual forma y con el mismo medio utilizado. Una ley especial asegurará la protección debida a toda persona o entidad contra los ataques a su honra, reputación, vida privada y familiar, cuando ésta sea lesionada por cualquiera de los medios de difusión de las ideas del pensamiento, determinado en el artículo 10.`, plainLanguageExplanation: 'Toda persona tiene derecho a responder o rectificar gratuitamente ante cualquier medio que haya publicado información que afecte su reputación. Una ley especial protege el honor y la vida privada frente a ataques difundidos por medios de comunicación.', practicalEffects: [], examples: ['Si un diario publica información falsa sobre una persona, esta puede exigir que se publique su rectificación en el mismo medio y espacio.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho de réplica', 'rectificación', 'honor', 'vida privada', 'reputación'], order: 11, segments: [], amendments: [] },
  { id: 'const-formosa-art-13', lawId: 'const-formosa', number: '13', title: 'Inviolabilidad del domicilio', originalText: `El domicilio es el asilo inviolable de las personas; nadie podrá penetrar en él sin permiso de su dueño, salvo por orden escrita y fundada de juez competente, y nunca después de las diecinueve, ni antes de las siete horas, salvo para socorrer las víctimas de un crimen o accidente. La ley determinará las formalidades y los casos en que puede procederse al allanamiento.`, currentText: `El domicilio es el asilo inviolable de las personas; nadie podrá penetrar en él sin permiso de su dueño, salvo por orden escrita y fundada de juez competente, y nunca después de las diecinueve, ni antes de las siete horas, salvo para socorrer las víctimas de un crimen o accidente. La ley determinará las formalidades y los casos en que puede procederse al allanamiento.`, plainLanguageExplanation: 'Nadie puede entrar a un domicilio sin el permiso del dueño, excepto con orden judicial escrita y fundada. Los allanamientos solo pueden realizarse entre las 7 y las 19 horas, salvo emergencias. La ley regula los casos y formalidades del allanamiento.', practicalEffects: [], examples: ['La policía necesita una orden judicial para allanar una vivienda; ingresar sin ella viola este artículo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inviolabilidad del domicilio', 'allanamiento', 'orden judicial', 'garantía procesal'], order: 12, segments: [], amendments: [] },
  { id: 'const-formosa-art-14', lawId: 'const-formosa', number: '14', title: 'Inviolabilidad de correspondencia y comunicaciones', originalText: `Los papeles particulares, la correspondencia epistolar y las comunicaciones telegráficas, telefónicas, cablegráficas o de cualquier otra especie, son inviolables, y nunca podrá hacerse sus registros, exámenes o interceptaciones, sino conforme a las leyes que se establecieren para casos limitados y concretos. Los que sean sustraídos o recogidos contra las disposiciones de aquéllas no podrán ser utilizados en procedimientos judiciales ni administrativos. Quedan asimismo protegidos los datos públicos o privados de los habitantes.`, currentText: `Los papeles particulares, la correspondencia epistolar y las comunicaciones telegráficas, telefónicas, cablegráficas o de cualquier otra especie, son inviolables, y nunca podrá hacerse sus registros, exámenes o interceptaciones, sino conforme a las leyes que se establecieren para casos limitados y concretos. Los que sean sustraídos o recogidos contra las disposiciones de aquéllas no podrán ser utilizados en procedimientos judiciales ni administrativos. Quedan asimismo protegidos los datos públicos o privados de los habitantes.`, plainLanguageExplanation: 'Las cartas, llamadas telefónicas y demás comunicaciones privadas son inviolables. Solo pueden interceptarse en casos previstos por ley. Las comunicaciones obtenidas en violación de esta norma no pueden usarse como prueba en juicios. También se protegen los datos personales de los habitantes.', practicalEffects: [], examples: ['Una escucha telefónica realizada sin autorización judicial no puede ser usada como prueba en un proceso penal provincial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inviolabilidad de comunicaciones', 'privacidad', 'interceptación', 'datos personales', 'prueba ilícita'], order: 13, segments: [], amendments: [] },
  { id: 'const-formosa-art-15', lawId: 'const-formosa', number: '15', title: 'Garantías en la detención de personas', originalText: `Ninguna persona puede ser detenida sin orden escrita de juez competente, fundada en semiplena prueba o indicio vehemente de la comisión de un hecho punible, salvo caso de flagrante delito, en que podrá ser aprehendida por cualquier habitante y conducida inmediatamente ante la autoridad respectiva. Todo arrestado o detenido será notificado de la causa de su detención dentro de las veinticuatro horas; en el mismo plazo deberá darse aviso al juez competente, poniéndoselo a su disposición con los antecedentes del hecho que lo motiva.`, currentText: `Ninguna persona puede ser detenida sin orden escrita de juez competente, fundada en semiplena prueba o indicio vehemente de la comisión de un hecho punible, salvo caso de flagrante delito, en que podrá ser aprehendida por cualquier habitante y conducida inmediatamente ante la autoridad respectiva. Todo arrestado o detenido será notificado de la causa de su detención dentro de las veinticuatro horas; en el mismo plazo deberá darse aviso al juez competente, poniéndoselo a su disposición con los antecedentes del hecho que lo motiva.`, plainLanguageExplanation: 'Nadie puede ser detenido sin orden judicial escrita, salvo en caso de flagrante delito. El detenido debe ser informado del motivo de su detención dentro de las 24 horas y puesto a disposición del juez competente en ese mismo plazo.', practicalEffects: [], examples: ['Si la policía detiene a una persona sin orden judicial y sin haberla sorprendido en flagrante delito, la detención es inconstitucional.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['detención', 'orden judicial', 'flagrante delito', 'garantías procesales', 'libertad personal'], order: 14, segments: [], amendments: [] },
  { id: 'const-formosa-art-16', lawId: 'const-formosa', number: '16', title: 'Derecho a la defensa en juicio', originalText: `Es inviolable la defensa en juicio de la persona y de los derechos. La Provincia está obligada a proveer a la defensa del habitante sin recursos o incapacitado. En ningún caso los defensores de quienes se hallaren amenazados en su libertad o privados de ella podrán ser molestados con motivo del ejercicio de la defensa, ello sin perjuicio del poder disciplinario de los jueces. Tampoco, por igual motivo, podrán allanarse sus domicilios o locales profesionales.`, currentText: `Es inviolable la defensa en juicio de la persona y de los derechos. La Provincia está obligada a proveer a la defensa del habitante sin recursos o incapacitado. En ningún caso los defensores de quienes se hallaren amenazados en su libertad o privados de ella podrán ser molestados con motivo del ejercicio de la defensa, ello sin perjuicio del poder disciplinario de los jueces. Tampoco, por igual motivo, podrán allanarse sus domicilios o locales profesionales.`, plainLanguageExplanation: 'La defensa en juicio es un derecho inviolable. La Provincia debe garantizar defensa gratuita a quienes no pueden costearla. Los abogados defensores no pueden ser molestados ni allanados sus domicilios o estudios por razón del ejercicio de su función.', practicalEffects: [], examples: ['Una persona imputada sin dinero tiene derecho a un defensor público gratuito provisto por el Estado provincial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['defensa en juicio', 'defensor público', 'debido proceso', 'abogado defensor'], order: 15, segments: [], amendments: [] },
  { id: 'const-formosa-art-17', lawId: 'const-formosa', number: '17', title: 'Acción de hábeas corpus', originalText: `Toda persona detenida sin orden emanada en legal forma de autoridad competente, por juez incompetente o por cualquier autoridad o individuo, o a quién arbitrariamente le negare, privare, restringiere o amenazare en su libertad o en el ejercicio de sus derechos individuales, con exclusión de los patrimoniales, podrá por si o por terceros en su nombre, sin necesidad de mandato, valiéndose de cualquier medio de comunicación y a cualquier hora, promover acción de hábeas corpus ante un juez letrado inmediato, sin distinción de fueros ni de instancias, restricción o amenaza de su libertad o en el ejercicio de sus derechos individuales. El juez del hábeas corpus ejercerá su potestad jurisdiccional por sobre todo otro poder o autoridad pública. La acción del hábeas corpus podrá instaurarse sin ninguna formalidad procesal. Toda vez que se tratare de amparar la libertad física, el juez hará comparecer a la persona afectada y al autor de la afectación dentro de las veinticuatro horas. Examinará el caso y hará cesar inmediatamente la afectación si ésta no proviniere de autoridad competente o si no cumplimentare los recaudos constitucionales y legales. Dispondrá asimismo las medidas correspondientes a la responsabilidad de quien expidió la orden y ejecutó el acto. Cuando un juez tuviere conocimiento de que alguna persona se hallare arbitrariamente detenida, confinada en su libertad por un funcionario o por un particular, podrá expedir de oficio el mandamiento de hábeas corpus. Una ley especial reglamentará las formas sumarísimas de hacer efectiva esta garantía. Ningún juez podrá denegar la acción de hábeas corpus fundado en el hecho de no haberse sancionado la ley reglamentaria, en cuyo caso deberá arbitrar las medidas adecuadas para hacer efectiva esta garantía. Todo funcionario o empleado, sin excepción de ninguna clase, está obligado a dar inmediato cumplimiento a las órdenes que impartiere el juez del hábeas corpus. La ley establecerá las penalidades que correspondieren a quienes rehusaren o descuidaren su cumplimiento. Procederá esta acción en los casos de agravación ilegítima de la forma y condiciones en que se cumple la privación de libertad, sin perjuicio de las facultades propias del juez del proceso, si lo hubiere.`, currentText: `Toda persona detenida sin orden emanada en legal forma de autoridad competente, por juez incompetente o por cualquier autoridad o individuo, o a quién arbitrariamente le negare, privare, restringiere o amenazare en su libertad o en el ejercicio de sus derechos individuales, con exclusión de los patrimoniales, podrá por si o por terceros en su nombre, sin necesidad de mandato, valiéndose de cualquier medio de comunicación y a cualquier hora, promover acción de hábeas corpus ante un juez letrado inmediato, sin distinción de fueros ni de instancias, restricción o amenaza de su libertad o en el ejercicio de sus derechos individuales. El juez del hábeas corpus ejercerá su potestad jurisdiccional por sobre todo otro poder o autoridad pública. La acción del hábeas corpus podrá instaurarse sin ninguna formalidad procesal. Toda vez que se tratare de amparar la libertad física, el juez hará comparecer a la persona afectada y al autor de la afectación dentro de las veinticuatro horas. Examinará el caso y hará cesar inmediatamente la afectación si ésta no proviniere de autoridad competente o si no cumplimentare los recaudos constitucionales y legales. Dispondrá asimismo las medidas correspondientes a la responsabilidad de quien expidió la orden y ejecutó el acto. Cuando un juez tuviere conocimiento de que alguna persona se hallare arbitrariamente detenida, confinada en su libertad por un funcionario o por un particular, podrá expedir de oficio el mandamiento de hábeas corpus. Una ley especial reglamentará las formas sumarísimas de hacer efectiva esta garantía. Ningún juez podrá denegar la acción de hábeas corpus fundado en el hecho de no haberse sancionado la ley reglamentaria, en cuyo caso deberá arbitrar las medidas adecuadas para hacer efectiva esta garantía. Todo funcionario o empleado, sin excepción de ninguna clase, está obligado a dar inmediato cumplimiento a las órdenes que impartiere el juez del hábeas corpus. La ley establecerá las penalidades que correspondieren a quienes rehusaren o descuidaren su cumplimiento. Procederá esta acción en los casos de agravación ilegítima de la forma y condiciones en que se cumple la privación de libertad, sin perjuicio de las facultades propias del juez del proceso, si lo hubiere.`, plainLanguageExplanation: 'Cualquier persona detenida ilegítimamente puede interponer hábeas corpus ante cualquier juez, sin formalidades, a cualquier hora y por cualquier medio. El juez debe resolver en 24 horas, hacer cesar la detención ilegal y puede actuar de oficio. Todos los funcionarios están obligados a cumplir las órdenes del juez de hábeas corpus.', practicalEffects: [], examples: ['Un familiar puede presentar un hábeas corpus de urgencia si su pariente fue detenido por la policía sin orden judicial ni flagrante delito.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['hábeas corpus', 'libertad personal', 'detención ilegal', 'garantía constitucional'], order: 16, segments: [], amendments: [] },
  { id: 'const-formosa-art-18', lawId: 'const-formosa', number: '18', title: 'Condiciones dignas de detención y reclusión', originalText: `En ningún caso, la simple detención se cumplirá en las cárceles sino en locales adecuados que se destinen a ese efecto; las mujeres y menores serán alojados en establecimientos especiales, con miras a su preservación y readaptación. Las cárceles y demás establecimientos de detención serán sanos y limpios, para seguridad y no para mortificación de los reclusos, debiendo constituir centros de trabajo y aprendizaje. En ningún caso los procesados serán enviados a establecimientos fuera del territorio de la Provincia.`, currentText: `En ningún caso, la simple detención se cumplirá en las cárceles sino en locales adecuados que se destinen a ese efecto; las mujeres y menores serán alojados en establecimientos especiales, con miras a su preservación y readaptación. Las cárceles y demás establecimientos de detención serán sanos y limpios, para seguridad y no para mortificación de los reclusos, debiendo constituir centros de trabajo y aprendizaje. En ningún caso los procesados serán enviados a establecimientos fuera del territorio de la Provincia.`, plainLanguageExplanation: 'Los detenidos no pueden ser alojados en cárceles si su situación es solo de detención preventiva. Las cárceles deben ser dignas, limpias y funcionar como centros de trabajo y aprendizaje, no para castigar. Los procesados no pueden ser trasladados fuera de Formosa.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['condiciones de detención', 'cárceles', 'readaptación', 'reclusos', 'derechos de detenidos'], order: 17, segments: [], amendments: [] },
  { id: 'const-formosa-art-19', lawId: 'const-formosa', number: '19', title: 'Prohibición de torturas y tratos degradantes', originalText: `Queda prohibida toda especie de tormentos, torturas y vejámenes, bajo pena de destitución inmediata y sin perjuicio de las responsabilidades penales en que incurran los funcionarios o empleados que las apliquen, ordenen, instiguen o consientan.`, currentText: `Queda prohibida toda especie de tormentos, torturas y vejámenes, bajo pena de destitución inmediata y sin perjuicio de las responsabilidades penales en que incurran los funcionarios o empleados que las apliquen, ordenen, instiguen o consientan.`, plainLanguageExplanation: 'Están prohibidas todas las formas de torturas y tratos degradantes. Los funcionarios que las apliquen, ordenen o consientan serán destituidos de inmediato y podrán enfrentar responsabilidades penales.', practicalEffects: [], examples: ['Un policía que torture a un detenido bajo custodia será destituido y podrá ser procesado penalmente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prohibición de tortura', 'tratos degradantes', 'destitución', 'responsabilidad penal'], order: 18, segments: [], amendments: [] },
  { id: 'const-formosa-art-20', lawId: 'const-formosa', number: '20', title: 'Garantías penales: no autoincriminación y non bis in idem', originalText: `Nadie puede ser obligado en causa penal o penal administrativa a declarar contra sí mismo, ni contra su cónyuge, sus ascendientes, descendientes y colaterales hasta el cuarto grado de consanguinidad, ni penado más de una vez por el mismo delito, ni sacado de sus jueces naturales, ni juzgado por comisiones especiales, ni encarcelado por incumplimiento de obligaciones en causa civil.`, currentText: `Nadie puede ser obligado en causa penal o penal administrativa a declarar contra sí mismo, ni contra su cónyuge, sus ascendientes, descendientes y colaterales hasta el cuarto grado de consanguinidad, ni penado más de una vez por el mismo delito, ni sacado de sus jueces naturales, ni juzgado por comisiones especiales, ni encarcelado por incumplimiento de obligaciones en causa civil.`, plainLanguageExplanation: 'Nadie está obligado a declarar contra sí mismo ni contra sus familiares cercanos. Tampoco puede ser juzgado dos veces por el mismo hecho, extraído de sus jueces naturales, ni enviado a prisión por deudas civiles.', practicalEffects: [], examples: ['Un imputado puede negarse a declarar en su propio proceso penal sin que eso se use en su contra.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['no autoincriminación', 'non bis in idem', 'juez natural', 'garantías penales'], order: 19, segments: [], amendments: [] },
  { id: 'const-formosa-art-21', lawId: 'const-formosa', number: '21', title: 'Garantías procesales penales específicas', originalText: `Queda abolido el secreto del sumario desde el momento en que el imputado ha prestado declaración indagatoria, la que no podrá prolongarse por un término mayor de cinco días desde su detención, si éste no se negare a prestarla. La incomunicación de los detenidos queda limitada a cuarenta y ocho horas como máximo, en los casos excepcionales que la ley autorice. Sólo podrán aplicarse con efecto retroactivo las leyes penales más favorables al imputado. En ningún caso serán de aplicación por analogía las leyes que califiquen delitos o establezcan penas. Queda suprimido el sobreseimiento provisional.`, currentText: `Queda abolido el secreto del sumario desde el momento en que el imputado ha prestado declaración indagatoria, la que no podrá prolongarse por un término mayor de cinco días desde su detención, si éste no se negare a prestarla. La incomunicación de los detenidos queda limitada a cuarenta y ocho horas como máximo, en los casos excepcionales que la ley autorice. Sólo podrán aplicarse con efecto retroactivo las leyes penales más favorables al imputado. En ningún caso serán de aplicación por analogía las leyes que califiquen delitos o establezcan penas. Queda suprimido el sobreseimiento provisional.`, plainLanguageExplanation: 'Una vez que el imputado declara, el sumario deja de ser secreto. La incomunicación máxima es de 48 horas. Las leyes penales solo se aplican retroactivamente cuando benefician al imputado, y jamás por analogía para crear delitos o penas. Se suprime el sobreseimiento provisional.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['secreto del sumario', 'incomunicación', 'ley penal más benigna', 'retroactividad', 'garantías penales'], order: 20, segments: [], amendments: [] },
  { id: 'const-formosa-art-22', lawId: 'const-formosa', number: '22', title: 'Revisión de sentencias e indemnización por error judicial', originalText: `No podrán reabrirse procesos definitivamente juzgados, salvo cuando apareciesen pruebas concluyentes de la inocencia del condenado. Si de la revisión de una causa resultare la inocencia del condenado, la Provincia tomará a su cargo la indemnización de los daños materiales y morales derivados del error judicial, sin perjuicio de la responsabilidad que pudiera recaer sobre quienes lo hubieren cometido.`, currentText: `No podrán reabrirse procesos definitivamente juzgados, salvo cuando apareciesen pruebas concluyentes de la inocencia del condenado. Si de la revisión de una causa resultare la inocencia del condenado, la Provincia tomará a su cargo la indemnización de los daños materiales y morales derivados del error judicial, sin perjuicio de la responsabilidad que pudiera recaer sobre quienes lo hubieren cometido.`, plainLanguageExplanation: 'Las sentencias firmes no pueden reabrirse excepto cuando surjan pruebas concluyentes de inocencia. Si se comprueba que el condenado era inocente, la Provincia debe indemnizarlo por los daños materiales y morales sufridos, sin perjuicio de las responsabilidades de quienes cometieron el error.', practicalEffects: [], examples: ['Si aparece evidencia nueva que demuestre que un condenado es inocente, puede solicitar la revisión del proceso y reclamar indemnización al Estado provincial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['revisión de sentencias', 'error judicial', 'indemnización', 'inocencia', 'cosa juzgada'], order: 21, segments: [], amendments: [] },
  { id: 'const-formosa-art-23', lawId: 'const-formosa', number: '23', title: 'Acción de amparo', originalText: `Procederá el recurso de amparo contra cualquier persona o autoridad que ilegalmente impidiere, dificultare, restringiere o pusiere en peligro inminente el ejercicio de los siguientes derechos: entrar, permanecer, transitar o salir del territorio de la Provincia; reunirse pacíficamente, opinar, profesar su culto, ejercer sus derechos políticos, de prensa, de trabajar, y de enseñar y aprender. El procedimiento será el establecido por la ley y, mientras no fuere sancionada, podrá el juez arbitrar y abreviar trámites y términos para el inmediato establecimiento del ejercicio legítimo del derecho afectado. Este recurso no obstará el ejercicio de otras acciones legales que correspondieren.`, currentText: `Procederá el recurso de amparo contra cualquier persona o autoridad que ilegalmente impidiere, dificultare, restringiere o pusiere en peligro inminente el ejercicio de los siguientes derechos: entrar, permanecer, transitar o salir del territorio de la Provincia; reunirse pacíficamente, opinar, profesar su culto, ejercer sus derechos políticos, de prensa, de trabajar, y de enseñar y aprender. El procedimiento será el establecido por la ley y, mientras no fuere sancionada, podrá el juez arbitrar y abreviar trámites y términos para el inmediato establecimiento del ejercicio legítimo del derecho afectado. Este recurso no obstará el ejercicio de otras acciones legales que correspondieren.`, plainLanguageExplanation: 'El amparo procede cuando alguien o alguna autoridad impide ilegalmente el ejercicio de derechos como circular, reunirse, trabajar, opinar o votar. El juez puede actuar con trámite abreviado para restablecer el derecho afectado de inmediato.', practicalEffects: [], examples: ['Un trabajador despedido por ejercer su derecho de huelga puede interponer un amparo para que se restablezca su situación laboral.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acción de amparo', 'derechos fundamentales', 'tutela judicial', 'trámite urgente'], order: 22, segments: [], amendments: [] },
  { id: 'const-formosa-art-24', lawId: 'const-formosa', number: '24', title: 'Registro civil a cargo de autoridades civiles', originalText: `El registro del estado civil de las personas será uniformemente llevado en toda la Provincia por las autoridades civiles, sin distinción de nacionalidad ni creencias religiosas, y en la forma que lo establezca la ley.`, currentText: `El registro del estado civil de las personas será uniformemente llevado en toda la Provincia por las autoridades civiles, sin distinción de nacionalidad ni creencias religiosas, y en la forma que lo establezca la ley.`, plainLanguageExplanation: 'El registro civil (nacimientos, matrimonios, defunciones, etc.) está a cargo de autoridades civiles del Estado en toda la Provincia, sin importar la nacionalidad o religión de las personas.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['registro civil', 'estado civil', 'autoridades civiles', 'laicidad'], order: 23, segments: [], amendments: [] },
  { id: 'const-formosa-art-25', lawId: 'const-formosa', number: '25', title: 'Responsabilidad personal de funcionarios públicos', originalText: `Todo funcionario o empleado de la Provincia a quien se impute la comisión de un delito de acción pública en el desempeño de su cargo, está obligado bajo pena de destitución, a promover querella criminal contra el acusador y a continuarla hasta la sentencia. Para la tramitación de esta querella, gozará del beneficio del proceso gratuito. Los funcionarios y empleados serán personalmente responsables por los daños causados a la Provincia, o a terceros, por extralimitación o cumplimiento irregular de sus funciones.`, currentText: `Todo funcionario o empleado de la Provincia a quien se impute la comisión de un delito de acción pública en el desempeño de su cargo, está obligado bajo pena de destitución, a promover querella criminal contra el acusador y a continuarla hasta la sentencia. Para la tramitación de esta querella, gozará del beneficio del proceso gratuito. Los funcionarios y empleados serán personalmente responsables por los daños causados a la Provincia, o a terceros, por extralimitación o cumplimiento irregular de sus funciones.`, plainLanguageExplanation: 'Si se imputa a un funcionario un delito en el ejercicio de su cargo, debe querellarse contra el acusador o será destituido. Además, los funcionarios responden personalmente por los daños causados por abuso o mal desempeño de sus funciones.', practicalEffects: [], examples: ['Un funcionario acusado de corrupción en su cargo debe iniciar y sostener una querella contra quien lo acusó, o perderá su cargo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad de funcionarios', 'querella', 'extralimitación de funciones', 'daños causados por el Estado'], order: 24, segments: [], amendments: [] },
  { id: 'const-formosa-art-26', lawId: 'const-formosa', number: '26', title: 'Prohibición de delegación de facultades constitucionales', originalText: `Los poderes públicos no podrán delegar las facultades que le han sido conferidas por esta Constitución, ni atribuir al Poder Ejecutivo otras que las que expresamente le están acordadas por ella. Tampoco podrán renunciar a las que expresamente no hayan sido delegadas al Gobierno Federal, conforme a la Constitución Nacional.`, currentText: `Los poderes públicos no podrán delegar las facultades que le han sido conferidas por esta Constitución, ni atribuir al Poder Ejecutivo otras que las que expresamente le están acordadas por ella. Tampoco podrán renunciar a las que expresamente no hayan sido delegadas al Gobierno Federal, conforme a la Constitución Nacional.`, plainLanguageExplanation: 'Los poderes del Estado no pueden delegar las competencias que la Constitución les asigna ni ampliar las del Ejecutivo más allá de lo previsto. Tampoco pueden renunciar a las facultades que no fueron delegadas expresamente a la Nación.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['delegación de facultades', 'división de poderes', 'competencias constitucionales', 'poder ejecutivo'], order: 25, segments: [], amendments: [] },
  { id: 'const-formosa-art-27', lawId: 'const-formosa', number: '27', title: 'Derecho de reunión pacífica', originalText: `Todos los habitantes de la Provincia tienen el derecho de reunirse pacíficamente, sin más requisitos que el de dar aviso a la autoridad policial cuando la reunión se efectúe en lugares públicos a fin de que ésta arbitre las medidas tendientes a preservar la seguridad y el orden. En ningún caso podrá ser prohibida, sino por motivo fundado de seguridad y orden público.`, currentText: `Todos los habitantes de la Provincia tienen el derecho de reunirse pacíficamente, sin más requisitos que el de dar aviso a la autoridad policial cuando la reunión se efectúe en lugares públicos a fin de que ésta arbitre las medidas tendientes a preservar la seguridad y el orden. En ningún caso podrá ser prohibida, sino por motivo fundado de seguridad y orden público.`, plainLanguageExplanation: 'Toda persona tiene derecho a reunirse en forma pacífica. En espacios públicos solo se requiere avisar a la policía para que organice la seguridad. La reunión no puede ser prohibida salvo por razones fundadas de seguridad u orden público.', practicalEffects: [], examples: ['Una marcha sindical debe avisar previamente a la policía pero no puede ser prohibida sin una razón concreta de seguridad.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho de reunión', 'manifestación pacífica', 'orden público', 'libertad de asamblea'], order: 26, segments: [], amendments: [] },
  { id: 'const-formosa-art-28', lawId: 'const-formosa', number: '28', title: 'Defensa del orden constitucional e inviolabilidad', originalText: `En ningún caso el Gobierno de la Provincia podrá suspender, en el todo o en alguna de sus partes, la vigencia de esta Constitución. A partir de la sanción de la presente Constitución, toda alteración de la misma, dispuesta por un poder no constituido regularmente, será nula. Todo el que se alzare contra las autoridades legítimamente constituidas o intentare alterar, suprimir o reformar la presente Constitución, fuera de los procedimientos en ella previstos, quedará inhabilitado a perpetuidad para ejercer cargos públicos, sin perjuicio de las acciones civiles y penales que le fueren aplicables. El no acatamiento de las órdenes o actos de usurpadores del Gobierno de la Provincia será legítimo. Todo habitante está obligado a organizarse en defensa del orden constitucional. Quienes, en esas circunstancias, ejercieren las funciones previstas para las autoridades de esta Constitución quedan inhabilitados para ocupar cargos o empleos públicos. A los fines previsionales, no se computará el tiempo de sus servicios, ni los aportes que, por tal concepto, hubieren realizado.`, currentText: `En ningún caso el Gobierno de la Provincia podrá suspender, en el todo o en alguna de sus partes, la vigencia de esta Constitución. A partir de la sanción de la presente Constitución, toda alteración de la misma, dispuesta por un poder no constituido regularmente, será nula. Todo el que se alzare contra las autoridades legítimamente constituidas o intentare alterar, suprimir o reformar la presente Constitución, fuera de los procedimientos en ella previstos, quedará inhabilitado a perpetuidad para ejercer cargos públicos, sin perjuicio de las acciones civiles y penales que le fueren aplicables. El no acatamiento de las órdenes o actos de usurpadores del Gobierno de la Provincia será legítimo. Todo habitante está obligado a organizarse en defensa del orden constitucional. Quienes, en esas circunstancias, ejercieren las funciones previstas para las autoridades de esta Constitución quedan inhabilitados para ocupar cargos o empleos públicos. A los fines previsionales, no se computará el tiempo de sus servicios, ni los aportes que, por tal concepto, hubieren realizado.`, plainLanguageExplanation: 'La Constitución no puede ser suspendida ni modificada por un gobierno de facto. Quien se alzare contra las autoridades legítimas o intente reformar la Constitución por vías no previstas queda inhabilitado perpetuamente para cargos públicos. Los habitantes tienen el deber de defender el orden constitucional, y desobedecer a usurpadores es legítimo.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inviolabilidad constitucional', 'defensa del orden', 'golpe de estado', 'inhabilitación perpetua', 'resistencia a la usurpación'], order: 27, segments: [], amendments: [] },
  { id: 'const-formosa-art-29', lawId: 'const-formosa', number: '29', title: 'Libertad de trabajo, industria y comercio', originalText: `La libertad de trabajo, industria y comercio son derechos asegurados a todos los habitantes de la Provincia, siempre que no tengan por fin dominar los mercados provinciales, eliminar la competencia o aumentar usurariamente los beneficios.`, currentText: `La libertad de trabajo, industria y comercio son derechos asegurados a todos los habitantes de la Provincia, siempre que no tengan por fin dominar los mercados provinciales, eliminar la competencia o aumentar usurariamente los beneficios.`, plainLanguageExplanation: 'Se garantiza la libertad de trabajar, montar industrias y comerciar. Sin embargo, esa libertad no puede usarse para monopolizar mercados, eliminar la competencia ni obtener ganancias abusivas.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad de trabajo', 'libertad de comercio', 'competencia', 'monopolio', 'derechos económicos'], order: 28, segments: [], amendments: [] },
  { id: 'const-formosa-art-30', lawId: 'const-formosa', number: '30', title: 'Prohibición de facultades extraordinarias', originalText: `Ninguna autoridad de la Provincia tiene facultades extraordinarias, ni puede pedirlas, ni se le concederán por motivo alguno.`, currentText: `Ninguna autoridad de la Provincia tiene facultades extraordinarias, ni puede pedirlas, ni se le concederán por motivo alguno.`, plainLanguageExplanation: 'Ningún funcionario o poder público provincial puede tener, solicitar ni recibir facultades extraordinarias, sin excepción alguna.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['facultades extraordinarias', 'estado de excepción', 'división de poderes', 'límites al poder'], order: 29, segments: [], amendments: [] },
  { id: 'const-formosa-art-31', lawId: 'const-formosa', number: '31', title: 'Libertad de culto y relaciones con la Iglesia', originalText: `Es inviolable, en el territorio de la Provincia, el derecho que toda persona tiene para rendir culto a su Dios, libre y públicamente, según los dictados de su conciencia y sin más limitaciones que las impuestas por la moral, las buenas costumbres y el orden público. Las creencias religiosas no constituyen circunstancias modificatorias de la personalidad civil o política de ninguno de los habitantes de la Provincia. No se obligará tampoco, por motivo alguno a declarar la religión que profesa. El Estado Provincial mantiene relaciones de autonomía y cooperación con la Iglesia Católica, Apostólica y Romana, según su tradición histórica y cultural, y con los demás cultos reconocidos, cuyos objetivos sean el bien común.`, currentText: `Es inviolable, en el territorio de la Provincia, el derecho que toda persona tiene para rendir culto a su Dios, libre y públicamente, según los dictados de su conciencia y sin más limitaciones que las impuestas por la moral, las buenas costumbres y el orden público. Las creencias religiosas no constituyen circunstancias modificatorias de la personalidad civil o política de ninguno de los habitantes de la Provincia. No se obligará tampoco, por motivo alguno a declarar la religión que profesa. El Estado Provincial mantiene relaciones de autonomía y cooperación con la Iglesia Católica, Apostólica y Romana, según su tradición histórica y cultural, y con los demás cultos reconocidos, cuyos objetivos sean el bien común.`, plainLanguageExplanation: 'La libertad de culto es inviolable y nadie puede ser obligado a declarar su religión. Las creencias religiosas no afectan los derechos civiles ni políticos. El Estado mantiene relaciones de cooperación con la Iglesia Católica y los demás cultos reconocidos orientados al bien común.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad de culto', 'religión', 'Iglesia Católica', 'no discriminación religiosa', 'Estado laico'], order: 30, segments: [], amendments: [] },
  { id: 'const-formosa-art-32', lawId: 'const-formosa', number: '32', title: 'Límites a la intervención federal', originalText: `En caso de intervención del Gobierno Federal, el representante nacional sólo podrá practicar válidamente actos administrativos que estén de acuerdo con esta Constitución y con las leyes provinciales.`, currentText: `En caso de intervención del Gobierno Federal, el representante nacional sólo podrá practicar válidamente actos administrativos que estén de acuerdo con esta Constitución y con las leyes provinciales.`, plainLanguageExplanation: 'Si el gobierno nacional interviene la Provincia, el interventor federal solo puede tomar medidas administrativas que respeten la Constitución y las leyes provinciales vigentes.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['intervención federal', 'interventor', 'límites administrativos', 'autonomía provincial'], order: 31, segments: [], amendments: [] },
  { id: 'const-formosa-art-33', lawId: 'const-formosa', number: '33', title: 'Mandamiento judicial de ejecución de deberes públicos', originalText: `Siempre que una ley u ordenanza imponga a un funcionario público o corporación pública de carácter administrativo un deber expresamente determinado, toda persona o entidad en cuyo interés deba ejecutarse el acto y que sufriere perjuicio material, moral o político, por falta de cumplimiento del deber, puede demandar ante los tribunales su ejecución inmediata y el tribunal, previa comprobación sumaria de la obligación legal y del derecho del reclamante, dirigirá al funcionario o corporación un mandamiento de ejecución.`, currentText: `Siempre que una ley u ordenanza imponga a un funcionario público o corporación pública de carácter administrativo un deber expresamente determinado, toda persona o entidad en cuyo interés deba ejecutarse el acto y que sufriere perjuicio material, moral o político, por falta de cumplimiento del deber, puede demandar ante los tribunales su ejecución inmediata y el tribunal, previa comprobación sumaria de la obligación legal y del derecho del reclamante, dirigirá al funcionario o corporación un mandamiento de ejecución.`, plainLanguageExplanation: 'Si una ley obliga a un funcionario o ente público a cumplir un deber concreto y no lo cumple, cualquier persona perjudicada puede exigir judicialmente su cumplimiento. El juez puede ordenar al funcionario que actúe mediante un mandamiento de ejecución.', practicalEffects: [], examples: ['Un vecino puede demandar a un municipio que por ley debe reparar una calle deteriorada y no lo hace.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mandamiento de ejecución', 'omisión administrativa', 'deber legal', 'acción judicial'], order: 32, segments: [], amendments: [] },
  { id: 'const-formosa-art-34', lawId: 'const-formosa', number: '34', title: 'Demandabilidad del Estado provincial', originalText: `La Provincia, como persona de derecho público, puede ser demandada ante sus propios tribunales, sin necesidad de autorización del Poder Legislativo, por el procedimiento que la ley establezca, no pudiendo exceder de noventa días perentorios los trámites administrativos previos. Cuando sea demandada como persona de derecho privado, lo será por el procedimiento ordinario. No podrá trabarse embargo en bienes o fondos indispensables para el cumplimiento de servicios o utilidad pública.`, currentText: `La Provincia, como persona de derecho público, puede ser demandada ante sus propios tribunales, sin necesidad de autorización del Poder Legislativo, por el procedimiento que la ley establezca, no pudiendo exceder de noventa días perentorios los trámites administrativos previos. Cuando sea demandada como persona de derecho privado, lo será por el procedimiento ordinario. No podrá trabarse embargo en bienes o fondos indispensables para el cumplimiento de servicios o utilidad pública.`, plainLanguageExplanation: 'La Provincia puede ser demandada en sus propios tribunales sin necesidad de autorización legislativa. La etapa administrativa previa no puede durar más de 90 días. Los bienes necesarios para servicios públicos no pueden ser embargados.', practicalEffects: [], examples: ['Un ciudadano puede demandar a la Provincia por daños sin necesidad de que el Legislativo lo autorice primero.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['demandabilidad del Estado', 'responsabilidad estatal', 'agotamiento de instancias', 'embargo', 'proceso contencioso'], order: 33, segments: [], amendments: [] },
  { id: 'const-formosa-art-35', lawId: 'const-formosa', number: '35', title: 'Limitación de inhabilitaciones para cargos públicos', originalText: `No se admitirán otras inhabilitaciones para el ejercicio de la función pública o gremial que las que surjan de esta Constitución y de las leyes que en su consecuencia se dicten.`, currentText: `No se admitirán otras inhabilitaciones para el ejercicio de la función pública o gremial que las que surjan de esta Constitución y de las leyes que en su consecuencia se dicten.`, plainLanguageExplanation: 'Solo pueden existir causales de inhabilitación para ejercer cargos públicos o gremiales si están expresamente previstas en la Constitución o en las leyes derivadas de ella. No se pueden crear inhabilitaciones por vías informales.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inhabilitación', 'función pública', 'gremial', 'legalidad', 'cargos públicos'], order: 34, segments: [], amendments: [] },
  { id: 'const-formosa-art-36', lawId: 'const-formosa', number: '36', title: 'Organizaciones libres del Pueblo y bien común', originalText: `La Provincia garantiza el funcionamiento de las organizaciones libres del Pueblo, sujetas a las leyes que las reglamenten. El Estado formoseño propende, como objetivo primordial de su organización social, a que todos los sectores que integran la comunidad provincial trabajen en pos de la felicidad del Pueblo y la grandeza de la Provincia y de la Patria.`, currentText: `La Provincia garantiza el funcionamiento de las organizaciones libres del Pueblo, sujetas a las leyes que las reglamenten. El Estado formoseño propende, como objetivo primordial de su organización social, a que todos los sectores que integran la comunidad provincial trabajen en pos de la felicidad del Pueblo y la grandeza de la Provincia y de la Patria.`, plainLanguageExplanation: 'La Provincia garantiza la existencia de organizaciones sociales, gremiales y comunitarias libres, dentro del marco legal. El objetivo social del Estado es que todos los sectores contribuyan al bienestar del pueblo y al desarrollo de Formosa.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['organizaciones libres', 'sociedad civil', 'bien común', 'comunidad provincial'], order: 35, segments: [], amendments: [] },
  { id: 'const-formosa-art-37', lawId: 'const-formosa', number: '37', title: 'Gobierno de las profesiones y colegios profesionales', originalText: `La Provincia, sin perjuicio del poder de policía que compete al Estado, podrá conferir el gobierno de las profesiones y el control de su ejercicio a las entidades que se organicen con el concurso de todos los profesionales de la actividad, en forma democrática, pluralista y sin discriminaciones, conforme con las bases y condiciones que establezca la ley. Tendrán la defensa y promoción de sus intereses específicos y gozarán de las atribuciones que la ley estime necesarias para el desempeño de sus funciones, con arreglo a los principios de la ética profesional.`, currentText: `La Provincia, sin perjuicio del poder de policía que compete al Estado, podrá conferir el gobierno de las profesiones y el control de su ejercicio a las entidades que se organicen con el concurso de todos los profesionales de la actividad, en forma democrática, pluralista y sin discriminaciones, conforme con las bases y condiciones que establezca la ley. Tendrán la defensa y promoción de sus intereses específicos y gozarán de las atribuciones que la ley estime necesarias para el desempeño de sus funciones, con arreglo a los principios de la ética profesional.`, plainLanguageExplanation: 'La Provincia puede delegar el control del ejercicio de las profesiones a entidades representativas democráticas de cada profesión (como colegios profesionales), las cuales pueden defender los intereses de sus miembros y hacer cumplir la ética profesional.', practicalEffects: [], examples: ['El Colegio de Abogados de Formosa puede regular y controlar el ejercicio de la abogacía en la Provincia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['colegios profesionales', 'gobierno de las profesiones', 'ética profesional', 'autorregulación'], order: 36, segments: [], amendments: [] },
  { id: 'const-formosa-art-38', lawId: 'const-formosa', number: '38', title: 'Derecho al medio ambiente sano', originalText: `Todos los habitantes tienen derecho a vivir en un medio ambiente adecuado para el desarrollo de la persona humana, así como el deber de conservarlo. Es obligación de los poderes públicos proteger el medio ambiente y los recursos naturales, promoviendo la utilización racional de los mismos, ya que de ellos dependen el desarrollo y la supervivencia humana. Para ello se dictarán normas que aseguren: 1) El mantenimiento de los procesos ecológicos esenciales, la preservación de la diversidad genética, y la protección, recuperación y mejoramiento del medio ambiente. 2) La compatibilidad de la planificación económica, social y urbanística de la Provincia con la protección de los recursos naturales, culturales y del patrimonio histórico y paisajístico. 3) La absoluta prohibición de realizar pruebas nucleares, y el almacenamiento de uranio o cualquier otro mineral radiactivo y de sus desechos, salvo los utilizados en investigación, salud y los relacionados con el desarrollo industrial, cuya normativa se ajustará a lo establecido por los organismos competentes. Todos los recursos naturales radioactivos, cuya extracción, elaboración o utilización puedan alterar el medio ambiente, deberán ser objeto de tratamientos específicos a efectos de la conservación del equilibrio ecológico. 4) El correcto uso y la comercialización adecuados de biocidas, agroquímicos y otros productos que puedan dañar el medio ambiente. 5) La protección de la flora y la fauna silvestre, así como su restauración. 6) El adecuado manejo de las aguas, tanto superficiales como subterráneas, protegiéndolas de todo tipo de contaminación o degradación, sea química o física. 7) La prevención y control de la degradación de los suelos. 8) El derecho de gozar de un aire puro, libre de contaminantes gaseosos, térmicos o acústicos. 9) La concientización social de los principios ecológicos. 10) La firma de acuerdos con la Nación, provincias o países limítrofes cuando se trate de recursos naturales compartidos. 11) La implementación de medidas adecuadas tendientes a la preservación de la capa de ozono. CAPITULO SEGUNDO.- Régimen Económico`, currentText: `Todos los habitantes tienen derecho a vivir en un medio ambiente adecuado para el desarrollo de la persona humana, así como el deber de conservarlo. Es obligación de los poderes públicos proteger el medio ambiente y los recursos naturales, promoviendo la utilización racional de los mismos, ya que de ellos dependen el desarrollo y la supervivencia humana. Para ello se dictarán normas que aseguren: 1) El mantenimiento de los procesos ecológicos esenciales, la preservación de la diversidad genética, y la protección, recuperación y mejoramiento del medio ambiente. 2) La compatibilidad de la planificación económica, social y urbanística de la Provincia con la protección de los recursos naturales, culturales y del patrimonio histórico y paisajístico. 3) La absoluta prohibición de realizar pruebas nucleares, y el almacenamiento de uranio o cualquier otro mineral radiactivo y de sus desechos, salvo los utilizados en investigación, salud y los relacionados con el desarrollo industrial, cuya normativa se ajustará a lo establecido por los organismos competentes. Todos los recursos naturales radioactivos, cuya extracción, elaboración o utilización puedan alterar el medio ambiente, deberán ser objeto de tratamientos específicos a efectos de la conservación del equilibrio ecológico. 4) El correcto uso y la comercialización adecuados de biocidas, agroquímicos y otros productos que puedan dañar el medio ambiente. 5) La protección de la flora y la fauna silvestre, así como su restauración. 6) El adecuado manejo de las aguas, tanto superficiales como subterráneas, protegiéndolas de todo tipo de contaminación o degradación, sea química o física. 7) La prevención y control de la degradación de los suelos. 8) El derecho de gozar de un aire puro, libre de contaminantes gaseosos, térmicos o acústicos. 9) La concientización social de los principios ecológicos. 10) La firma de acuerdos con la Nación, provincias o países limítrofes cuando se trate de recursos naturales compartidos. 11) La implementación de medidas adecuadas tendientes a la preservación de la capa de ozono. CAPITULO SEGUNDO.- Régimen Económico`, plainLanguageExplanation: 'Todos tienen derecho a un medio ambiente sano y el deber de cuidarlo. El Estado debe proteger los recursos naturales con uso racional. Se prohíben las pruebas nucleares y el almacenamiento de residuos radiactivos; se protegen suelos, aguas, flora, fauna y el aire limpio. Pueden celebrarse acuerdos interjurisdiccionales para recursos compartidos.', practicalEffects: [], examples: ['Una empresa que contamine un río provincial puede ser demandada judicialmente por violación del derecho al medio ambiente sano garantizado en este artículo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medio ambiente', 'recursos naturales', 'prohibición nuclear', 'flora y fauna', 'derecho ambiental'], order: 37, segments: [], amendments: [] },
  { id: 'const-formosa-art-39', lawId: 'const-formosa', number: '39', title: 'Planificación y regulación económica provincial', originalText: `El Estado regulará el proceso económico orientando las distintas actividades, de acuerdo con los principios establecidos en esta Constitución. A tales efectos elaborará una adecuada planificación que será indicativa para el sector privado, e imperativa para los diversos estamentos públicos propendiendo a un desarrollo armónico y equilibrado de la Provincia, facilitando la integración regional y ejecutando programas y acciones que contemplen sus potencialidades y su ubicación geopolítica. La Provincia participa en los sistemas de planeamiento regional, federal e internacional.`, currentText: `El Estado regulará el proceso económico orientando las distintas actividades, de acuerdo con los principios establecidos en esta Constitución. A tales efectos elaborará una adecuada planificación que será indicativa para el sector privado, e imperativa para los diversos estamentos públicos propendiendo a un desarrollo armónico y equilibrado de la Provincia, facilitando la integración regional y ejecutando programas y acciones que contemplen sus potencialidades y su ubicación geopolítica. La Provincia participa en los sistemas de planeamiento regional, federal e internacional.`, plainLanguageExplanation: 'El Estado orienta y regula la economía provincial mediante una planificación que es obligatoria para los organismos públicos pero solo orientadora para el sector privado. La Provincia también participa en la planificación regional, federal e internacional.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['planificación económica', 'regulación estatal', 'desarrollo provincial', 'integración regional'], order: 38, segments: [], amendments: [] },
  { id: 'const-formosa-art-40', lawId: 'const-formosa', number: '40', title: 'Bases de la política económica provincial', originalText: `El Estado encausará la economía de la Provincia mediante una legislación adecuada y fomentará la explotación racional de sus recursos naturales, el crédito, las industrias, el consumo, el intercambio al servicio de la colectividad y el bienestar social asegurando el imperio del método democrático en la regulación planificada de la producción, circulación y distribución de la riqueza, de acuerdo con las siguientes bases: 1) Estímulo y protección a la iniciativa privada, en su realidad creadora. 2) Distribución equitativa de la tierra, considerada como bien de trabajo, a los fines de su explotación racional, a un precio justo en relación con su rendimiento. 3) Promoción de las industrias, procurando su diversificación y su instalación preferentemente en los centros de producción de materia prima. 4) Fomento de las instituciones cooperativas con fines de protección a los pequeños productores y estímulo del seguro agrario contra todo riesgo. 5) Otorgamiento de créditos de fomento a los productores rurales, orientados y supervisados. 6) Defensa de su producción básica contra la acción de los monopolios y trusts, pudiendo el Estado intervenir en cualquier etapa del circuito económico, para restablecer y posibilitar el juego armónico de las fuerzas del mercado. Fomento de su industrialización dentro de su propio territorio, promoviendo la comercialización de sus productos, en base a estudios de mercados regionales, nacionales e internacionales. 7) Fijación, por ley especial, de las condiciones en que se hará la reserva, venta o concesión de tierras que se encuentran en las zonas de influencia de obras de aprovechamiento hídrico. 8) Gestión a nivel nacional de establecimiento de zonas francas cuando la estrategia del desarrollo determine la conveniencia.`, currentText: `El Estado encausará la economía de la Provincia mediante una legislación adecuada y fomentará la explotación racional de sus recursos naturales, el crédito, las industrias, el consumo, el intercambio al servicio de la colectividad y el bienestar social asegurando el imperio del método democrático en la regulación planificada de la producción, circulación y distribución de la riqueza, de acuerdo con las siguientes bases: 1) Estímulo y protección a la iniciativa privada, en su realidad creadora. 2) Distribución equitativa de la tierra, considerada como bien de trabajo, a los fines de su explotación racional, a un precio justo en relación con su rendimiento. 3) Promoción de las industrias, procurando su diversificación y su instalación preferentemente en los centros de producción de materia prima. 4) Fomento de las instituciones cooperativas con fines de protección a los pequeños productores y estímulo del seguro agrario contra todo riesgo. 5) Otorgamiento de créditos de fomento a los productores rurales, orientados y supervisados. 6) Defensa de su producción básica contra la acción de los monopolios y trusts, pudiendo el Estado intervenir en cualquier etapa del circuito económico, para restablecer y posibilitar el juego armónico de las fuerzas del mercado. Fomento de su industrialización dentro de su propio territorio, promoviendo la comercialización de sus productos, en base a estudios de mercados regionales, nacionales e internacionales. 7) Fijación, por ley especial, de las condiciones en que se hará la reserva, venta o concesión de tierras que se encuentran en las zonas de influencia de obras de aprovechamiento hídrico. 8) Gestión a nivel nacional de establecimiento de zonas francas cuando la estrategia del desarrollo determine la conveniencia.`, plainLanguageExplanation: 'El Estado orienta la economía con criterio democrático: protege la iniciativa privada, distribuye la tierra equitativamente, fomenta cooperativas e industrias, defiende la producción frente a monopolios y otorga créditos rurales. También puede gestionar zonas francas ante la Nación.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['política económica', 'cooperativas', 'distribución de la tierra', 'defensa ante monopolios', 'crédito rural'], order: 39, segments: [], amendments: [] },
  { id: 'const-formosa-art-41', lawId: 'const-formosa', number: '41', title: 'Fomento de PyMEs, cooperativas y comercio fronterizo', originalText: `Se dictarán leyes especiales tendientes a: 1) El otorgamiento de créditos a los distintos sectores de la economía, estimulando principalmente la formación y evolución de las pequeñas y medianas empresas. Prioritariamente se utilizará el sistema de crédito de fomento, planificado, orientado y supervisado. Se podrá crear un fondo de promoción con carácter permanente, previéndose un porcentaje en el presupuesto provincial. 2) La promoción industrial incentivando la radicación de industrias de transformación de materias primas en la zona de producción. 3) El fomento de las cooperativas, mutuales y asociaciones, fundaciones y demás instituciones que estén basadas en principios de solidaridad social, cualquiera sea la actividad. El Estado asegura una adecuada orientación, asistencia y fiscalización. 4) El estímulo y promoción al turismo. 5) Agilizar e incrementar el comercio fronterizo en coordinación con las políticas nacionales, en búsqueda de una expansión e integración regional e internacional.`, currentText: `Se dictarán leyes especiales tendientes a: 1) El otorgamiento de créditos a los distintos sectores de la economía, estimulando principalmente la formación y evolución de las pequeñas y medianas empresas. Prioritariamente se utilizará el sistema de crédito de fomento, planificado, orientado y supervisado. Se podrá crear un fondo de promoción con carácter permanente, previéndose un porcentaje en el presupuesto provincial. 2) La promoción industrial incentivando la radicación de industrias de transformación de materias primas en la zona de producción. 3) El fomento de las cooperativas, mutuales y asociaciones, fundaciones y demás instituciones que estén basadas en principios de solidaridad social, cualquiera sea la actividad. El Estado asegura una adecuada orientación, asistencia y fiscalización. 4) El estímulo y promoción al turismo. 5) Agilizar e incrementar el comercio fronterizo en coordinación con las políticas nacionales, en búsqueda de una expansión e integración regional e internacional.`, plainLanguageExplanation: 'Se deben dictar leyes para fomentar créditos a pequeñas y medianas empresas, promover industrias transformadoras de materias primas, apoyar cooperativas y mutuales, estimular el turismo y agilizar el comercio fronterizo en coordinación con la política nacional.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['PyMEs', 'crédito de fomento', 'cooperativas', 'turismo', 'comercio fronterizo'], order: 40, segments: [], amendments: [] },
  { id: 'const-formosa-art-42', lawId: 'const-formosa', number: '42', title: 'Infraestructura para el desarrollo económico', originalText: `La Provincia promoverá e intensificará la construcción, consolidación y expansión de las redes ferrocamineras, fluviales, eléctricas, de comunicaciones, de gasoductos, de sistemas de agua, parques industriales y toda infraestructura económica básica tendientes a afianzar su economía productiva, favoreciendo el desarrollo armónico de su interior y la integración provincial, regional, nacional e internacional.`, currentText: `La Provincia promoverá e intensificará la construcción, consolidación y expansión de las redes ferrocamineras, fluviales, eléctricas, de comunicaciones, de gasoductos, de sistemas de agua, parques industriales y toda infraestructura económica básica tendientes a afianzar su economía productiva, favoreciendo el desarrollo armónico de su interior y la integración provincial, regional, nacional e internacional.`, plainLanguageExplanation: 'La Provincia debe desarrollar infraestructura de transporte, energía, comunicaciones, agua y parques industriales para fortalecer su economía y promover la integración con otras regiones del país y el exterior.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['infraestructura', 'transporte', 'gasoductos', 'parques industriales', 'desarrollo provincial'], order: 41, segments: [], amendments: [] },
  { id: 'const-formosa-art-43', lawId: 'const-formosa', number: '43', title: 'Servicios públicos: titularidad y formas de explotación', originalText: `Los servicios públicos corresponden, originariamente, a la Provincia o a los municipios, y la explotación puede ser efectuada por el Estado, por cooperativas, sociedades con participación estatal o por particulares. La ley establecerá la forma de explotación de los mismos y el control de su prestación, de acuerdo con las características y naturaleza de cada servicio y a la eficiencia en su cumplimiento.`, currentText: `Los servicios públicos corresponden, originariamente, a la Provincia o a los municipios, y la explotación puede ser efectuada por el Estado, por cooperativas, sociedades con participación estatal o por particulares. La ley establecerá la forma de explotación de los mismos y el control de su prestación, de acuerdo con las características y naturaleza de cada servicio y a la eficiencia en su cumplimiento.`, plainLanguageExplanation: 'Los servicios públicos son originariamente provinciales o municipales. Pueden ser prestados por el Estado, cooperativas, empresas mixtas o privadas. La ley regula cómo se explotan y controla la eficiencia de su prestación.', practicalEffects: [], examples: ['El servicio de agua potable puede ser concesionado a una cooperativa o empresa privada, pero la Provincia mantiene el control y la regulación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['servicios públicos', 'concesión', 'cooperativas', 'regulación estatal', 'municipios'], order: 42, segments: [], amendments: [] },
  { id: 'const-formosa-art-44', lawId: 'const-formosa', number: '44', title: 'Fomento del ahorro y del crédito agroindustrial', originalText: `La Provincia estimulará el aumento real del ahorro y propiciará la creación o radicación de bancos e instituciones de crédito, especialmente aquellos que orienten sus actividades al fomento agroindustrial.`, currentText: `La Provincia estimulará el aumento real del ahorro y propiciará la creación o radicación de bancos e instituciones de crédito, especialmente aquellos que orienten sus actividades al fomento agroindustrial.`, plainLanguageExplanation: 'La Provincia promueve el ahorro y la instalación de bancos y entidades de crédito en su territorio, con especial atención a aquellas que financien actividades agropecuarias e industriales.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ahorro', 'crédito', 'bancos', 'agroindustria', 'fomento productivo'], order: 43, segments: [], amendments: [] },
  { id: 'const-formosa-art-45', lawId: 'const-formosa', number: '45', title: 'Función social de la tierra y colonización', originalText: `La Provincia considera la tierra rural fiscal como factor de producción y fomentará su adjudicación a quién la trabaja, evitando la especulación, el desarraigo y la concentración de la propiedad. Es legítima la privatización en función social de la tierra y constituye un derecho para todos los habitantes de acceder a ella. Se propenderá la ejecución de planes de colonización. La Ley establecerá las condiciones de manejo de la tierra pública como recurso natural renovable. Promoverá la adjudicación mediante ofrecimiento público de las tierras libres de ocupantes. La unidad productiva máxima será de cinco mil hectáreas, salvo excepciones que precisarán de una ley especial que las justifique.`, currentText: `La Provincia considera la tierra rural fiscal como factor de producción y fomentará su adjudicación a quién la trabaja, evitando la especulación, el desarraigo y la concentración de la propiedad. Es legítima la privatización en función social de la tierra y constituye un derecho para todos los habitantes de acceder a ella. Se propenderá la ejecución de planes de colonización. La Ley establecerá las condiciones de manejo de la tierra pública como recurso natural renovable. Promoverá la adjudicación mediante ofrecimiento público de las tierras libres de ocupantes. La unidad productiva máxima será de cinco mil hectáreas, salvo excepciones que precisarán de una ley especial que las justifique.`, plainLanguageExplanation: 'La tierra fiscal se adjudica a quienes la trabajan, evitando la especulación y la concentración. Se promueven planes de colonización y el acceso a la tierra como derecho. La unidad máxima por propietario es de 5000 hectáreas, salvo que una ley especial justifique excepciones.', practicalEffects: [], examples: ['Un productor que ocupa y trabaja tierras fiscales puede solicitar la adjudicación a su nombre conforme a la ley provincial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tierra fiscal', 'función social', 'colonización', 'acceso a la tierra', 'concentración de la propiedad'], order: 44, segments: [], amendments: [] },
  { id: 'const-formosa-art-46', lawId: 'const-formosa', number: '46', title: 'Relevamiento de recursos naturales', originalText: `La Provincia procederá a efectuar el relevamiento de los recursos naturales renovables y no renovables, para la realización de los estudios que permitan la conformación de las distintas unidades de producción zonal.`, currentText: `La Provincia procederá a efectuar el relevamiento de los recursos naturales renovables y no renovables, para la realización de los estudios que permitan la conformación de las distintas unidades de producción zonal.`, plainLanguageExplanation: 'La Provincia debe realizar un inventario de sus recursos naturales, tanto renovables como no renovables, para planificar las zonas de producción de manera ordenada y eficiente.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['recursos naturales', 'relevamiento', 'planificación territorial', 'zonas de producción'], order: 45, segments: [], amendments: [] },
  { id: 'const-formosa-art-47', lawId: 'const-formosa', number: '47', title: 'Expropiación por utilidad pública o incumplimiento social', originalText: `Las tierras rurales, urbanas y suburbanas podrán ser expropiadas por causa de utilidad pública, calificada por ley y previamente indemnizadas. También podrán expropiarse aquellos inmuebles que no cumplan con la función social que esta Constitución asigna a la tierra. En este supuesto, la ley que lo disponga requerirá el voto de los dos tercios de los miembros de la Legislatura.`, currentText: `Las tierras rurales, urbanas y suburbanas podrán ser expropiadas por causa de utilidad pública, calificada por ley y previamente indemnizadas. También podrán expropiarse aquellos inmuebles que no cumplan con la función social que esta Constitución asigna a la tierra. En este supuesto, la ley que lo disponga requerirá el voto de los dos tercios de los miembros de la Legislatura.`, plainLanguageExplanation: 'Las tierras pueden ser expropiadas por utilidad pública con previa indemnización y calificación legal. También pueden expropiarse inmuebles que no cumplan su función social; en ese caso la ley requiere aprobación por dos tercios de la Legislatura.', practicalEffects: [], examples: ['Un terreno urbano abandonado que no cumpla ninguna función productiva o social puede ser expropiado por la Provincia si la Legislatura lo aprueba con dos tercios.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['expropiación', 'utilidad pública', 'función social', 'indemnización', 'legislatura'], order: 46, segments: [], amendments: [] },
  { id: 'const-formosa-art-48', lawId: 'const-formosa', number: '48', title: 'Dominio provincial sobre bienes en su territorio', originalText: `Todos los bienes, cualquiera sea su naturaleza, ubicados en el territorio de la Provincia son del dominio de ésta, con excepción de los que pertenezcan a la Nación, municipalidades u otras personas o entidades de derecho público o privado, y los pertenecientes a comunidades aborígenes.`, currentText: `Todos los bienes, cualquiera sea su naturaleza, ubicados en el territorio de la Provincia son del dominio de ésta, con excepción de los que pertenezcan a la Nación, municipalidades u otras personas o entidades de derecho público o privado, y los pertenecientes a comunidades aborígenes.`, plainLanguageExplanation: 'Todos los bienes ubicados en el territorio de Formosa son de la Provincia, salvo los que pertenecen a la Nación, municipios, personas privadas y comunidades aborígenes.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['dominio provincial', 'bienes fiscales', 'propiedad estatal', 'comunidades aborígenes'], order: 47, segments: [], amendments: [] },
  { id: 'const-formosa-art-49', lawId: 'const-formosa', number: '49', title: 'Aprovechamiento racional de bosques', originalText: `La Provincia promoverá el aprovechamiento racional de los bosques, teniendo en cuenta la necesidad de supervivencia, conservación y mejoramiento de las especies, la reposición de aquellas de mayor interés económico y la forestación de zonas de producción; tomando estas funciones a su cargo directo, en los casos de las variedades que, por sus peculiaridades, difícilmente pueden estar al alcance de la acción privada. La ley reglamentará la entrega de las superficies boscosas a la explotación privada, estableciendo el régimen de concesiones y sobre superficies que en ningún caso sean mayores de dos mil quinientas hectáreas de bosques, las que serán adjudicadas por licitación.`, currentText: `La Provincia promoverá el aprovechamiento racional de los bosques, teniendo en cuenta la necesidad de supervivencia, conservación y mejoramiento de las especies, la reposición de aquellas de mayor interés económico y la forestación de zonas de producción; tomando estas funciones a su cargo directo, en los casos de las variedades que, por sus peculiaridades, difícilmente pueden estar al alcance de la acción privada. La ley reglamentará la entrega de las superficies boscosas a la explotación privada, estableciendo el régimen de concesiones y sobre superficies que en ningún caso sean mayores de dos mil quinientas hectáreas de bosques, las que serán adjudicadas por licitación.`, plainLanguageExplanation: 'La Provincia promueve el uso sostenible de los bosques con reposición de especies y forestación. Las concesiones privadas para explotación forestal no pueden superar las 2500 hectáreas y se adjudican por licitación.', practicalEffects: [], examples: ['Una empresa forestal solo puede obtener una concesión para explotar hasta 2500 hectáreas de bosque, adjudicada mediante licitación pública.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['bosques', 'forestación', 'concesiones forestales', 'recursos renovables', 'licitación'], order: 48, segments: [], amendments: [] },
  { id: 'const-formosa-art-50', lawId: 'const-formosa', number: '50', title: 'Obligación de combatir plagas vegetales y animales', originalText: `El Estado Provincial y los particulares tienen la obligación de combatir por todos los medios idóneos las plagas vegetales y animales, especialmente aquéllas que afecten el normal rendimiento de la tierra.`, currentText: `El Estado Provincial y los particulares tienen la obligación de combatir por todos los medios idóneos las plagas vegetales y animales, especialmente aquéllas que afecten el normal rendimiento de la tierra.`, plainLanguageExplanation: 'Tanto el Estado como los particulares tienen el deber de combatir las plagas que afecten la producción agrícola y ganadera del territorio provincial, utilizando todos los medios disponibles.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['plagas', 'sanidad vegetal', 'sanidad animal', 'producción agropecuaria', 'deber estatal'], order: 49, segments: [], amendments: [] },
  { id: 'const-formosa-art-51', lawId: 'const-formosa', number: '51', title: 'Dominio provincial sobre recursos minerales y energéticos', originalText: `La Provincia ejercerá la plenitud del dominio exclusivo, imprescriptible e inalienable sobre los recursos minerales, incluyendo los hidrocarburíferos, las fuentes de energía hidráulica, solar, eólica, geotérmica, nuclear y toda otra que exista en su territorio, con excepción de la vegetal. El aprovechamiento podrá realizarlo por sí o por convenio con la Nación, con otros países, con otras provincias, con particulares, con empresas, públicas o privadas ya sea en lo referente a su prospección, exploración, explotación, industrialización, transporte y comercialización, reservando para sí el derecho de fiscalizar todas las etapas de aprovechamiento del recurso. El Estado propiciará la industrialización y aprovechamiento más conveniente en territorio provincial, y que el producto de las explotaciones derivadas de hidrocarburos se destine al desarrollo de la economía, atendiendo preferentemente las zonas afectadas por la actividad extractiva y privilegiando la atención de los grupos humanos con mayores necesidades sociales. La política provincial de aprovechamiento de hidrocarburos y demás recursos naturales será coordinada con la de la Nación, en atención a los intereses respectivos.`, currentText: `La Provincia ejercerá la plenitud del dominio exclusivo, imprescriptible e inalienable sobre los recursos minerales, incluyendo los hidrocarburíferos, las fuentes de energía hidráulica, solar, eólica, geotérmica, nuclear y toda otra que exista en su territorio, con excepción de la vegetal. El aprovechamiento podrá realizarlo por sí o por convenio con la Nación, con otros países, con otras provincias, con particulares, con empresas, públicas o privadas ya sea en lo referente a su prospección, exploración, explotación, industrialización, transporte y comercialización, reservando para sí el derecho de fiscalizar todas las etapas de aprovechamiento del recurso. El Estado propiciará la industrialización y aprovechamiento más conveniente en territorio provincial, y que el producto de las explotaciones derivadas de hidrocarburos se destine al desarrollo de la economía, atendiendo preferentemente las zonas afectadas por la actividad extractiva y privilegiando la atención de los grupos humanos con mayores necesidades sociales. La política provincial de aprovechamiento de hidrocarburos y demás recursos naturales será coordinada con la de la Nación, en atención a los intereses respectivos.`, plainLanguageExplanation: 'Formosa tiene dominio exclusivo, imprescriptible e inalienable sobre todos sus recursos minerales e hidrocarburíferos y fuentes de energía. Puede explotarlos directamente o a través de concesiones con la Nación, otras provincias, países o empresas privadas, siempre con control provincial. Los ingresos por hidrocarburos deben destinarse preferentemente a las zonas afectadas por la actividad extractiva.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['recursos minerales', 'hidrocarburos', 'dominio provincial', 'energía', 'regalías'], order: 50, segments: [], amendments: [] },
  { id: 'const-formosa-art-52', lawId: 'const-formosa', number: '52', title: 'Condominio sobre ríos limítrofes y tratados fluviales', originalText: `La Provincia ratifica los derechos de condominio público sobre los ríos limítrofes a su territorio. En tal carácter, podrá concertar con sus similares y países ribereños tratados sobre el aprovechamiento de las aguas de dichos ríos, sin perjuicio de las facultades del Estado Nacional en materia de navegación y comercio interprovincial e internacional.`, currentText: `La Provincia ratifica los derechos de condominio público sobre los ríos limítrofes a su territorio. En tal carácter, podrá concertar con sus similares y países ribereños tratados sobre el aprovechamiento de las aguas de dichos ríos, sin perjuicio de las facultades del Estado Nacional en materia de navegación y comercio interprovincial e internacional.`, plainLanguageExplanation: 'Formosa reafirma sus derechos sobre los ríos fronterizos (Pilcomayo y Paraguay) en carácter de condominio. Puede celebrar tratados con otras provincias o países vecinos para aprovechar esas aguas, respetando las facultades nacionales de navegación y comercio.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ríos limítrofes', 'condominio fluvial', 'Pilcomayo', 'Paraguay', 'tratados internacionales'], order: 51, segments: [], amendments: [] },
  { id: 'const-formosa-art-53', lawId: 'const-formosa', number: '53', title: 'Uso racional del agua y Código de Aguas', originalText: `La Provincia debe procurar el aprovechamiento integral y el uso racional del agua, respetando las prioridades que derivan de las necesidades de consumo de la población y el desarrollo del sector primario e industrial. Un código de aguas reglamentará todo lo atinente a este recurso. CAPITULO TERCERO.- Régimen Financiero`, currentText: `La Provincia debe procurar el aprovechamiento integral y el uso racional del agua, respetando las prioridades que derivan de las necesidades de consumo de la población y el desarrollo del sector primario e industrial. Un código de aguas reglamentará todo lo atinente a este recurso. CAPITULO TERCERO.- Régimen Financiero`, plainLanguageExplanation: 'La Provincia debe administrar el agua racionalmente, priorizando el consumo humano y el desarrollo agroindustrial. Un Código de Aguas regulará todo lo relativo a este recurso esencial.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['agua', 'uso racional', 'código de aguas', 'consumo humano', 'sector primario'], order: 52, segments: [], amendments: [] },
  { id: 'const-formosa-art-54', lawId: 'const-formosa', number: '54', title: 'Fuentes de financiamiento del Estado provincial', originalText: `La Provincia financia los gastos de su administración, tanto con fondos propios y con los obtenidos de la Nación, en virtud de su participación de los impuestos y acuerdos especiales; como con los de la actividad económica que realiza, servicios que presta y enajenación o locación de bienes de dominio fiscal, impuestos, contribuciones y tasas que imponga, debiendo éstos responder a los principios de equidad, igualdad, proporcionalidad y progresividad.`, currentText: `La Provincia financia los gastos de su administración, tanto con fondos propios y con los obtenidos de la Nación, en virtud de su participación de los impuestos y acuerdos especiales; como con los de la actividad económica que realiza, servicios que presta y enajenación o locación de bienes de dominio fiscal, impuestos, contribuciones y tasas que imponga, debiendo éstos responder a los principios de equidad, igualdad, proporcionalidad y progresividad.`, plainLanguageExplanation: 'Los gastos del Estado provincial se financian con fondos propios (impuestos, tasas, bienes fiscales) y con los que recibe de la Nación por coparticipación y acuerdos especiales. Los tributos deben respetar los principios de equidad, igualdad, proporcionalidad y progresividad.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['financiamiento provincial', 'impuestos', 'coparticipación', 'equidad tributaria', 'progresividad'], order: 53, segments: [], amendments: [] },
  { id: 'const-formosa-art-55', lawId: 'const-formosa', number: '55', title: 'Eliminación de impuestos sobre bienes básicos y vivienda', originalText: `La Legislatura, al dictar las leyes de carácter tributario, propenderá a la eliminación de los impuestos que incidan sobre los Artículos de primera necesidad y la vivienda familiar propia de tipo económico.`, currentText: `La Legislatura, al dictar las leyes de carácter tributario, propenderá a la eliminación de los impuestos que incidan sobre los Artículos de primera necesidad y la vivienda familiar propia de tipo económico.`, plainLanguageExplanation: 'Al dictar leyes impositivas, la Legislatura debe procurar eliminar los impuestos que graven artículos de primera necesidad y la vivienda familiar económica, protegiendo a los sectores de menores recursos.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['impuestos', 'primera necesidad', 'vivienda familiar', 'política tributaria'], order: 54, segments: [], amendments: [] },
  { id: 'const-formosa-art-56', lawId: 'const-formosa', number: '56', title: 'Revisión anual de impuestos permanentes', originalText: `Las leyes de impuestos permanentes son susceptibles de revisión anual.`, currentText: `Las leyes de impuestos permanentes son susceptibles de revisión anual.`, plainLanguageExplanation: 'Los impuestos permanentes pueden ser revisados y modificados cada año por la Legislatura, lo que permite adaptar la política tributaria a las necesidades del momento.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['impuestos permanentes', 'revisión anual', 'legislación tributaria'], order: 55, segments: [], amendments: [] },
  { id: 'const-formosa-art-57', lawId: 'const-formosa', number: '57', title: 'Destino específico de impuestos transitorios', originalText: `Los fondos provenientes de impuestos transitorios creados especialmente para cubrir gastos determinados o amortizar operaciones de créditos, se aplicarán exclusivamente al objeto previsto y su recaudación cesará tan pronto como éste quede cumplido.`, currentText: `Los fondos provenientes de impuestos transitorios creados especialmente para cubrir gastos determinados o amortizar operaciones de créditos, se aplicarán exclusivamente al objeto previsto y su recaudación cesará tan pronto como éste quede cumplido.`, plainLanguageExplanation: 'Los impuestos creados para un gasto específico o para cancelar deudas solo pueden destinarse a ese fin. Una vez cumplido el objetivo, la recaudación del impuesto debe cesar automáticamente.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['impuestos transitorios', 'afectación específica', 'deuda pública', 'finanzas públicas'], order: 56, segments: [], amendments: [] },
  { id: 'const-formosa-art-58', lawId: 'const-formosa', number: '58', title: 'Irrenunciabilidad de la potestad tributaria provincial', originalText: `La Provincia no podrá celebrar tratados o convenios con la Nación u otras provincias, mediante los cuales se desprenda de sus derechos originarios de gravar o percibir impuestos que le son privativos por su condición de tal.`, currentText: `La Provincia no podrá celebrar tratados o convenios con la Nación u otras provincias, mediante los cuales se desprenda de sus derechos originarios de gravar o percibir impuestos que le son privativos por su condición de tal.`, plainLanguageExplanation: 'Formosa no puede renunciar a su facultad original de cobrar los impuestos que le corresponden exclusivamente como provincia, aunque lo haga mediante tratados con la Nación u otras provincias.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['potestad tributaria', 'autonomía fiscal', 'impuestos provinciales', 'tratados fiscales'], order: 57, segments: [], amendments: [] },
  { id: 'const-formosa-art-59', lawId: 'const-formosa', number: '59', title: 'Valuación periódica de inmuebles con fines impositivos', originalText: `La valuación de los bienes inmobiliarios particulares, con fines impositivos, se hará en toda la Provincia periódicamente y por ley especial.`, currentText: `La valuación de los bienes inmobiliarios particulares, con fines impositivos, se hará en toda la Provincia periódicamente y por ley especial.`, plainLanguageExplanation: 'Los inmuebles de particulares deben ser valuados periódicamente para calcular sus impuestos. Esta valuación se realiza en toda la Provincia mediante una ley especial.', practicalEffects: [], examples: ['La valuación fiscal de una propiedad determina la base imponible del impuesto inmobiliario provincial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['valuación fiscal', 'inmuebles', 'impuesto inmobiliario', 'catastro'], order: 58, segments: [], amendments: [] },
  { id: 'const-formosa-art-60', lawId: 'const-formosa', number: '60', title: 'Coparticipación impositiva y criterio de desarrollo relativo', originalText: `La Provincia participará y coordinará con la Nación la distribución de los ingresos que provengan de la coparticipación de los gravámenes emergentes de facultades concurrentes; sosteniendo, para una parte de la masa coparticipable, el criterio de mayor participación en función directa a la brecha de desarrollo relativo, en todo acuerdo o legislación tributaria. La Provincia podrá establecer sistemas de cooperación, administración y fiscalización conjunta de los gravámenes con el Estado Nacional, las demás provincias y los municipios.`, currentText: `La Provincia participará y coordinará con la Nación la distribución de los ingresos que provengan de la coparticipación de los gravámenes emergentes de facultades concurrentes; sosteniendo, para una parte de la masa coparticipable, el criterio de mayor participación en función directa a la brecha de desarrollo relativo, en todo acuerdo o legislación tributaria. La Provincia podrá establecer sistemas de cooperación, administración y fiscalización conjunta de los gravámenes con el Estado Nacional, las demás provincias y los municipios.`, plainLanguageExplanation: 'Formosa coordina con la Nación la distribución de la coparticipación impositiva y sostiene que las provincias con mayor brecha de desarrollo deben recibir una mayor proporción. También puede establecer convenios de administración tributaria conjunta con la Nación, otras provincias y municipios.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['coparticipación', 'desarrollo relativo', 'federalismo fiscal', 'distribución de recursos', 'acuerdos tributarios'], order: 59, segments: [], amendments: [] },
  { id: 'const-formosa-art-61', lawId: 'const-formosa', number: '61', title: 'Régimen tributario: tierras inexplotadas y exención cultural', originalText: `El régimen tributario gravará, preferentemente, las tierras libre de mejoras y aquéllas que, de acuerdo con su clasificación y destino, se encuentren total o parcialmente inexplotadas; la renta y el patrimonio, y todo otro concepto que la ley establezca. Podrá establecer desgravaciones, por tiempo determinado, de las actividades que coadyuven al crecimiento económico y social. Las actividades culturales estarán exentas de gravámenes.`, currentText: `El régimen tributario gravará, preferentemente, las tierras libre de mejoras y aquéllas que, de acuerdo con su clasificación y destino, se encuentren total o parcialmente inexplotadas; la renta y el patrimonio, y todo otro concepto que la ley establezca. Podrá establecer desgravaciones, por tiempo determinado, de las actividades que coadyuven al crecimiento económico y social. Las actividades culturales estarán exentas de gravámenes.`, plainLanguageExplanation: 'El sistema impositivo de Formosa graba prioritariamente las tierras sin mejoras ni explotación, la renta y el patrimonio. Se pueden otorgar exenciones temporales a actividades que impulsen el crecimiento. Las actividades culturales están exentas de impuestos.', practicalEffects: [], examples: ['Un campo que no se destina a ninguna actividad productiva ni tiene mejoras, tributa a mayor tasa que uno explotado agrícolamente.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['régimen tributario', 'tierras inexplotadas', 'exención cultural', 'desgravaciones', 'impuesto a la tierra'], order: 60, segments: [], amendments: [] },
  { id: 'const-formosa-art-62', lawId: 'const-formosa', number: '62', title: 'Presupuesto General: aprobación anual y reconducción automática', originalText: `El Presupuesto General de la Provincia preverá los recursos pertinentes; explicitando sus objetivos y finalidades, autorizará las inversiones y gastos; y fijará el número de agentes públicos. El Presupuesto Provincial se aprobará anualmente. La falta de sanción de la ley que apruebe el presupuesto al fenecer la vigencia del anterior, implica la reconducción automática de los créditos aprobados en este último, con los ajustes que el Poder Ejecutivo determine conforme a lo establecido en la ley de aplicación. Las Sociedades o Empresas del Estado se regirán por sus propios presupuestos. Las leyes especiales que dispongan o autoricen gastos deben indicar el recurso correspondiente y ser incorporados al Presupuesto General. El Poder Legislativo, el Poder Judicial y el Tribunal de Cuentas remitirán al Poder Ejecutivo sus respectivos presupuestos, que deberán adecuarse a las pautas contenidas en el Presupuesto General de la Administración; caso contrario deberán ser reformulados, con una anticipación de treinta días de plazo fijado para la presentación del Presupuesto General, para su incorporación al mismo.`, currentText: `El Presupuesto General de la Provincia preverá los recursos pertinentes; explicitando sus objetivos y finalidades, autorizará las inversiones y gastos; y fijará el número de agentes públicos. El Presupuesto Provincial se aprobará anualmente. La falta de sanción de la ley que apruebe el presupuesto al fenecer la vigencia del anterior, implica la reconducción automática de los créditos aprobados en este último, con los ajustes que el Poder Ejecutivo determine conforme a lo establecido en la ley de aplicación. Las Sociedades o Empresas del Estado se regirán por sus propios presupuestos. Las leyes especiales que dispongan o autoricen gastos deben indicar el recurso correspondiente y ser incorporados al Presupuesto General. El Poder Legislativo, el Poder Judicial y el Tribunal de Cuentas remitirán al Poder Ejecutivo sus respectivos presupuestos, que deberán adecuarse a las pautas contenidas en el Presupuesto General de la Administración; caso contrario deberán ser reformulados, con una anticipación de treinta días de plazo fijado para la presentación del Presupuesto General, para su incorporación al mismo.`, plainLanguageExplanation: 'El presupuesto provincial se aprueba cada año y establece los gastos, inversiones y número de empleados públicos. Si el presupuesto no se aprueba a tiempo, continúa vigente el del año anterior. Las empresas del Estado tienen presupuesto propio y todos los poderes deben coordinar sus presupuestos con el presupuesto general.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presupuesto general', 'reconducción presupuestaria', 'inversiones', 'agentes públicos', 'planificación fiscal'], order: 61, segments: [], amendments: [] },
  { id: 'const-formosa-art-63', lawId: 'const-formosa', number: '63', title: 'Banca oficial como agente financiero y ejecutor crediticio', originalText: `Las bancas oficiales de la Provincia de Formosa o de los municipios podrán adoptar diversas formas jurídicas con participación mayoritaria del capital del Estado, y serán agentes financieros de todos los entes públicos provinciales o municipales. Asimismo, actuarán como órganos ejecutores de la política crediticia que fije el Estado y canalizarán el ahorro público en inversiones para el desarrollo de la economía. Las bancas oficiales valorarán, en los créditos de fomento a los productores agropecuarios, su capacidad de trabajo y solvencia moral.`, currentText: `Las bancas oficiales de la Provincia de Formosa o de los municipios podrán adoptar diversas formas jurídicas con participación mayoritaria del capital del Estado, y serán agentes financieros de todos los entes públicos provinciales o municipales. Asimismo, actuarán como órganos ejecutores de la política crediticia que fije el Estado y canalizarán el ahorro público en inversiones para el desarrollo de la economía. Las bancas oficiales valorarán, en los créditos de fomento a los productores agropecuarios, su capacidad de trabajo y solvencia moral.`, plainLanguageExplanation: 'Los bancos oficiales de la provincia y municipios tienen participación estatal mayoritaria y actúan como agentes financieros del sector público. Ejecutan la política crediticia del Estado y canalizan el ahorro hacia inversiones productivas. Al otorgar créditos de fomento agropecuario, valoran la capacidad de trabajo y la solvencia moral del productor.', practicalEffects: [], examples: ['Un pequeño productor sin garantías reales puede acceder a crédito de fomento del banco oficial si demuestra historial de trabajo y solvencia moral ante la institución.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['banca oficial', 'agente financiero', 'política crediticia', 'crédito agropecuario', 'ahorro público'], order: 62, segments: [], amendments: [] },
  { id: 'const-formosa-art-64', lawId: 'const-formosa', number: '64', title: 'Exclusión de contratistas morosos en obligaciones sociales', originalText: `El Estado se reserva el derecho a no celebrar contrato alguno con co-contratantes que se encuentren en mora en el cumplimiento de sus obligaciones previsionales, sindicales o sociales; salvo caso de acogimiento a planes de regularización con las modalidades que la ley respectiva determina. En todos los casos, el tratamiento con los co-contratantes será igualitario.`, currentText: `El Estado se reserva el derecho a no celebrar contrato alguno con co-contratantes que se encuentren en mora en el cumplimiento de sus obligaciones previsionales, sindicales o sociales; salvo caso de acogimiento a planes de regularización con las modalidades que la ley respectiva determina. En todos los casos, el tratamiento con los co-contratantes será igualitario.`, plainLanguageExplanation: 'El Estado puede negarse a contratar con empresas o personas que no estén al día con sus obligaciones previsionales, sindicales o sociales. Si el deudor se adhiere a un plan de regularización, puede acceder igualmente. El trato a todos los contratistas debe ser igualitario.', practicalEffects: [], examples: ['Una empresa que deba aportes jubilatorios de sus empleados no puede participar en licitaciones provinciales salvo que se acoja a un plan de pago.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratistas del Estado', 'obligaciones previsionales', 'morosidad', 'licitaciones', 'igualdad de trato'], order: 63, segments: [], amendments: [] },
  { id: 'const-formosa-art-65', lawId: 'const-formosa', number: '65', title: 'Operaciones financieras del Ejecutivo para el funcionamiento estatal', originalText: `El Estado Provincial, a través del Poder Ejecutivo, deberá realizar las operaciones financieras, crediticias, de préstamos y bursátiles necesarias para asegurar el funcionamiento del Estado, las inversiones indispensables, la realización de obras públicas; atender las necesidades sociales, evitar los efectos que provocan las variaciones económicas y financieras; cubrir las necesidades del Tesoro Provincial, asegurar el crecimiento económico y social provincial, afectando para ello los recursos correspondientes.`, currentText: `El Estado Provincial, a través del Poder Ejecutivo, deberá realizar las operaciones financieras, crediticias, de préstamos y bursátiles necesarias para asegurar el funcionamiento del Estado, las inversiones indispensables, la realización de obras públicas; atender las necesidades sociales, evitar los efectos que provocan las variaciones económicas y financieras; cubrir las necesidades del Tesoro Provincial, asegurar el crecimiento económico y social provincial, afectando para ello los recursos correspondientes.`, plainLanguageExplanation: 'El Poder Ejecutivo está autorizado y obligado a realizar operaciones financieras y crediticias para sostener el funcionamiento del Estado, financiar obras públicas, cubrir necesidades del Tesoro y mitigar crisis económicas, asignando los recursos necesarios.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['operaciones financieras', 'crédito público', 'obras públicas', 'Tesoro Provincial', 'Poder Ejecutivo'], order: 64, segments: [], amendments: [] },
  { id: 'const-formosa-art-66', lawId: 'const-formosa', number: '66', title: 'Fondo Provincial Agropecuario, Forestal y Minero', originalText: `El Estado creará el Fondo Provincial Agropecuario, Forestal y Minero que promoverán dichos sectores, cuyo objetivo principal es asegurar el precio de los productos de los mismos y mejorar las condiciones de su comercialización.`, currentText: `El Estado creará el Fondo Provincial Agropecuario, Forestal y Minero que promoverán dichos sectores, cuyo objetivo principal es asegurar el precio de los productos de los mismos y mejorar las condiciones de su comercialización.`, plainLanguageExplanation: 'El Estado de Formosa debe crear un fondo especial para promover los sectores agropecuario, forestal y minero, con el objetivo de garantizar precios justos a los productores y mejorar las condiciones de venta de sus productos.', practicalEffects: [], examples: ['Ante una caída del precio de la madera, el Fondo podría intervenir para garantizar un precio mínimo a los productores forestales provinciales.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fondo agropecuario', 'sector forestal', 'sector minero', 'precio de productos', 'comercialización'], order: 65, segments: [], amendments: [] },
  { id: 'const-formosa-art-67', lawId: 'const-formosa', number: '67', title: 'Fondo Provincial de Colonización y desarrollo rural', originalText: `El Estado propenderá a la creación del Fondo Provincial de Colonización, cuyo destino específico será el apoyo, orientación y planificación de la actividad primaria a efectos de lograr estabilidad en la población rural; la incorporación de nuevas tierras a la explotación agropecuaria mediante la compra de predios de propiedad privada o mejoras existentes en los fiscales; la generación y transferencia de tecnología, y la promoción de las distintas regiones por medio de adecuadas políticas específicas, según su ubicación geográfica. Los recursos del Fondo Provincial de Colonización serán inembargables por causas ajenas a su actividad, y no podrán invertirse ni distraerse para otra finalidad distinta de la de su creación. CAPITULO CUARTO.- Régimen Social`, currentText: `El Estado propenderá a la creación del Fondo Provincial de Colonización, cuyo destino específico será el apoyo, orientación y planificación de la actividad primaria a efectos de lograr estabilidad en la población rural; la incorporación de nuevas tierras a la explotación agropecuaria mediante la compra de predios de propiedad privada o mejoras existentes en los fiscales; la generación y transferencia de tecnología, y la promoción de las distintas regiones por medio de adecuadas políticas específicas, según su ubicación geográfica. Los recursos del Fondo Provincial de Colonización serán inembargables por causas ajenas a su actividad, y no podrán invertirse ni distraerse para otra finalidad distinta de la de su creación. CAPITULO CUARTO.- Régimen Social`, plainLanguageExplanation: 'El Estado debe crear un Fondo de Colonización para sostener la vida rural: apoya la actividad primaria, incorpora nuevas tierras a la producción, transfiere tecnología y promueve distintas regiones. Los recursos de este fondo son inembargables y solo pueden usarse para ese fin.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['colonización', 'desarrollo rural', 'actividad primaria', 'transferencia de tecnología', 'fondo inembargable'], order: 66, segments: [], amendments: [] },
  { id: 'const-formosa-art-68', lawId: 'const-formosa', number: '68', title: 'Protección integral de la familia y bien de familia', originalText: `La Provincia protege a la familia como célula base de la sociedad establecida, organizada y proyectada a través del afecto, facilitando su constitución y el logro de sus fines culturales, sociales y económicos. A este efecto: 1) Regulará el régimen impositivo y fiscal para la protección del núcleo familiar. 2) Promoverá medidas que hagan posible la formación del patrimonio familiar. 3) Establecerá el bien de familia como institución social, cuyo régimen será determinado por ley, sobre la base de la inembargabilidad de la vivienda familiar, sus muebles y los demás elementos necesarios para el trabajo intelectual o manual. 4) Permitirá a la familia, a través de su legislación, medios e instituciones, la educación de sus hijos de acuerdo con las propias tradiciones, valores religiosos y culturales. 5) Preservará la estabilidad del vínculo afectivo familiar, y su intimidad. 6) Ayudará a la familia en el ejercicio de su responsabilidad, en el campo de la transmisión de la vida.`, currentText: `La Provincia protege a la familia como célula base de la sociedad establecida, organizada y proyectada a través del afecto, facilitando su constitución y el logro de sus fines culturales, sociales y económicos. A este efecto: 1) Regulará el régimen impositivo y fiscal para la protección del núcleo familiar. 2) Promoverá medidas que hagan posible la formación del patrimonio familiar. 3) Establecerá el bien de familia como institución social, cuyo régimen será determinado por ley, sobre la base de la inembargabilidad de la vivienda familiar, sus muebles y los demás elementos necesarios para el trabajo intelectual o manual. 4) Permitirá a la familia, a través de su legislación, medios e instituciones, la educación de sus hijos de acuerdo con las propias tradiciones, valores religiosos y culturales. 5) Preservará la estabilidad del vínculo afectivo familiar, y su intimidad. 6) Ayudará a la familia en el ejercicio de su responsabilidad, en el campo de la transmisión de la vida.`, plainLanguageExplanation: 'La familia es la base de la sociedad y la Provincia la protege en múltiples dimensiones: impositiva, patrimonial, educativa y afectiva. El bien de familia garantiza que la vivienda familiar, sus muebles y las herramientas de trabajo no puedan ser embargados. El Estado apoya la educación de los hijos conforme a los valores de cada familia.', practicalEffects: [], examples: ['Una familia que tenga su casa inscripta como bien de familia no puede perderla en una ejecución hipotecaria por deudas ajenas al inmueble.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['familia', 'bien de familia', 'inembargabilidad', 'patrimonio familiar', 'protección social'], order: 67, segments: [], amendments: [] },
  { id: 'const-formosa-art-69', lawId: 'const-formosa', number: '69', title: 'Protección de la niñez y responsabilidad estatal subsidiaria', originalText: `La familia tiene el derecho y la obligación de proteger al niño en forma integral. El Estado lo amparará, especialmente, al desprotegido y carenciado. Asume la responsabilidad subsidiaria y preventiva, particularmente, sobre niños que se encuentren bajo cualquier forma de discriminación o ejercicio abusivo de autoridad familiar o de terceros. En caso de desamparo, corresponde al Estado proveer dicha protección, en forma directa o a través de institutos con personal especializado, y con vocación de servicio, u hogares sustitutos, sin perjuicio de la obligación de subrogarse en el ejercicio de las acciones, para demandar los aportes correspondientes a los familiares obligados. El Estado creará y estimulará la formación de fundaciones, asociaciones y demás organizaciones libres del Pueblo destinadas a tales fines. Asimismo, resguardará al niño de los efectos perniciosos de los medicamentos, la drogadicción, la corrupción, el alcoholismo y el tabaquismo, u otras adicciones, y emitirá por los medios de comunicación mensajes pacíficos y orientados a su formación, en base a los valores de la argentinidad, solidaridad y amistad.`, currentText: `La familia tiene el derecho y la obligación de proteger al niño en forma integral. El Estado lo amparará, especialmente, al desprotegido y carenciado. Asume la responsabilidad subsidiaria y preventiva, particularmente, sobre niños que se encuentren bajo cualquier forma de discriminación o ejercicio abusivo de autoridad familiar o de terceros. En caso de desamparo, corresponde al Estado proveer dicha protección, en forma directa o a través de institutos con personal especializado, y con vocación de servicio, u hogares sustitutos, sin perjuicio de la obligación de subrogarse en el ejercicio de las acciones, para demandar los aportes correspondientes a los familiares obligados. El Estado creará y estimulará la formación de fundaciones, asociaciones y demás organizaciones libres del Pueblo destinadas a tales fines. Asimismo, resguardará al niño de los efectos perniciosos de los medicamentos, la drogadicción, la corrupción, el alcoholismo y el tabaquismo, u otras adicciones, y emitirá por los medios de comunicación mensajes pacíficos y orientados a su formación, en base a los valores de la argentinidad, solidaridad y amistad.`, plainLanguageExplanation: 'La familia debe proteger al niño, pero cuando no puede hacerlo el Estado asume esa responsabilidad de manera subsidiaria, a través de institutos especializados u hogares sustitutos. El Estado también protege a los niños de las adicciones y el abuso, y promueve mensajes positivos en los medios de comunicación.', practicalEffects: [], examples: ['Cuando un niño queda sin cuidado familiar, el Estado puede intervenir colocándolo en un hogar sustituto y luego reclamar judicialmente los alimentos a los parientes obligados.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['protección de la niñez', 'responsabilidad subsidiaria', 'hogares sustitutos', 'desamparo', 'adicciones'], order: 68, segments: [], amendments: [] },
  { id: 'const-formosa-art-70', lawId: 'const-formosa', number: '70', title: 'Desarrollo integral de los jóvenes y participación cívica', originalText: `El Estado promueve el desarrollo integral de los jóvenes, procura su perfeccionamiento y su aporte creativo. Propende a lograr su plena formación cultural, intelectual, cívica y laboral, que desarrolle la conciencia nacional y facilite su participación efectiva en las actividades comunitarias y políticas.`, currentText: `El Estado promueve el desarrollo integral de los jóvenes, procura su perfeccionamiento y su aporte creativo. Propende a lograr su plena formación cultural, intelectual, cívica y laboral, que desarrolle la conciencia nacional y facilite su participación efectiva en las actividades comunitarias y políticas.`, plainLanguageExplanation: 'El Estado apoya el desarrollo integral de los jóvenes en lo cultural, intelectual, laboral y cívico. El objetivo es que sean ciudadanos formados que participen activamente en la vida comunitaria y política.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juventud', 'desarrollo integral', 'formación cívica', 'participación comunitaria', 'conciencia nacional'], order: 69, segments: [], amendments: [] },
  { id: 'const-formosa-art-71', lawId: 'const-formosa', number: '71', title: 'Protección integral de las personas mayores', originalText: `El Estado propiciará para las personas de la tercera edad una protección integral que las revalorice como activos protagonistas de esta sociedad. En caso de desamparo corresponde al Estado proveer dicha protección, ya sea en forma directa o por intermedio de institutos y fundaciones creados o por crearse, con estos fines: atención de carácter familiar; establecimientos especiales organizados con fines preventivos; hogares o centros de día; asistencia integral domiciliaria; acceso a la vivienda a través del crédito de ampliación, de adjudicación en propiedad y en comodato de por vida, asignando un porcentaje de las viviendas que se construyan con fondos nacionales, provinciales y municipales; promover su reinserción laboral con fines de laborterapia y aprovechamiento de su experiencia y capacitación, la cual será reglamentada por una ley para el justo goce de dicho derecho.`, currentText: `El Estado propiciará para las personas de la tercera edad una protección integral que las revalorice como activos protagonistas de esta sociedad. En caso de desamparo corresponde al Estado proveer dicha protección, ya sea en forma directa o por intermedio de institutos y fundaciones creados o por crearse, con estos fines: atención de carácter familiar; establecimientos especiales organizados con fines preventivos; hogares o centros de día; asistencia integral domiciliaria; acceso a la vivienda a través del crédito de ampliación, de adjudicación en propiedad y en comodato de por vida, asignando un porcentaje de las viviendas que se construyan con fondos nacionales, provinciales y municipales; promover su reinserción laboral con fines de laborterapia y aprovechamiento de su experiencia y capacitación, la cual será reglamentada por una ley para el justo goce de dicho derecho.`, plainLanguageExplanation: 'El Estado debe brindar protección integral a los adultos mayores revalorizándolos como sujetos activos. Si están desamparados, el Estado provee asistencia domiciliaria, hogares de día y acceso a vivienda. La reinserción laboral con fines terapéuticos también está garantizada por ley.', practicalEffects: [], examples: ['Un adulto mayor sin familia ni recursos puede acceder a un hogar de día o recibir asistencia domiciliaria provista por el Estado provincial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tercera edad', 'adultos mayores', 'protección integral', 'vivienda', 'reinserción laboral'], order: 70, segments: [], amendments: [] },
  { id: 'const-formosa-art-72', lawId: 'const-formosa', number: '72', title: 'Derechos de las personas con capacidades diferentes', originalText: `Las personas con capacidades diferentes tienen derecho: 1) A la protección integral del Estado, ya sea en forma directa o por intermedio de los institutos y fundaciones creadas o por crearse para ese fin. 2) A la atención en establecimientos especiales de tratamiento preventivo, teniendo el Estado el contralor de los objetivos trazados. 3) A la promoción de políticas que desarrollen la conciencia social y la solidaridad respecto de ellos.`, currentText: `Las personas con capacidades diferentes tienen derecho: 1) A la protección integral del Estado, ya sea en forma directa o por intermedio de los institutos y fundaciones creadas o por crearse para ese fin. 2) A la atención en establecimientos especiales de tratamiento preventivo, teniendo el Estado el contralor de los objetivos trazados. 3) A la promoción de políticas que desarrollen la conciencia social y la solidaridad respecto de ellos.`, plainLanguageExplanation: 'Las personas con discapacidad tienen derecho a protección integral del Estado, atención en establecimientos especiales y políticas que promuevan la solidaridad y conciencia social hacia ellas.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['discapacidad', 'capacidades diferentes', 'protección integral', 'solidaridad social'], order: 71, segments: [], amendments: [] },
  { id: 'const-formosa-art-73', lawId: 'const-formosa', number: '73', title: 'Igualdad de género, maternidad y trabajo doméstico', originalText: `El Estado garantiza a la mujer y al hombre la igualdad de derechos en lo cultural, económico, político, social y familiar, respetando sus características sociobiológicas. Brindará especial amparo a las madres solteras desprotegidas. Implementará guarderías maternales zonales en forma directa o a través de entidades competentes. La Provincia considera importante la labor del ama de casa y su aporte a la comunidad. La Legislatura dictará normas en consecuencia, y cuando éstas impliquen erogaciones se deberá prever un financiamiento que no afecte el equilibrio del tesoro provincial.`, currentText: `El Estado garantiza a la mujer y al hombre la igualdad de derechos en lo cultural, económico, político, social y familiar, respetando sus características sociobiológicas. Brindará especial amparo a las madres solteras desprotegidas. Implementará guarderías maternales zonales en forma directa o a través de entidades competentes. La Provincia considera importante la labor del ama de casa y su aporte a la comunidad. La Legislatura dictará normas en consecuencia, y cuando éstas impliquen erogaciones se deberá prever un financiamiento que no afecte el equilibrio del tesoro provincial.`, plainLanguageExplanation: 'El Estado garantiza igualdad de derechos entre hombres y mujeres. Brinda amparo especial a madres solteras desprotegidas e implementa guarderías maternales. La Constitución reconoce el valor social del trabajo del ama de casa.', practicalEffects: [], examples: ['Una madre soltera sin apoyo familiar puede acceder a programas de asistencia del Estado provincial basados en este artículo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['igualdad de género', 'madres solteras', 'guarderías', 'trabajo doméstico', 'familia'], order: 72, segments: [], amendments: [] },
  { id: 'const-formosa-art-74', lawId: 'const-formosa', number: '74', title: 'Derechos de consumidores y usuarios', originalText: `Los consumidores y usuarios de bienes y servicios tienen derecho, en la relación de consumo, a la protección de su salud, seguridad e intereses económicos; a una información adecuada y veraz, a la libertad de elección y a condiciones de trato equitativo digno. Las autoridades proveerán a la protección de esos derechos, a la educación para el consumo, a la defensa de la competencia contra toda forma de distorsión de los mercados, al control de los monopolios naturales y legales, al de la calidad y eficiencia de los servicios públicos, y a la constitución de asociaciones de consumidores y de usuarios. La legislación establecerá procedimientos eficaces para la prevención y solución de conflictos, y los marcos regulatorios de los servicios públicos de competencia provincial, previendo la necesaria participación de las asociaciones de consumidores y usuarios en los organismos de control.`, currentText: `Los consumidores y usuarios de bienes y servicios tienen derecho, en la relación de consumo, a la protección de su salud, seguridad e intereses económicos; a una información adecuada y veraz, a la libertad de elección y a condiciones de trato equitativo digno. Las autoridades proveerán a la protección de esos derechos, a la educación para el consumo, a la defensa de la competencia contra toda forma de distorsión de los mercados, al control de los monopolios naturales y legales, al de la calidad y eficiencia de los servicios públicos, y a la constitución de asociaciones de consumidores y de usuarios. La legislación establecerá procedimientos eficaces para la prevención y solución de conflictos, y los marcos regulatorios de los servicios públicos de competencia provincial, previendo la necesaria participación de las asociaciones de consumidores y usuarios en los organismos de control.`, plainLanguageExplanation: 'Los consumidores tienen derecho a información veraz, trato digno y protección de su salud y economía. El Estado controla los monopolios, la calidad de los servicios públicos y garantiza el acceso a las asociaciones de consumidores.', practicalEffects: [], examples: ['Una asociación de usuarios puede participar en la regulación del servicio de agua potable provincial en representación de los consumidores.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['consumidores', 'usuarios', 'servicios públicos', 'defensa de la competencia', 'información veraz'], order: 73, segments: [], amendments: [] },
  { id: 'const-formosa-art-75', lawId: 'const-formosa', number: '75', title: 'Derecho a la vivienda digna y política habitacional', originalText: `Todos los habitantes de la Provincia tienen el derecho a disfrutar de una vivienda digna, con sus servicios conexos y a la tierra necesaria para su asentamiento. El Estado Provincial planificará y ejecutará una política habitacional concertada con los demás niveles jurisdiccionales, instituciones sociales, o con el aporte solidario de los interesados, de acuerdo con los siguientes principios: 1) Usar racionalmente el suelo y preservar la calidad de vida, de acuerdo con el interés general y las pautas culturales y regionales de la comunidad. 2) Impedir la especulación. 3) Asistir a las familias de escasos recursos, para facilitar su acceso a la vivienda propia. 4) Incluir en los planes la construcción de viviendas familiares en predios rurales de cada beneficiario.`, currentText: `Todos los habitantes de la Provincia tienen el derecho a disfrutar de una vivienda digna, con sus servicios conexos y a la tierra necesaria para su asentamiento. El Estado Provincial planificará y ejecutará una política habitacional concertada con los demás niveles jurisdiccionales, instituciones sociales, o con el aporte solidario de los interesados, de acuerdo con los siguientes principios: 1) Usar racionalmente el suelo y preservar la calidad de vida, de acuerdo con el interés general y las pautas culturales y regionales de la comunidad. 2) Impedir la especulación. 3) Asistir a las familias de escasos recursos, para facilitar su acceso a la vivienda propia. 4) Incluir en los planes la construcción de viviendas familiares en predios rurales de cada beneficiario.`, plainLanguageExplanation: 'Todo habitante de Formosa tiene derecho a vivienda digna con servicios básicos. El Estado planifica la política habitacional para evitar la especulación, asistir a familias de bajos recursos y garantizar tierra para asentarse.', practicalEffects: [], examples: ['Una familia de bajos recursos puede acceder a planes habitacionales provinciales que incluyen la construcción de viviendas en predios rurales propios.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['vivienda digna', 'política habitacional', 'especulación inmobiliaria', 'familias de escasos recursos', 'tierra'], order: 74, segments: [], amendments: [] },
  { id: 'const-formosa-art-76', lawId: 'const-formosa', number: '76', title: 'Seguridad social universal y solidaridad', originalText: `La Provincia establecerá un régimen de seguridad social que comprenderá a toda la población, durante el transcurso de la existencia humana, contemplando las contingencias económico-sociales de la desocupación, nacimiento, enfermedad, desamparo, invalidez, vejez y muerte. Fomentará las instituciones de solidaridad social.`, currentText: `La Provincia establecerá un régimen de seguridad social que comprenderá a toda la población, durante el transcurso de la existencia humana, contemplando las contingencias económico-sociales de la desocupación, nacimiento, enfermedad, desamparo, invalidez, vejez y muerte. Fomentará las instituciones de solidaridad social.`, plainLanguageExplanation: 'La Provincia debe establecer un sistema de seguridad social universal que cubra desempleo, enfermedad, invalidez, vejez y muerte para toda la población. También fomenta las instituciones de solidaridad social.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['seguridad social', 'cobertura universal', 'desempleo', 'vejez', 'solidaridad social'], order: 75, segments: [], amendments: [] },
  { id: 'const-formosa-art-77', lawId: 'const-formosa', number: '77', title: 'Jubilación del empleado público — condiciones y haber mínimo', originalText: `La Legislatura dictará leyes de previsión social para funcionarios y empleados públicos con acceso a beneficios jubilatorios con límites mínimos de edad, de cincuenta y cinco años los varones y cincuenta las mujeres y un período mínimo de treinta años de servicios con aportes, como condición para acceder al beneficio de la jubilación ordinaria, salvo regímenes especiales fundados en razones médicas de salud. Se establecerá un haber jubilatorio móvil, no menor al ochenta y dos por ciento de la retribución del cargo o función equivalente al del empleado en actividad. El haber jubilatorio será integral e irrenunciable. Los servicios ad-honorem no originarán derecho a jubilación ni beneficio previsional alguno, ni se implementarán regímenes de jerarquizaciones, ni voluntarios.`, currentText: `La Legislatura dictará leyes de previsión social para funcionarios y empleados públicos con acceso a beneficios jubilatorios con límites mínimos de edad, de cincuenta y cinco años los varones y cincuenta las mujeres y un período mínimo de treinta años de servicios con aportes, como condición para acceder al beneficio de la jubilación ordinaria, salvo regímenes especiales fundados en razones médicas de salud. Se establecerá un haber jubilatorio móvil, no menor al ochenta y dos por ciento de la retribución del cargo o función equivalente al del empleado en actividad. El haber jubilatorio será integral e irrenunciable. Los servicios ad-honorem no originarán derecho a jubilación ni beneficio previsional alguno, ni se implementarán regímenes de jerarquizaciones, ni voluntarios.`, plainLanguageExplanation: 'Los empleados públicos acceden a jubilación ordinaria con 55 años (varones) o 50 (mujeres) y 30 años de aportes. El haber jubilatorio mínimo es del 82% móvil de la remuneración en actividad. Los servicios ad honorem no generan derecho jubilatorio.', practicalEffects: [], examples: ['Un empleado público provincial con 30 años de aportes y 55 años tiene derecho a jubilarse con el 82% de su salario en actividad.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['jubilación', 'empleado público', '82% móvil', 'previsión social', 'haber jubilatorio'], order: 76, segments: [], amendments: [] },
  { id: 'const-formosa-art-78', lawId: 'const-formosa', number: '78', title: 'Prohibición de jubilaciones de privilegio para cargos electivos', originalText: `El ejercicio de los cargos de Gobernador, Vicegobernador, Ministros, Secretario de Estado, Diputado o Diputado Convencional Constituyente con mandato cumplido, en ningún caso dará lugar a jubilación de privilegio. La Legislatura dictará el régimen respectivo sobre la base del otorgamiento de beneficios jubilatorios que contemplen la prestación de tales servicios, si se dan las condiciones mínimas de cincuenta y cinco años de edad en varones y cincuenta años en mujeres, con treinta años de aportes acreditados a cualquier sistema comprendido en el régimen de reciprocidad jubilatoria, sin perjuicio a la jubilación por invalidez o el derecho a pensión. En tales casos el haber jubilatorio no será menor al ochenta y dos por ciento móvil de la remuneración asignada a los cargos en actividad; y el haber de las jubilaciones por invalidez y pensiones será igual a lo establecido en el régimen ordinario. A partir de la vigencia de esta Constitución, no se incluirán en la liquidación de los haberes obtenidos por aplicación de las leyes especiales, los adicionales por título y antigüedad, salvo que correspondieren por aplicación de la ley provincial ordinaria.`, currentText: `El ejercicio de los cargos de Gobernador, Vicegobernador, Ministros, Secretario de Estado, Diputado o Diputado Convencional Constituyente con mandato cumplido, en ningún caso dará lugar a jubilación de privilegio. La Legislatura dictará el régimen respectivo sobre la base del otorgamiento de beneficios jubilatorios que contemplen la prestación de tales servicios, si se dan las condiciones mínimas de cincuenta y cinco años de edad en varones y cincuenta años en mujeres, con treinta años de aportes acreditados a cualquier sistema comprendido en el régimen de reciprocidad jubilatoria, sin perjuicio a la jubilación por invalidez o el derecho a pensión. En tales casos el haber jubilatorio no será menor al ochenta y dos por ciento móvil de la remuneración asignada a los cargos en actividad; y el haber de las jubilaciones por invalidez y pensiones será igual a lo establecido en el régimen ordinario. A partir de la vigencia de esta Constitución, no se incluirán en la liquidación de los haberes obtenidos por aplicación de las leyes especiales, los adicionales por título y antigüedad, salvo que correspondieren por aplicación de la ley provincial ordinaria.`, plainLanguageExplanation: 'Gobernador, ministros, diputados y convencionales no tienen jubilación de privilegio. Para acceder a beneficios jubilatorios deben cumplir las condiciones mínimas comunes (55/50 años y 30 años de aportes). El haber no puede ser inferior al 82% móvil del cargo en actividad.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['jubilación de privilegio', 'gobernador', 'ministros', 'diputados', '82% móvil', 'previsión social'], order: 77, segments: [], amendments: [] },
  { id: 'const-formosa-art-79', lawId: 'const-formosa', number: '79', title: 'Derechos de los pueblos aborígenes', originalText: `La Provincia reconoce la preexistencia de los pueblos aborígenes que la habitan. El Estado reconoce y garantiza: 1) Su identidad étnica y cultural. 2) El derecho a una educación bilingüe e intercultural. 3) La personería jurídica de sus comunidades. 4) La posesión y propiedad comunitaria de las tierras que tradicionalmente ocupan. Ninguna de ellas será enajenable, transmisible ni susceptible de gravámenes o embargos. 5) Su participación en la gestión referida a sus recursos naturales y a los demás intereses que la afecten.`, currentText: `La Provincia reconoce la preexistencia de los pueblos aborígenes que la habitan. El Estado reconoce y garantiza: 1) Su identidad étnica y cultural. 2) El derecho a una educación bilingüe e intercultural. 3) La personería jurídica de sus comunidades. 4) La posesión y propiedad comunitaria de las tierras que tradicionalmente ocupan. Ninguna de ellas será enajenable, transmisible ni susceptible de gravámenes o embargos. 5) Su participación en la gestión referida a sus recursos naturales y a los demás intereses que la afecten.`, plainLanguageExplanation: 'La Constitución reconoce la preexistencia de los pueblos indígenas de Formosa. Les garantiza identidad cultural, educación bilingüe e intercultural, personería jurídica, propiedad comunitaria inalienable de sus tierras ancestrales y participación en decisiones sobre sus recursos naturales.', practicalEffects: [], examples: ['Una comunidad wichí puede reclamar la propiedad comunitaria de las tierras que ocupa ancestralmente, siendo esas tierras inembargables e inalienables.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pueblos aborígenes', 'identidad étnica', 'educación bilingüe', 'tierras comunitarias', 'recursos naturales'], order: 78, segments: [], amendments: [] },
  { id: 'const-formosa-art-80', lawId: 'const-formosa', number: '80', title: 'Derecho a la salud — concepto integral y atención primaria', originalText: `El Estado reconoce a la salud como un proceso de equilibrio bio-psico-espiritual y social y no solamente la ausencia de afección o enfermedad; y un derecho humano fundamental, tanto de los individuos como de la comunidad, contemplando sus diferentes pautas culturales. Asumirá la estrategia de la atención primaria de la salud, comprensiva e integral, como núcleo fundamental del sistema salud, conforme con el espíritu de la justicia social.`, currentText: `El Estado reconoce a la salud como un proceso de equilibrio bio-psico-espiritual y social y no solamente la ausencia de afección o enfermedad; y un derecho humano fundamental, tanto de los individuos como de la comunidad, contemplando sus diferentes pautas culturales. Asumirá la estrategia de la atención primaria de la salud, comprensiva e integral, como núcleo fundamental del sistema salud, conforme con el espíritu de la justicia social.`, plainLanguageExplanation: 'Formosa entiende la salud como un equilibrio bio-psico-espiritual y social, no solo como ausencia de enfermedad. La atención primaria de salud, con enfoque integral y respeto a las culturas locales, es el eje del sistema de salud provincial.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho a la salud', 'atención primaria', 'salud integral', 'justicia social', 'diversidad cultural'], order: 79, segments: [], amendments: [] },
  { id: 'const-formosa-art-81', lawId: 'const-formosa', number: '81', title: 'Medios para la atención primaria de salud — vademécum regional', originalText: `El Estado asegura los medios necesarios para que en forma permanente, se lleven a la práctica los postulados de la atención primaria de la salud, comprensiva para lograr el más alto nivel posible en lo físico, mental y social de las personas y comunidades, mediante: 1) La constante promoción, prevención, asistencia y rehabilitación de la salud de todos los habitantes de la Provincia, priorizando los grupos de alto riesgo social, asegurando una atención igualitaria y equitativa. 2) La capacitación permanente de los efectores de salud, en todos los niveles de atención, como asimismo de la comunidad, para que ésta sea protagonista de su proceso de salud. 3) La planificación y evaluación participativa de las acciones de salud, orientadas fundamentalmente en las enfermedades y males sociales, socio-ambientales, endemo-epidémico y ecológicos regionales. 4) La investigación social, biomédica y sobre los servicios de salud, orientada hacia los principales problemas de enfermedad de la población, el uso de tecnología apropiada científicamente válida y socialmente aceptada; y el suministro de medicamentos esenciales. 5) El contralor de las acciones y prestaciones medico-sanitarias, teniendo como referencia los principios éticos del ejercicio profesional. 6) Toda otra acción del sistema de salud e intersectorial, que convenga a los fines del bienestar de los individuos y tendiente a mejorar la calidad de vida de la población. 7) La confección y utilización obligatoria por los organismos efectores de un vademécum medicamentoso básico social adecuado a las patologías regionales. El Estado Provincial promoverá la legislación correspondiente.`, currentText: `El Estado asegura los medios necesarios para que en forma permanente, se lleven a la práctica los postulados de la atención primaria de la salud, comprensiva para lograr el más alto nivel posible en lo físico, mental y social de las personas y comunidades, mediante: 1) La constante promoción, prevención, asistencia y rehabilitación de la salud de todos los habitantes de la Provincia, priorizando los grupos de alto riesgo social, asegurando una atención igualitaria y equitativa. 2) La capacitación permanente de los efectores de salud, en todos los niveles de atención, como asimismo de la comunidad, para que ésta sea protagonista de su proceso de salud. 3) La planificación y evaluación participativa de las acciones de salud, orientadas fundamentalmente en las enfermedades y males sociales, socio-ambientales, endemo-epidémico y ecológicos regionales. 4) La investigación social, biomédica y sobre los servicios de salud, orientada hacia los principales problemas de enfermedad de la población, el uso de tecnología apropiada científicamente válida y socialmente aceptada; y el suministro de medicamentos esenciales. 5) El contralor de las acciones y prestaciones medico-sanitarias, teniendo como referencia los principios éticos del ejercicio profesional. 6) Toda otra acción del sistema de salud e intersectorial, que convenga a los fines del bienestar de los individuos y tendiente a mejorar la calidad de vida de la población. 7) La confección y utilización obligatoria por los organismos efectores de un vademécum medicamentoso básico social adecuado a las patologías regionales. El Estado Provincial promoverá la legislación correspondiente.`, plainLanguageExplanation: 'El Estado garantiza la implementación permanente de la atención primaria de salud priorizando grupos de alto riesgo. Los organismos de salud deben usar obligatoriamente un vademécum de medicamentos básicos adaptado a las enfermedades regionales de Formosa.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['atención primaria', 'vademécum', 'salud pública', 'prevención', 'grupos de riesgo'], order: 80, segments: [], amendments: [] },
  { id: 'const-formosa-art-82', lawId: 'const-formosa', number: '82', title: 'Derechos del trabajador — catálogo constitucional', originalText: `El trabajo es un derecho dignificante del ser humano que desaparece con la extinción de la vida, y también es un deber. Gozará, en sus diversas formas, de protección de las leyes, las que deberán asegurar al trabajador: 1) Libre agremiación. 2) Libre elección; condiciones dignas y equitativas de trabajo. 3) Retribución justa, salario mínimo, vital y móvil; igual remuneración por igual tarea y sueldo anual complementario; retribuciones complementarias por razones objetivas, motivadas en las características del trabajo y el medio en que se presta, conforme con las leyes que a tal efecto se sancionen. Todo incremento deberá quedar incluido en el salario, sujeto a contribuciones y aportes. 4) Jornadas limitadas de trabajo; descanso semanal y compensatorio; vacaciones anuales remuneradas. Todo servicio extraordinario prestado por el empleado público o privado deberá ser remunerado. 5) Estabilidad en el trabajo y protección contra el despido arbitrario y sin preaviso; e indemnización a cargo del empleador. Garantías legales contra el despido en masa. 6) Seguridad e higiene en el trabajo. La Provincia dispondrá de un organismo de higiene, seguridad y medicina del trabajo, con conducción especializada. 7) Formación cultural y capacitación. 8) A la participación en las ganancias de las empresas que será obligatoria con un mínimo de un cinco por ciento, con control y cogestión en la producción y colaboración en la dirección; la ley dará operatividad a lo normado. 9) Seguridad social, que tendrá carácter de integral e irrenunciable. Seguro social obligatorio prestado por entidades oficiales, con autonomía financiera y económica o entidades privadas. 10) Gratuidad de las actuaciones administrativas o judiciales de naturaleza laboral, profesional o gremial. 11) Fomento de la cooperación libre. 12) Jubilación y pensiones móviles. 13) Rehabilitación integral de los incapacitados.`, currentText: `El trabajo es un derecho dignificante del ser humano que desaparece con la extinción de la vida, y también es un deber. Gozará, en sus diversas formas, de protección de las leyes, las que deberán asegurar al trabajador: 1) Libre agremiación. 2) Libre elección; condiciones dignas y equitativas de trabajo. 3) Retribución justa, salario mínimo, vital y móvil; igual remuneración por igual tarea y sueldo anual complementario; retribuciones complementarias por razones objetivas, motivadas en las características del trabajo y el medio en que se presta, conforme con las leyes que a tal efecto se sancionen. Todo incremento deberá quedar incluido en el salario, sujeto a contribuciones y aportes. 4) Jornadas limitadas de trabajo; descanso semanal y compensatorio; vacaciones anuales remuneradas. Todo servicio extraordinario prestado por el empleado público o privado deberá ser remunerado. 5) Estabilidad en el trabajo y protección contra el despido arbitrario y sin preaviso; e indemnización a cargo del empleador. Garantías legales contra el despido en masa. 6) Seguridad e higiene en el trabajo. La Provincia dispondrá de un organismo de higiene, seguridad y medicina del trabajo, con conducción especializada. 7) Formación cultural y capacitación. 8) A la participación en las ganancias de las empresas que será obligatoria con un mínimo de un cinco por ciento, con control y cogestión en la producción y colaboración en la dirección; la ley dará operatividad a lo normado. 9) Seguridad social, que tendrá carácter de integral e irrenunciable. Seguro social obligatorio prestado por entidades oficiales, con autonomía financiera y económica o entidades privadas. 10) Gratuidad de las actuaciones administrativas o judiciales de naturaleza laboral, profesional o gremial. 11) Fomento de la cooperación libre. 12) Jubilación y pensiones móviles. 13) Rehabilitación integral de los incapacitados.`, plainLanguageExplanation: 'El trabajo es un derecho y un deber dignificante. La Constitución garantiza al trabajador: salario mínimo vital y móvil, igual remuneración por igual tarea, estabilidad, protección contra el despido, vacaciones, seguridad e higiene, participación obligatoria en las ganancias (mínimo 5%) y gratuidad de las actuaciones laborales.', practicalEffects: [], examples: ['Un trabajador despedido sin causa y sin preaviso tiene derecho a indemnización a cargo del empleador conforme a este artículo.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos del trabajador', 'salario mínimo', 'estabilidad laboral', 'participación en ganancias', 'seguridad social'], order: 81, segments: [], amendments: [] },
  { id: 'const-formosa-art-83', lawId: 'const-formosa', number: '83', title: 'Libertad sindical y derechos gremiales', originalText: `Se garantiza a los trabajadores el derecho de asociarse en sindicatos independientes, en defensa de sus intereses profesionales, los que deben darse una organización pluralista con gestión democrática y elección periódica de sus autoridades. Los sindicatos aseguran el goce efectivo de los derechos de los trabajadores y realizan propuestas económicas y sociales a los distintos organismos del Estado. La ley asegura a los gremios los siguientes derechos: 1) De organizarse libre y democráticamente. 2) De ser reconocidos y obtener su personería gremial, sin otro requisito que la inscripción en un registro especial. 3) De concertar los convenios colectivos de trabajo. 4) De huelga, con fines de defensa de los intereses de los trabajadores. 5) Garantías necesarias para el cumplimiento de su gestión sindical a los representantes gremiales, así como las relacionadas con la estabilidad en sus empleos y licencias gremiales. 6) A la conciliación y al arbitraje. 7) A la fiscalización en el cumplimiento de las leyes del trabajo.`, currentText: `Se garantiza a los trabajadores el derecho de asociarse en sindicatos independientes, en defensa de sus intereses profesionales, los que deben darse una organización pluralista con gestión democrática y elección periódica de sus autoridades. Los sindicatos aseguran el goce efectivo de los derechos de los trabajadores y realizan propuestas económicas y sociales a los distintos organismos del Estado. La ley asegura a los gremios los siguientes derechos: 1) De organizarse libre y democráticamente. 2) De ser reconocidos y obtener su personería gremial, sin otro requisito que la inscripción en un registro especial. 3) De concertar los convenios colectivos de trabajo. 4) De huelga, con fines de defensa de los intereses de los trabajadores. 5) Garantías necesarias para el cumplimiento de su gestión sindical a los representantes gremiales, así como las relacionadas con la estabilidad en sus empleos y licencias gremiales. 6) A la conciliación y al arbitraje. 7) A la fiscalización en el cumplimiento de las leyes del trabajo.`, plainLanguageExplanation: 'Los trabajadores tienen derecho a organizarse en sindicatos independientes con gestión democrática. Los gremios tienen personería gremial, derecho a convenios colectivos, derecho de huelga, licencias gremiales para sus representantes y acceso a la conciliación y arbitraje.', practicalEffects: [], examples: ['Un sindicato puede obtener personería gremial simplemente inscribiéndose en el registro especial, sin otro requisito.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad sindical', 'sindicatos', 'huelga', 'convenios colectivos', 'personería gremial'], order: 82, segments: [], amendments: [] },
  { id: 'const-formosa-art-84', lawId: 'const-formosa', number: '84', title: 'Libertad de las asociaciones profesionales', originalText: `Las asociaciones profesionales gozarán de plena libertad para su constitución, funcionamiento e integración en federaciones o confederaciones. La legislación asegurará la plena independencia de las asociaciones profesionales frente al Estado Provincial y a las organizaciones políticas. La ley determinará en qué casos y qué autoridades podrán intervenir las asociaciones y sociedades, y los recursos correspondientes ante el Poder Judicial. Ninguna asociación podrá ser disuelta compulsivamente, ni clausurados sus locales, ni privada de su personería jurídica sino en virtud de sentencia judicial.`, currentText: `Las asociaciones profesionales gozarán de plena libertad para su constitución, funcionamiento e integración en federaciones o confederaciones. La legislación asegurará la plena independencia de las asociaciones profesionales frente al Estado Provincial y a las organizaciones políticas. La ley determinará en qué casos y qué autoridades podrán intervenir las asociaciones y sociedades, y los recursos correspondientes ante el Poder Judicial. Ninguna asociación podrá ser disuelta compulsivamente, ni clausurados sus locales, ni privada de su personería jurídica sino en virtud de sentencia judicial.`, plainLanguageExplanation: 'Las asociaciones profesionales son independientes del Estado y de los partidos políticos. No pueden ser disueltas, clausuradas ni despersonalizadas sin sentencia judicial. Solo la ley puede autorizar su intervención.', practicalEffects: [], examples: ['Un colegio de abogados no puede ser intervenido por el Ejecutivo provincial sin orden judicial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['asociaciones profesionales', 'libertad de asociación', 'independencia gremial', 'intervención judicial'], order: 83, segments: [], amendments: [] },
  { id: 'const-formosa-art-85', lawId: 'const-formosa', number: '85', title: 'Protección especial del trabajo femenino y de menores', originalText: `El Estado Provincial protegerá, especialmente, el trabajo de las mujeres y de los menores. La mujer grávida tendrá derecho al descanso antes y después del alumbramiento y continuará percibiendo su remuneración completa. Queda prohibido el trabajo de los menores de dieciséis años en actividades nocturnas y las incompatibles con su edad.`, currentText: `El Estado Provincial protegerá, especialmente, el trabajo de las mujeres y de los menores. La mujer grávida tendrá derecho al descanso antes y después del alumbramiento y continuará percibiendo su remuneración completa. Queda prohibido el trabajo de los menores de dieciséis años en actividades nocturnas y las incompatibles con su edad.`, plainLanguageExplanation: 'El Estado protege especialmente el trabajo femenino e infantil. La mujer embarazada goza de licencia pre y post parto con sueldo completo. Está prohibido el trabajo nocturno y perjudicial para menores de 16 años.', practicalEffects: [], examples: ['Una empleada pública embarazada tiene derecho a licencia pagada antes y después del parto, sin perder su remuneración.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['trabajo femenino', 'licencia por maternidad', 'trabajo infantil', 'menores de edad', 'trabajo nocturno'], order: 84, segments: [], amendments: [] },
  { id: 'const-formosa-art-86', lawId: 'const-formosa', number: '86', title: 'Participación del movimiento obrero en organismos estatales', originalText: `El Estado garantizará al movimiento obrero organizado de Formosa su participación institucional en sus distintos estamentos, así como en todo ente descentralizado, autárquico o autónomo, en sociedades de economía mixta y las sociedades con participación estatal mayoritaria, cuyas formas de gobierno sean colegiadas, mediante la designación en ellas de sus representantes gremiales. La ley fijará las normas para su cumplimiento.`, currentText: `El Estado garantizará al movimiento obrero organizado de Formosa su participación institucional en sus distintos estamentos, así como en todo ente descentralizado, autárquico o autónomo, en sociedades de economía mixta y las sociedades con participación estatal mayoritaria, cuyas formas de gobierno sean colegiadas, mediante la designación en ellas de sus representantes gremiales. La ley fijará las normas para su cumplimiento.`, plainLanguageExplanation: 'El movimiento obrero organizado de Formosa tiene derecho a participar institucionalmente en los organismos estatales con gobierno colegiado, incluyendo entes autárquicos, empresas mixtas y sociedades con mayoría estatal, designando sus propios representantes gremiales.', practicalEffects: [], examples: ['En una sociedad de economía mixta provincial, el movimiento obrero puede designar representantes en el directorio o cuerpo colegiado de gobierno.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['movimiento obrero', 'participación institucional', 'entes autárquicos', 'economía mixta', 'representación gremial'], order: 85, segments: [], amendments: [] },
  { id: 'const-formosa-art-87', lawId: 'const-formosa', number: '87', title: 'Principios de la administración pública provincial', originalText: `La Administración Pública Provincial y la Municipal están regidas por los principios de la legalidad, eficacia, austeridad, centralización normativa, desconcentración operativa, capacidad, equidad, igualdad, informalismo y publicidad de las normas o actos. Su actuación tiende a lograr economía y sencillez en el trámite, celeridad, participación y el debido procedimiento público para los administrados. La Provincia establecerá un sistema integrado de administración financiera pública, contabilidad, tesorería, crédito público y presupuesto, cuya organización, atribuciones y funciones reglamentará el Poder Ejecutivo.`, currentText: `La Administración Pública Provincial y la Municipal están regidas por los principios de la legalidad, eficacia, austeridad, centralización normativa, desconcentración operativa, capacidad, equidad, igualdad, informalismo y publicidad de las normas o actos. Su actuación tiende a lograr economía y sencillez en el trámite, celeridad, participación y el debido procedimiento público para los administrados. La Provincia establecerá un sistema integrado de administración financiera pública, contabilidad, tesorería, crédito público y presupuesto, cuya organización, atribuciones y funciones reglamentará el Poder Ejecutivo.`, plainLanguageExplanation: 'La administración pública provincial y municipal se rige por legalidad, eficacia, austeridad, equidad e informalismo. Los trámites deben ser simples y rápidos. La Provincia tendrá un sistema integrado de administración financiera que reglamenta el Ejecutivo.', practicalEffects: [], examples: ['Un ciudadano puede invocar el principio de informalismo para que su trámite no sea rechazado por defectos de forma subsanables.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['administración pública', 'legalidad', 'eficacia', 'informalismo', 'administración financiera'], order: 86, segments: [], amendments: [] },
  { id: 'const-formosa-art-88', lawId: 'const-formosa', number: '88', title: 'Estatuto del empleado público provincial — bases constitucionales', originalText: `La legislación establecerá el Estatuto General para el Empleado Público Provincial, en base a las pautas normadas por esta Constitución, orientado según el principio de igual remuneración por igual tarea, tendiente a equiparar situaciones similares, y basado en el concepto fundamental de que el empleado honra al cargo y no el cargo al empleado; respetando los convenios colectivos de trabajo, estatutos, estatuto-escalafón, escalafones, acuerdos y leyes específicas ya existentes y los que se concertaren, actualizándolos y perfeccionándolos mediante paritarias que el Estado deberá otorgar a las organizaciones sindicales agrupadas, asegurando sus individualidades y modalidades específicas. Sus preceptos serán aplicables a: 1) Poderes Ejecutivo, Legislativo y Judicial. 2) Organismos de la Constitución. 3) Entes autárquicos, descentralizados y autónomos. 4) El Estado propenderá a una política de nivelación salarial del empleado público provincial, que partiendo del orden constitucional del equilibrio y división de los Poderes, tienda a armonizar las retribuciones de la totalidad de las tareas que efectúa el mismo.`, currentText: `La legislación establecerá el Estatuto General para el Empleado Público Provincial, en base a las pautas normadas por esta Constitución, orientado según el principio de igual remuneración por igual tarea, tendiente a equiparar situaciones similares, y basado en el concepto fundamental de que el empleado honra al cargo y no el cargo al empleado; respetando los convenios colectivos de trabajo, estatutos, estatuto-escalafón, escalafones, acuerdos y leyes específicas ya existentes y los que se concertaren, actualizándolos y perfeccionándolos mediante paritarias que el Estado deberá otorgar a las organizaciones sindicales agrupadas, asegurando sus individualidades y modalidades específicas. Sus preceptos serán aplicables a: 1) Poderes Ejecutivo, Legislativo y Judicial. 2) Organismos de la Constitución. 3) Entes autárquicos, descentralizados y autónomos. 4) El Estado propenderá a una política de nivelación salarial del empleado público provincial, que partiendo del orden constitucional del equilibrio y división de los Poderes, tienda a armonizar las retribuciones de la totalidad de las tareas que efectúa el mismo.`, plainLanguageExplanation: 'El Estatuto del empleado público se basa en igual remuneración por igual tarea y la dignidad del empleado sobre el cargo. Se aplica a los tres poderes y entes autárquicos. El Estado negocia salarios a través de paritarias con los sindicatos.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['estatuto del empleado público', 'igual remuneración', 'paritarias', 'carrera administrativa', 'dignidad laboral'], order: 87, segments: [], amendments: [] },
  { id: 'const-formosa-art-89', lawId: 'const-formosa', number: '89', title: 'Acceso a la función pública por idoneidad y concurso', originalText: `Todos los habitantes de la Provincia, sin distinción de sexos, son admisibles en los empleos públicos, sin otra condición que la idoneidad. Será requisito indispensable para el ingreso la residencia previa en el territorio de la Provincia; excepto en aquellas actividades que deban realizarse fuera de ella. Como criterio de selección en igualdad de condiciones, se dará preferencia al nativo. Aquellos cuya elección o nombramiento no prevea esta Constitución, serán designados previo concurso de oposición y antecedentes que aseguren su idoneidad para el cargo conforme con las leyes respectivas. Serán inamovibles en sus puestos mientras dure su buena conducta y capacidad; la ley fijará un régimen de escalafón, derechos, deberes y obligaciones; y de traslado, remoción e indemnización de los empleados.`, currentText: `Todos los habitantes de la Provincia, sin distinción de sexos, son admisibles en los empleos públicos, sin otra condición que la idoneidad. Será requisito indispensable para el ingreso la residencia previa en el territorio de la Provincia; excepto en aquellas actividades que deban realizarse fuera de ella. Como criterio de selección en igualdad de condiciones, se dará preferencia al nativo. Aquellos cuya elección o nombramiento no prevea esta Constitución, serán designados previo concurso de oposición y antecedentes que aseguren su idoneidad para el cargo conforme con las leyes respectivas. Serán inamovibles en sus puestos mientras dure su buena conducta y capacidad; la ley fijará un régimen de escalafón, derechos, deberes y obligaciones; y de traslado, remoción e indemnización de los empleados.`, plainLanguageExplanation: 'Para ingresar al empleo público solo se requiere idoneidad y residencia previa en Formosa. Los cargos que no prevé la Constitución deben cubrirse por concurso. Los empleados son inamovibles mientras mantengan buena conducta y capacidad.', practicalEffects: [], examples: ['Una persona que postula a un cargo administrativo provincial debe rendir concurso de oposición y antecedentes para demostrar su idoneidad.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['empleo público', 'idoneidad', 'concurso', 'inamovilidad', 'residencia previa'], order: 88, segments: [], amendments: [] },
  { id: 'const-formosa-art-90', lawId: 'const-formosa', number: '90', title: 'Carrera administrativa — límite de agentes al 6% de la población', originalText: `Se establece la carrera administrativa para los agentes públicos. Se promoverá a estos efectos la capacitación de los mismos. La ley determinará su extensión y excepciones. Por igual función corresponde igual remuneración, otorgándose la garantía del sumario con intervención del afectado para su sanción o remoción. El Estado propenderá a que el número de agentes de la administración pública provincial no exceda de un seis por ciento del total de la población.`, currentText: `Se establece la carrera administrativa para los agentes públicos. Se promoverá a estos efectos la capacitación de los mismos. La ley determinará su extensión y excepciones. Por igual función corresponde igual remuneración, otorgándose la garantía del sumario con intervención del afectado para su sanción o remoción. El Estado propenderá a que el número de agentes de la administración pública provincial no exceda de un seis por ciento del total de la población.`, plainLanguageExplanation: 'Existe una carrera administrativa para los empleados públicos con igual remuneración por igual función. Antes de ser sancionado o removido, el agente tiene derecho a sumario con su participación. La planta de personal provincial no debería superar el 6% de la población.', practicalEffects: [], examples: ['Un empleado público que enfrenta una sanción disciplinaria tiene derecho a un sumario donde puede presentar su descargo antes de que se dicte resolución.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['carrera administrativa', 'igual remuneración', 'sumario administrativo', 'planta de personal', 'límite de empleo público'], order: 89, segments: [], amendments: [] },
  { id: 'const-formosa-art-91', lawId: 'const-formosa', number: '91', title: 'Incompatibilidades en el empleo público provincial', originalText: `No podrán acumularse dos o más empleos públicos o sueldos en una misma persona, esté el agente en actividad, jubilado o retirado; sean aquéllos permanentes o transitorios y aún cuando uno de ellos sea provincial y el otro u otros nacionales o municipales; con excepción del ejercicio de la docencia o por causas de carácter profesional o técnico, cuando circunstancias especiales justifiquen esta acumulación. Es incompatible el ejercicio de cualquier cargo político con actuaciones relacionadas directa o indirectamente con el mismo o actividades empresarias como contratista o proveedor del Estado Provincial. Ningún funcionario o agente público puede representar, gestionar, patrocinar o actuar de cualquier manera en contra de los intereses del Estado Provincial o de las municipalidades, bajo sanción de destitución salvo que actúe por derecho propio.`, currentText: `No podrán acumularse dos o más empleos públicos o sueldos en una misma persona, esté el agente en actividad, jubilado o retirado; sean aquéllos permanentes o transitorios y aún cuando uno de ellos sea provincial y el otro u otros nacionales o municipales; con excepción del ejercicio de la docencia o por causas de carácter profesional o técnico, cuando circunstancias especiales justifiquen esta acumulación. Es incompatible el ejercicio de cualquier cargo político con actuaciones relacionadas directa o indirectamente con el mismo o actividades empresarias como contratista o proveedor del Estado Provincial. Ningún funcionario o agente público puede representar, gestionar, patrocinar o actuar de cualquier manera en contra de los intereses del Estado Provincial o de las municipalidades, bajo sanción de destitución salvo que actúe por derecho propio.`, plainLanguageExplanation: 'Nadie puede acumular dos empleos públicos, salvo docencia o casos técnicos especiales. Un cargo político es incompatible con ser contratista o proveedor del Estado. El funcionario que actúe contra los intereses del Estado puede ser destituido.', practicalEffects: [], examples: ['Un diputado provincial no puede ser contratista del Estado provincial; hacerlo sería causal de incompatibilidad y puede resultar en su destitución.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incompatibilidades', 'doble empleo público', 'conflicto de intereses', 'contratista del Estado', 'destitución'], order: 90, segments: [], amendments: [] },
  { id: 'const-formosa-art-92', lawId: 'const-formosa', number: '92', title: 'Cultura como derecho humano — identidad formoseña y Consejo de Cultura', originalText: `La Cultura es un derecho humano fundamental. La Provincia de Formosa reconoce su realidad cultural conformada por vertientes nativas y diversas corrientes inmigratorias. Las variadas costumbres, lenguas, artes, tradiciones, folklore y demás manifestaciones culturales que coexisten, merecen el respeto y el apoyo del Estado y de la sociedad en general. Esta pluralidad cultural marca la identidad del pueblo formoseño. La educación bregará por afianzar: 1) Dicha identidad cultural. 2) La conciencia de pertenencia a Formosa en un marco nacional, latinoamericano y universal. 3) El compromiso para el desarrollo integral de la cultura. El Estado dictará leyes para el logro de estos objetivos: la defensa, preservación e incremento del patrimonio cultural; el apoyo a los creadores de cultura sin discriminación alguna; el respeto y resguardo de los derechos de autor, inventor y propiedad intelectual. Creará un Consejo de Cultura y Catastro de Bienes Culturales, integrados por representantes de las instituciones artístico-culturales. Dicha área contará con el presupuesto propio y destinado en parte al apoyo material de los artistas en todas sus manifestaciones. El patrimonio histórico y cultural de la Provincia está bajo la protección del Estado e integra su dominio público.`, currentText: `La Cultura es un derecho humano fundamental. La Provincia de Formosa reconoce su realidad cultural conformada por vertientes nativas y diversas corrientes inmigratorias. Las variadas costumbres, lenguas, artes, tradiciones, folklore y demás manifestaciones culturales que coexisten, merecen el respeto y el apoyo del Estado y de la sociedad en general. Esta pluralidad cultural marca la identidad del pueblo formoseño. La educación bregará por afianzar: 1) Dicha identidad cultural. 2) La conciencia de pertenencia a Formosa en un marco nacional, latinoamericano y universal. 3) El compromiso para el desarrollo integral de la cultura. El Estado dictará leyes para el logro de estos objetivos: la defensa, preservación e incremento del patrimonio cultural; el apoyo a los creadores de cultura sin discriminación alguna; el respeto y resguardo de los derechos de autor, inventor y propiedad intelectual. Creará un Consejo de Cultura y Catastro de Bienes Culturales, integrados por representantes de las instituciones artístico-culturales. Dicha área contará con el presupuesto propio y destinado en parte al apoyo material de los artistas en todas sus manifestaciones. El patrimonio histórico y cultural de la Provincia está bajo la protección del Estado e integra su dominio público.`, plainLanguageExplanation: 'La cultura es un derecho humano y la Provincia reconoce la diversidad cultural de sus habitantes. El Estado debe proteger el patrimonio cultural, apoyar a los creadores y crear un Consejo de Cultura con presupuesto propio.', practicalEffects: [], examples: ['Un músico folclórico formoseño puede acceder a subsidios del Consejo de Cultura, ya que el Estado está obligado constitucionalmente a apoyar a los creadores.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cultura', 'patrimonio cultural', 'identidad formoseña', 'Consejo de Cultura', 'derechos de autor'], order: 91, segments: [], amendments: [] },
  { id: 'const-formosa-art-93', lawId: 'const-formosa', number: '93', title: 'Obligaciones del Estado en educación — fines y lineamientos', originalText: `El Estado Provincial tiene la obligación según corresponda, de determinar, conducir, ejecutar, supervisar, concertar y apoyar la educación del pueblo en todas sus formas, contenidos y manifestaciones. A tal efecto, las leyes que se dicten y las políticas educativas que se fijen deberán contemplar: 1) La libertad de enseñar y aprender; el reconocimiento de la familia como agente natural y primigenio de la cultura y la educación. 2) Que la educación tiene por finalidad: la formación integral de la persona humana en su plenitud y hacia la trascendencia; que sepa vivir en paz, en familia, en democracia participativa; en cooperación, solidaridad y justicia; bregar por el desarrollo de la capacidad reflexiva y espíritu crítico; la formación de una conciencia de pertenencia a la sociedad local, provincial, regional, nacional y latinoamericana con proyección universal; y el desarrollo de la capacidad para ejercer acciones científicas, tecnológicas y artísticas, transformadoras de la realidad natural y cultural que la circundan; que aspire a vivir en salud individual y colectiva; que respete y proteja el medio ambiente en el que vive. 3) Que los planes de estudio y lineamientos curriculares que se elaboren y concierten para todos los niveles y modalidades del sistema educativo, dentro de los grados de complejidad de cada uno, adopten, como pautas normativas para la elaboración de los contenidos y metodologías, los fines fijados en el inciso anterior. 4) Que el sistema educativo se integre por niveles, ciclos y grados; por modalidades y especialidades adecuadamente articuladas entre sí; en forma regionalizada y previendo la igualdad de posibilidades y de oportunidades para todos, tanto para el ingreso como para la permanencia y la promoción a través de la asistencia de carácter psicopedagógico y socioeconómico, con especiales adecuaciones para personas con capacidades diferentes. 5) Que el sistema educativo se complemente con los acuerdos que se realicen con la Nación y los Estados Provinciales para asegurar la educación nacional, en cuanto a niveles, currículos, títulos y equivalencias. 6) Que garantice la obligatoriedad y gratuidad de la educación primaria, sin perjuicio de ampliaciones que pudiere establecer la ley. 7) Que genere y promueva formas y medios diversos para la educación permanente, alfabetización y la educación del adulto; la capacitación laboral o formación profesional, presencial o a distancia para el trabajo vinculado con el tipo de producción de cada zona, dentro del perfil de desarrollo de la Provincia y la región, con apoyo en los medios de comunicación social, según las necesidades locales zonales. 8) Que promueva una educación que resalte la cultura del trabajo, ya que éste es el medio de realización personal y social dignificante de la persona humana que lo integra consigo mismo y con la sociedad. 9) Que promueva el desarrollo y práctica de actividades recreativas y deportivas, de manera sistematizada. 10) Que la educación impartida por el Estado en las comunidades aborígenes se realicen en forma bilingüe e intercultural. 11) Que las Constituciones Nacional y Provincial y su historia sean materia obligatoria de estudios en todos los niveles y modalidades exaltando su espíritu y normativas. 12) Que se provea al sistema educativo de bibliotecas, museos, comedores escolares y recursos auxiliares didácticos.`, currentText: `El Estado Provincial tiene la obligación según corresponda, de determinar, conducir, ejecutar, supervisar, concertar y apoyar la educación del pueblo en todas sus formas, contenidos y manifestaciones. A tal efecto, las leyes que se dicten y las políticas educativas que se fijen deberán contemplar: 1) La libertad de enseñar y aprender; el reconocimiento de la familia como agente natural y primigenio de la cultura y la educación. 2) Que la educación tiene por finalidad: la formación integral de la persona humana en su plenitud y hacia la trascendencia; que sepa vivir en paz, en familia, en democracia participativa; en cooperación, solidaridad y justicia; bregar por el desarrollo de la capacidad reflexiva y espíritu crítico; la formación de una conciencia de pertenencia a la sociedad local, provincial, regional, nacional y latinoamericana con proyección universal; y el desarrollo de la capacidad para ejercer acciones científicas, tecnológicas y artísticas, transformadoras de la realidad natural y cultural que la circundan; que aspire a vivir en salud individual y colectiva; que respete y proteja el medio ambiente en el que vive. 3) Que los planes de estudio y lineamientos curriculares que se elaboren y concierten para todos los niveles y modalidades del sistema educativo, dentro de los grados de complejidad de cada uno, adopten, como pautas normativas para la elaboración de los contenidos y metodologías, los fines fijados en el inciso anterior. 4) Que el sistema educativo se integre por niveles, ciclos y grados; por modalidades y especialidades adecuadamente articuladas entre sí; en forma regionalizada y previendo la igualdad de posibilidades y de oportunidades para todos, tanto para el ingreso como para la permanencia y la promoción a través de la asistencia de carácter psicopedagógico y socioeconómico, con especiales adecuaciones para personas con capacidades diferentes. 5) Que el sistema educativo se complemente con los acuerdos que se realicen con la Nación y los Estados Provinciales para asegurar la educación nacional, en cuanto a niveles, currículos, títulos y equivalencias. 6) Que garantice la obligatoriedad y gratuidad de la educación primaria, sin perjuicio de ampliaciones que pudiere establecer la ley. 7) Que genere y promueva formas y medios diversos para la educación permanente, alfabetización y la educación del adulto; la capacitación laboral o formación profesional, presencial o a distancia para el trabajo vinculado con el tipo de producción de cada zona, dentro del perfil de desarrollo de la Provincia y la región, con apoyo en los medios de comunicación social, según las necesidades locales zonales. 8) Que promueva una educación que resalte la cultura del trabajo, ya que éste es el medio de realización personal y social dignificante de la persona humana que lo integra consigo mismo y con la sociedad. 9) Que promueva el desarrollo y práctica de actividades recreativas y deportivas, de manera sistematizada. 10) Que la educación impartida por el Estado en las comunidades aborígenes se realicen en forma bilingüe e intercultural. 11) Que las Constituciones Nacional y Provincial y su historia sean materia obligatoria de estudios en todos los niveles y modalidades exaltando su espíritu y normativas. 12) Que se provea al sistema educativo de bibliotecas, museos, comedores escolares y recursos auxiliares didácticos.`, plainLanguageExplanation: 'El Estado provincial tiene la obligación de dirigir y financiar la educación en todos sus niveles. La educación primaria es obligatoria y gratuita. Debe incluir educación bilingüe para comunidades indígenas, formación para el trabajo y enseñanza de las Constituciones Nacional y Provincial.', practicalEffects: [], examples: ['Un estudiante de una comunidad wichí tiene derecho constitucional a recibir educación en su lengua materna junto con el castellano.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['educación', 'obligatoriedad', 'gratuidad', 'educación bilingüe', 'libertad de enseñanza'], order: 92, segments: [], amendments: [] },
  { id: 'const-formosa-art-94', lawId: 'const-formosa', number: '94', title: 'Derecho a crear instituciones educativas — subsidios a escuelas privadas', originalText: `Las personas físicas o jurídicas vinculadas con la educación, la Iglesia Católica, los credos religiosos reconocidos oficialmente, y los municipios tienen derecho a crear instituciones educativas ajustadas a los principios de esta Constitución. No se reconocen más títulos de estudios que los autorizados por el Estado Nacional y Provincial. La ley reglamentará el régimen de subsidios del Estado a aquellas escuelas públicas de gestión privada que cumplen funciones sociales no discriminatorias y demás requisitos que se fijen y que no persigan fines de lucro.`, currentText: `Las personas físicas o jurídicas vinculadas con la educación, la Iglesia Católica, los credos religiosos reconocidos oficialmente, y los municipios tienen derecho a crear instituciones educativas ajustadas a los principios de esta Constitución. No se reconocen más títulos de estudios que los autorizados por el Estado Nacional y Provincial. La ley reglamentará el régimen de subsidios del Estado a aquellas escuelas públicas de gestión privada que cumplen funciones sociales no discriminatorias y demás requisitos que se fijen y que no persigan fines de lucro.`, plainLanguageExplanation: 'Particulares, iglesias y municipios pueden crear escuelas respetando la Constitución. Los títulos solo valen si están autorizados por el Estado. Las escuelas privadas sin fines de lucro que sean inclusivas pueden recibir subsidios estatales.', practicalEffects: [], examples: ['Una comunidad religiosa que funda una escuela en un área rural puede solicitar subsidios provinciales si no discrimina y no persigue lucro.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['educación privada', 'subsidios', 'libertad de enseñanza', 'títulos habilitantes'], order: 93, segments: [], amendments: [] },
  { id: 'const-formosa-art-95', lawId: 'const-formosa', number: '95', title: 'Financiamiento de la educación y la cultura', originalText: `Los fondos para la educación y la cultura se constituyen con contribuciones y rentas propias, de la Nación o de otras provincias, con donaciones y legados particulares; con aportes comunitarios y sectoriales; con las partidas asignadas por el Presupuesto General de Recursos y Gastos de la Provincia, de manera que se aseguren en forma permanente los recursos suficientes para su sostén, extensión y mejoramiento.`, currentText: `Los fondos para la educación y la cultura se constituyen con contribuciones y rentas propias, de la Nación o de otras provincias, con donaciones y legados particulares; con aportes comunitarios y sectoriales; con las partidas asignadas por el Presupuesto General de Recursos y Gastos de la Provincia, de manera que se aseguren en forma permanente los recursos suficientes para su sostén, extensión y mejoramiento.`, plainLanguageExplanation: 'El financiamiento de la educación y la cultura proviene del presupuesto provincial, aportes nacionales, donaciones y contribuciones comunitarias, y debe garantizar recursos permanentes y suficientes.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['financiamiento educativo', 'presupuesto', 'cultura', 'educación'], order: 94, segments: [], amendments: [] },
  { id: 'const-formosa-art-96', lawId: 'const-formosa', number: '96', title: 'Gobierno y administración de la educación provincial', originalText: `El gobierno, la dirección y la administración de la educación de la Provincia se ajustarán entre otros a los siguientes principios: 1) La conducción de la educación tendrá jerarquía ministerial a efectos de asegurar la unidad política y normativa. 2) Se asegurará la representación de los docentes a través de su participación democrática y electiva en los órganos colegiados educativos. 3) La desconcentración operativa se cumplirá de modo regionalizado, por intermedio de organismos de conducción zonal en los niveles y modalidades, cuando su necesidad se detecte, asegurando la participación democrática de docentes, padres, vecinos y, según corresponda, alumnos. 4) Las unidades escolares constituyen comunidades educativas a los efectos de la práctica democrática y la participación en la toma de decisiones en la planificación institucional. 5) En la asignación de roles y funciones en los distintos estamentos desconcentrados de la conducción educativa se asegurará que los aspectos técnico-pedagógicos estén a cargo de docentes. Igual criterio regirá para aquellos aspectos inherentes a la incumbencia y autonomía profesionales. 6) Para fijar las políticas anuales del sector, la conducción ministerial deberá dar participación a los docentes, según el espíritu de este artículo.`, currentText: `El gobierno, la dirección y la administración de la educación de la Provincia se ajustarán entre otros a los siguientes principios: 1) La conducción de la educación tendrá jerarquía ministerial a efectos de asegurar la unidad política y normativa. 2) Se asegurará la representación de los docentes a través de su participación democrática y electiva en los órganos colegiados educativos. 3) La desconcentración operativa se cumplirá de modo regionalizado, por intermedio de organismos de conducción zonal en los niveles y modalidades, cuando su necesidad se detecte, asegurando la participación democrática de docentes, padres, vecinos y, según corresponda, alumnos. 4) Las unidades escolares constituyen comunidades educativas a los efectos de la práctica democrática y la participación en la toma de decisiones en la planificación institucional. 5) En la asignación de roles y funciones en los distintos estamentos desconcentrados de la conducción educativa se asegurará que los aspectos técnico-pedagógicos estén a cargo de docentes. Igual criterio regirá para aquellos aspectos inherentes a la incumbencia y autonomía profesionales. 6) Para fijar las políticas anuales del sector, la conducción ministerial deberá dar participación a los docentes, según el espíritu de este artículo.`, plainLanguageExplanation: 'La educación provincial tiene rango ministerial y se organiza de forma descentralizada por zonas. Los docentes participan democráticamente en los órganos de gobierno educativo y los aspectos pedagógicos siempre deben estar a cargo de docentes.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['gobierno educativo', 'ministerio de educación', 'participación docente', 'descentralización'], order: 95, segments: [], amendments: [] },
  { id: 'const-formosa-art-97', lawId: 'const-formosa', number: '97', title: 'Estatuto docente — derechos laborales y jubilación', originalText: `Los docentes provinciales contarán por ley, con un estatuto que garantice los siguientes principios en todos los niveles y modalidades: 1) Régimen de concurso para ingreso, ascensos y otros cambios de situación de revista. 2) Escalafón y estabilidad laboral. 3) La participación en los cuerpos colegiados del sistema educativo provincial. 4) Formación, actualización y perfeccionamiento facilitados por el Estado con la participación de la comunidad educativa. 5) Respeto y primacía absoluta del título docente para las áreas de su especialidad. 6) Salarios dignos y diferenciados por funciones y jerarquías. 7) Actualización permanente del mencionado Estatuto con la participación libre y democrática de los docentes. 8) La jubilación será con veinticinco años de aporte sin límite de edad. La ley determinará los casos y los plazos en que dicha jubilación será obligatoria.`, currentText: `Los docentes provinciales contarán por ley, con un estatuto que garantice los siguientes principios en todos los niveles y modalidades: 1) Régimen de concurso para ingreso, ascensos y otros cambios de situación de revista. 2) Escalafón y estabilidad laboral. 3) La participación en los cuerpos colegiados del sistema educativo provincial. 4) Formación, actualización y perfeccionamiento facilitados por el Estado con la participación de la comunidad educativa. 5) Respeto y primacía absoluta del título docente para las áreas de su especialidad. 6) Salarios dignos y diferenciados por funciones y jerarquías. 7) Actualización permanente del mencionado Estatuto con la participación libre y democrática de los docentes. 8) La jubilación será con veinticinco años de aporte sin límite de edad. La ley determinará los casos y los plazos en que dicha jubilación será obligatoria.`, plainLanguageExplanation: 'Los docentes provinciales tienen un estatuto que les garantiza ingreso y ascenso por concurso, estabilidad laboral, salarios dignos y jubilación a los 25 años de aportes sin importar la edad.', practicalEffects: [], examples: ['Una maestra que completa 25 años de aportes puede jubilarse aunque tenga menos de 60 años, a diferencia del régimen general.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['estatuto docente', 'jubilación docente', 'concurso', 'estabilidad laboral', 'salario docente'], order: 96, segments: [], amendments: [] },
  { id: 'const-formosa-art-98', lawId: 'const-formosa', number: '98', title: 'Nivel universitario — autonomía y vinculación social', originalText: `El Estado provincial podrá crear o reconocer el nivel universitario de la educación. La presencia de instituciones educativas universitarias en la comunidad formoseña será objeto de promoción y apoyo en término de su accionar específico, de sus vínculos con los demás actores y sectores sociales, de su inserción y contribución a los procesos de desarrollo económico y social, científico y tecnológico. Asimismo velará por la preservación de la identidad y de la originalidad de las instituciones universitarias integradas al territorio provincial, en tanto se constituyan como espacio específico de construcción y socialización de saberes, de autonomía de pensamientos, de producción científica cualitativa, de articulación, de vinculación tecnológica con los sectores de la producción y el trabajo, y se conjuguen con las demandas sociales de crecimiento y bienestar; sirviendo al Pueblo que la sustenta sin perder su autonomía, entendida ésta como derecho que pertenece a la comunidad y que le permite a la institución universitaria cumplir sus funciones como depositaria de una tarea eminentemente pública.`, currentText: `El Estado provincial podrá crear o reconocer el nivel universitario de la educación. La presencia de instituciones educativas universitarias en la comunidad formoseña será objeto de promoción y apoyo en término de su accionar específico, de sus vínculos con los demás actores y sectores sociales, de su inserción y contribución a los procesos de desarrollo económico y social, científico y tecnológico. Asimismo velará por la preservación de la identidad y de la originalidad de las instituciones universitarias integradas al territorio provincial, en tanto se constituyan como espacio específico de construcción y socialización de saberes, de autonomía de pensamientos, de producción científica cualitativa, de articulación, de vinculación tecnológica con los sectores de la producción y el trabajo, y se conjuguen con las demandas sociales de crecimiento y bienestar; sirviendo al Pueblo que la sustenta sin perder su autonomía, entendida ésta como derecho que pertenece a la comunidad y que le permite a la institución universitaria cumplir sus funciones como depositaria de una tarea eminentemente pública.`, plainLanguageExplanation: 'El Estado puede crear o reconocer universidades y debe apoyar su vinculación con la sociedad y el desarrollo productivo. Las universidades son autónomas y deben servir al pueblo sin perder esa autonomía.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['universidad', 'autonomía universitaria', 'educación superior', 'vinculación tecnológica'], order: 97, segments: [], amendments: [] },
  { id: 'const-formosa-art-99', lawId: 'const-formosa', number: '99', title: 'Requisitos para universidades reconocidas por la Provincia', originalText: `Las universidades que fueran objeto de reconocimiento, estímulo, promoción, contribución y articulación por parte del Estado provincial deberán contemplar los siguientes aspectos, sin perjuicios de otros que establecieren para sí: 1) Formación de recursos humanos. 2) Promoción y desarrollo de la investigación. 3) Extensión universitaria. 4) Vinculación tecnológica y laboral. 5) Articulación con el sistema educativo provincial. 6) Función ética, de autonomía, responsabilidad y prospectiva. 7) Igualdad de acceso irrestricto. 8) Otorgamiento de becas. 9) Diversificación académica y curricular como medio de reforzar la igualdad de oportunidades. 10) Innovación educativa, pensamiento crítico y creatividad. 11) Gobierno autónomo integrado por docentes, alumnos egresados, no docentes elegidos libre y democráticamente y representantes de sectores sociales. 12) Educación enraizada en los valores, tradiciones y aspiraciones de la sociedad.`, currentText: `Las universidades que fueran objeto de reconocimiento, estímulo, promoción, contribución y articulación por parte del Estado provincial deberán contemplar los siguientes aspectos, sin perjuicios de otros que establecieren para sí: 1) Formación de recursos humanos. 2) Promoción y desarrollo de la investigación. 3) Extensión universitaria. 4) Vinculación tecnológica y laboral. 5) Articulación con el sistema educativo provincial. 6) Función ética, de autonomía, responsabilidad y prospectiva. 7) Igualdad de acceso irrestricto. 8) Otorgamiento de becas. 9) Diversificación académica y curricular como medio de reforzar la igualdad de oportunidades. 10) Innovación educativa, pensamiento crítico y creatividad. 11) Gobierno autónomo integrado por docentes, alumnos egresados, no docentes elegidos libre y democráticamente y representantes de sectores sociales. 12) Educación enraizada en los valores, tradiciones y aspiraciones de la sociedad.`, plainLanguageExplanation: 'Para recibir apoyo provincial, las universidades deben garantizar acceso irrestricto e igualitario, ofrecer becas, articularse con el sistema educativo provincial y tener gobierno democrático con participación de docentes, estudiantes y egresados.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['universidad', 'acceso irrestricto', 'becas', 'gobierno universitario', 'extensión universitaria'], order: 98, segments: [], amendments: [] },
  { id: 'const-formosa-art-100', lawId: 'const-formosa', number: '100', title: 'Derecho a la ciencia y tecnología — sistema provincial', originalText: `Todas las personas tienen derecho a acceder a los beneficios de la ciencia y de la tecnología. Para ello el Estado deberá: 1) Organizar un sistema provincial de ciencia y tecnología, con participación de científicos, tecnólogos, instituciones y empresas. 2) Incentivar la formación y perfeccionamiento de recursos humanos para el desarrollo científico y tecnológico. 3) Fomentar la cooperación entre las instituciones de investigación científica, de desarrollo tecnológico y de empresas productivas, públicas y privadas, que evite la dispersión y duplicación de esfuerzos, estimule su discusión y utilización en todos los ámbitos de la sociedad. 4) Crear y desarrollar servicios técnicos y de extensión educativa y cultural, tales como investigación y desarrollo científico y tecnológico. Se privilegiará lo inherente al uso y control de los recursos naturales provinciales con énfasis en los del sector primario y los energéticos, como asimismo el desarrollo de ventajas competitivas en la producción de bienes y servicios, especialmente en los siguientes aspectos: a) Innovación y desarrollo tecnológico de procesos productivos. b) Cultura empresarial. c) Rentabilidad. d) Actitud estratégica. e) Diseño y competencia. f) Apertura exterior. g) Apoyo e incentivo a las empresas, entidades cooperativas y uniones asociativas que inviertan en investigación y desarrollo tecnológico y en la formación y perfeccionamiento de sus recursos humanos, siempre que asegure fuentes de trabajo a la comunidad. 5) Concertar con la Nación, Provincias o Estados extranjeros su participación en planes de investigación o intercambio. Las Municipalidades podrán organizar en sus respectivas jurisdicciones el Sistema Municipal de Ciencia y Tecnología, sujeto a los principios de este artículo.`, currentText: `Todas las personas tienen derecho a acceder a los beneficios de la ciencia y de la tecnología. Para ello el Estado deberá: 1) Organizar un sistema provincial de ciencia y tecnología, con participación de científicos, tecnólogos, instituciones y empresas. 2) Incentivar la formación y perfeccionamiento de recursos humanos para el desarrollo científico y tecnológico. 3) Fomentar la cooperación entre las instituciones de investigación científica, de desarrollo tecnológico y de empresas productivas, públicas y privadas, que evite la dispersión y duplicación de esfuerzos, estimule su discusión y utilización en todos los ámbitos de la sociedad. 4) Crear y desarrollar servicios técnicos y de extensión educativa y cultural, tales como investigación y desarrollo científico y tecnológico. Se privilegiará lo inherente al uso y control de los recursos naturales provinciales con énfasis en los del sector primario y los energéticos, como asimismo el desarrollo de ventajas competitivas en la producción de bienes y servicios, especialmente en los siguientes aspectos: a) Innovación y desarrollo tecnológico de procesos productivos. b) Cultura empresarial. c) Rentabilidad. d) Actitud estratégica. e) Diseño y competencia. f) Apertura exterior. g) Apoyo e incentivo a las empresas, entidades cooperativas y uniones asociativas que inviertan en investigación y desarrollo tecnológico y en la formación y perfeccionamiento de sus recursos humanos, siempre que asegure fuentes de trabajo a la comunidad. 5) Concertar con la Nación, Provincias o Estados extranjeros su participación en planes de investigación o intercambio. Las Municipalidades podrán organizar en sus respectivas jurisdicciones el Sistema Municipal de Ciencia y Tecnología, sujeto a los principios de este artículo.`, plainLanguageExplanation: 'Toda persona tiene derecho a beneficiarse de la ciencia y la tecnología. El Estado debe crear un sistema provincial de ciencia y tecnología, priorizar el uso de los recursos naturales propios e incentivar la formación de investigadores.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ciencia', 'tecnología', 'recursos naturales', 'investigación', 'innovación'], order: 99, segments: [], amendments: [] },
  { id: 'const-formosa-art-101', lawId: 'const-formosa', number: '101', title: 'Centro de investigación de datos genéticos — filiación', originalText: `El Estado provincial promoverá un centro de investigación de datos genéticos que realice estudios sobre filiación en las condiciones que fije la ley.`, currentText: `El Estado provincial promoverá un centro de investigación de datos genéticos que realice estudios sobre filiación en las condiciones que fije la ley.`, plainLanguageExplanation: 'La Provincia debe crear un centro de genética para realizar estudios de filiación (determinar parentesco biológico), regulado por ley.', practicalEffects: [], examples: ['Una persona que busca conocer su identidad biológica puede acudir al centro provincial de datos genéticos para realizar estudios de ADN.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['datos genéticos', 'filiación', 'identidad biológica', 'ADN'], order: 100, segments: [], amendments: [] },
  { id: 'const-formosa-art-102', lawId: 'const-formosa', number: '102', title: 'Dominio público del espectro radioeléctrico — radiodifusión provincial', originalText: `La Provincia, partiendo del espíritu democrático sentado en la presente Constitución y en ejercicio de su autonomía, reafirma el dominio público sobre el espectro de frecuencia, reservándose el derecho de: 1) Legislar en materia de radiodifusión. 2) Promover la instalación de emisoras en zonas de frontera, en coordinación con la Nación. 3) Integrarse a una política federal de radiodifusión y televisión. 4) Todos los medios de difusión masiva de la Provincia deben ceder un espacio gratuito de dos horas semanales en su programación, que deberán ser utilizados para educación a distancia.`, currentText: `La Provincia, partiendo del espíritu democrático sentado en la presente Constitución y en ejercicio de su autonomía, reafirma el dominio público sobre el espectro de frecuencia, reservándose el derecho de: 1) Legislar en materia de radiodifusión. 2) Promover la instalación de emisoras en zonas de frontera, en coordinación con la Nación. 3) Integrarse a una política federal de radiodifusión y televisión. 4) Todos los medios de difusión masiva de la Provincia deben ceder un espacio gratuito de dos horas semanales en su programación, que deberán ser utilizados para educación a distancia.`, plainLanguageExplanation: 'El espectro radioeléctrico es de dominio público provincial. La Provincia puede legislar en radiodifusión y los medios masivos de comunicación deben ceder 2 horas semanales gratuitas para educación a distancia.', practicalEffects: [], examples: ['Una radio local de Formosa debe reservar 2 horas semanales de su programación para contenidos de educación a distancia.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['radiodifusión', 'espectro radioeléctrico', 'medios de comunicación', 'educación a distancia'], order: 101, segments: [], amendments: [] },
  { id: 'const-formosa-art-103', lawId: 'const-formosa', number: '103', title: 'Poder Legislativo — Cámara de Diputados unicameral', originalText: `El Poder Legislativo será ejercido por una Cámara de Diputados, elegidos directamente por el pueblo con base en la población, no pudiendo exceder de treinta el número de sus miembros.`, currentText: `El Poder Legislativo será ejercido por una Cámara de Diputados, elegidos directamente por el pueblo con base en la población, no pudiendo exceder de treinta el número de sus miembros.`, plainLanguageExplanation: 'El Poder Legislativo de Formosa es unicameral: una sola Cámara de Diputados elegidos directamente por el pueblo, con un máximo de 30 miembros.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Poder Legislativo', 'Cámara de Diputados', 'unicameral', 'elección directa'], order: 102, segments: [], amendments: [] },
  { id: 'const-formosa-art-104', lawId: 'const-formosa', number: '104', title: 'Requisitos para ser Diputado provincial', originalText: `Para ser Diputado se requiere: 1) Ser ciudadano argentino, o naturalizado con seis años en el ejercicio de la ciudadanía. 2) Haber cumplido veintiún años de edad. 3) Tener seis años de residencia inmediata en la Provincia, sino se ha nacido en ella. A tales efectos no causa interrupción la ausencia motivada por el ejercicio de funciones políticas o técnicas al servicio del Gobierno Federal o de la Provincia.`, currentText: `Para ser Diputado se requiere: 1) Ser ciudadano argentino, o naturalizado con seis años en el ejercicio de la ciudadanía. 2) Haber cumplido veintiún años de edad. 3) Tener seis años de residencia inmediata en la Provincia, sino se ha nacido en ella. A tales efectos no causa interrupción la ausencia motivada por el ejercicio de funciones políticas o técnicas al servicio del Gobierno Federal o de la Provincia.`, plainLanguageExplanation: 'Para ser diputado provincial se requiere: ciudadanía argentina (nativa o naturalizada con 6 años), 21 años de edad cumplidos y 6 años de residencia en la Provincia (salvo haber nacido en ella).', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Diputado', 'requisitos', 'ciudadanía', 'residencia'], order: 103, segments: [], amendments: [] },
  { id: 'const-formosa-art-105', lawId: 'const-formosa', number: '105', title: 'Duración del mandato y renovación de la Cámara', originalText: `Los diputados durarán cuatro años en el ejercicio de sus cargos, y podrán ser reelectos. La Cámara se renovará por mitad cada dos años. Al constituirse la Legislatura, se determinará por sorteo los diputados que cesarán en el primer bienio.`, currentText: `Los diputados durarán cuatro años en el ejercicio de sus cargos, y podrán ser reelectos. La Cámara se renovará por mitad cada dos años. Al constituirse la Legislatura, se determinará por sorteo los diputados que cesarán en el primer bienio.`, plainLanguageExplanation: 'Los diputados duran 4 años en su cargo y pueden ser reelectos. La Cámara se renueva por mitad cada 2 años. Al constituirse la primera Legislatura, se sortea qué diputados cesan en el primer bienio.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mandato', 'reelección', 'renovación legislativa', 'Cámara de Diputados'], order: 104, segments: [], amendments: [] },
  { id: 'const-formosa-art-106', lawId: 'const-formosa', number: '106', title: 'Sesiones ordinarias y extraordinarias de la Cámara', originalText: `La Cámara abrirá sus sesiones por sí misma y se reunirá todos los años en sesiones ordinarias, desde el día primero de marzo hasta el día treinta de noviembre, pudiendo prorrogarse sus sesiones, por resolución tomada antes de fenecer el período, para tratar el asunto que ella determine al acordar la prórroga. El Presidente de la Cámara a petición suscripta por una cuarta parte del total de diputados, podrá convocarla extraordinariamente por un período no mayor de treinta días, cuando un grave asunto de interés o de orden público lo requiera; en las sesiones extraordinarias no se tratarán sino los asuntos determinados en la convocatoria.`, currentText: `La Cámara abrirá sus sesiones por sí misma y se reunirá todos los años en sesiones ordinarias, desde el día primero de marzo hasta el día treinta de noviembre, pudiendo prorrogarse sus sesiones, por resolución tomada antes de fenecer el período, para tratar el asunto que ella determine al acordar la prórroga. El Presidente de la Cámara a petición suscripta por una cuarta parte del total de diputados, podrá convocarla extraordinariamente por un período no mayor de treinta días, cuando un grave asunto de interés o de orden público lo requiera; en las sesiones extraordinarias no se tratarán sino los asuntos determinados en la convocatoria.`, plainLanguageExplanation: 'La Cámara funciona en sesiones ordinarias del 1° de marzo al 30 de noviembre. Puede prorrogarse o convocarse en sesiones extraordinarias (por hasta 30 días) cuando un asunto grave de interés público lo requiera.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sesiones ordinarias', 'sesiones extraordinarias', 'Cámara de Diputados', 'período legislativo'], order: 105, segments: [], amendments: [] },
  { id: 'const-formosa-art-107', lawId: 'const-formosa', number: '107', title: 'Presidente Nato — jefe administrativo de la Cámara', originalText: `El Presidente Nato de la Cámara es el jefe administrativo; designa y remueve por sí a los secretarios, conforme con el reglamento que dicte el Cuerpo.`, currentText: `El Presidente Nato de la Cámara es el jefe administrativo; designa y remueve por sí a los secretarios, conforme con el reglamento que dicte el Cuerpo.`, plainLanguageExplanation: 'El Presidente Nato de la Cámara actúa como jefe administrativo y tiene la potestad de designar y remover a los secretarios conforme al reglamento que dicte el cuerpo.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Presidente Nato', 'jefe administrativo', 'secretarios', 'Cámara de Diputados'], order: 106, segments: [], amendments: [] },
  { id: 'const-formosa-art-108', lawId: 'const-formosa', number: '108', title: 'Cámara como juez de elecciones — revisión por Superior Tribunal', originalText: `La Cámara es juez exclusivo de las elecciones de sus miembros, sin perjuicio de la acción de los tribunales para castigar las violaciones de la ley electoral. El juzgamiento del diploma deberá hacerse a más tardar dentro del mes de sesiones posterior a su presentación. En caso contrario el interesado tiene derecho a someter la validez de su título a la decisión del Superior Tribunal de Justicia, el que se expedirá dentro del término de quince días, con audiencia del interesado y de cualquier candidato reclamante que hubiere obtenido votos en la misma elección. La resolución de la Cámara o del Superior Tribunal de Justicia no podrá reverse.`, currentText: `La Cámara es juez exclusivo de las elecciones de sus miembros, sin perjuicio de la acción de los tribunales para castigar las violaciones de la ley electoral. El juzgamiento del diploma deberá hacerse a más tardar dentro del mes de sesiones posterior a su presentación. En caso contrario el interesado tiene derecho a someter la validez de su título a la decisión del Superior Tribunal de Justicia, el que se expedirá dentro del término de quince días, con audiencia del interesado y de cualquier candidato reclamante que hubiere obtenido votos en la misma elección. La resolución de la Cámara o del Superior Tribunal de Justicia no podrá reverse.`, plainLanguageExplanation: 'La Cámara es el juez de las elecciones de sus propios miembros, pero si no resuelve en tiempo, el candidato puede someter su título al Superior Tribunal de Justicia, que debe expedirse en 15 días.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['diploma legislativo', 'juicio de elecciones', 'Superior Tribunal de Justicia', 'validez de títulos'], order: 107, segments: [], amendments: [] },
  { id: 'const-formosa-art-109', lawId: 'const-formosa', number: '109', title: 'Publicidad de las sesiones legislativas', originalText: `Las sesiones de la Cámara serán públicas, salvo que la naturaleza de las cuestiones por tratarse aconsejen lo contrario, lo que deberá determinarse por mayoría de votos.`, currentText: `Las sesiones de la Cámara serán públicas, salvo que la naturaleza de las cuestiones por tratarse aconsejen lo contrario, lo que deberá determinarse por mayoría de votos.`, plainLanguageExplanation: 'Las sesiones de la Cámara son públicas por defecto. Solo pueden hacerse secretas cuando la naturaleza de los asuntos lo requiera, y debe decidirse por mayoría de votos.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['publicidad de las sesiones', 'transparencia legislativa', 'sesiones secretas'], order: 108, segments: [], amendments: [] },
  { id: 'const-formosa-art-110', lawId: 'const-formosa', number: '110', title: 'Quórum legislativo — mayoría absoluta', originalText: `La Cámara necesita, para sesionar, mayoría absoluta de sus miembros, pero en minoría podrá acordar las medidas que estime necesarias para compeler a los inasistentes, aplicar multas y suspensiones.`, currentText: `La Cámara necesita, para sesionar, mayoría absoluta de sus miembros, pero en minoría podrá acordar las medidas que estime necesarias para compeler a los inasistentes, aplicar multas y suspensiones.`, plainLanguageExplanation: 'Para sesionar válidamente se requiere mayoría absoluta de los miembros. Con minoría la Cámara solo puede tomar medidas para compeler la asistencia de los ausentes, incluyendo multas y suspensiones.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['quórum', 'mayoría absoluta', 'inasistencia legislativa', 'multas'], order: 109, segments: [], amendments: [] },
  { id: 'const-formosa-art-111', lawId: 'const-formosa', number: '111', title: 'Reglamento interno — corrección y exclusión de miembros', originalText: `La Cámara de Diputados hará su reglamento, que no podrá modificar sobre tablas en un mismo día. Podrá, con dos tercios de la votación de sus miembros, corregir y aún excluir de su seno a cualquiera de ellos, por desorden de conducta en el ejercicio de sus funciones o indignidad, y removerlos por inhabilidad física o moral, o sobreviniente a su incorporación, pero bastará la mayoría de uno sobre la mitad de los presentes para decidir acerca de la renuncia a su cargo.`, currentText: `La Cámara de Diputados hará su reglamento, que no podrá modificar sobre tablas en un mismo día. Podrá, con dos tercios de la votación de sus miembros, corregir y aún excluir de su seno a cualquiera de ellos, por desorden de conducta en el ejercicio de sus funciones o indignidad, y removerlos por inhabilidad física o moral, o sobreviniente a su incorporación, pero bastará la mayoría de uno sobre la mitad de los presentes para decidir acerca de la renuncia a su cargo.`, plainLanguageExplanation: 'La Cámara dicta su propio reglamento. Con dos tercios puede corregir o excluir a un miembro por conducta indecorosa o inhabilidad. Para aceptar renuncias basta mayoría simple de los presentes.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglamento interno', 'exclusión de diputados', 'disciplina legislativa', 'renuncia'], order: 110, segments: [], amendments: [] },
  { id: 'const-formosa-art-112', lawId: 'const-formosa', number: '112', title: 'Interpelación a Ministros del Poder Ejecutivo', originalText: `La Cámara, con la aprobación de un tercio de sus miembros presentes, puede llamar a su seno a los Ministros del Poder Ejecutivo para recibir las explicaciones e informes que crea convenientes, citándolos por lo menos con dos días de anticipación, salvo el caso de asunto grave, y comunicándoles al citarlos los puntos sobre los cuales han de informar.`, currentText: `La Cámara, con la aprobación de un tercio de sus miembros presentes, puede llamar a su seno a los Ministros del Poder Ejecutivo para recibir las explicaciones e informes que crea convenientes, citándolos por lo menos con dos días de anticipación, salvo el caso de asunto grave, y comunicándoles al citarlos los puntos sobre los cuales han de informar.`, plainLanguageExplanation: 'Con aprobación de un tercio de sus miembros, la Cámara puede citar a Ministros del Ejecutivo para recibir explicaciones o informes. La citación no puede diferirse más de 30 días.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['interpelación', 'ministros', 'control legislativo', 'Poder Ejecutivo'], order: 111, segments: [], amendments: [] },
  { id: 'const-formosa-art-113', lawId: 'const-formosa', number: '113', title: 'Comisiones investigadoras legislativas', originalText: `La Cámara tiene facultades para nombrar comisiones investigadoras, las que serán integradas por representantes de todos los bloques, en forma tal que esté reflejada la composición de la Cámara, invistiéndolas de los poderes necesarios para el ejercicio de sus funciones. Los miembros de estas comisiones tendrán la facultad de entrar en todos los establecimientos públicos, revisar cuentas y documentos oficiales, exigir informes e investigar el funcionamiento de las oficinas públicas, a cuyos efectos dispondrán del auxilio de la fuerza pública en caso necesario. Los diputados individualmente podrán solicitar informes con conocimiento de la Cámara.`, currentText: `La Cámara tiene facultades para nombrar comisiones investigadoras, las que serán integradas por representantes de todos los bloques, en forma tal que esté reflejada la composición de la Cámara, invistiéndolas de los poderes necesarios para el ejercicio de sus funciones. Los miembros de estas comisiones tendrán la facultad de entrar en todos los establecimientos públicos, revisar cuentas y documentos oficiales, exigir informes e investigar el funcionamiento de las oficinas públicas, a cuyos efectos dispondrán del auxilio de la fuerza pública en caso necesario. Los diputados individualmente podrán solicitar informes con conocimiento de la Cámara.`, plainLanguageExplanation: 'La Cámara puede crear comisiones investigadoras con representantes de todos los bloques. Estas comisiones tienen poder de citación y pueden requerir documentación a funcionarios, organismos y particulares.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['comisiones investigadoras', 'control legislativo', 'investigación parlamentaria'], order: 112, segments: [], amendments: [] },
  { id: 'const-formosa-art-114', lawId: 'const-formosa', number: '114', title: 'Inmunidad de opinión de los legisladores', originalText: `Ninguno de los miembros del Poder Legislativo podrá ser acusado, interrogado judicialmente ni molestado por las opiniones, discursos o votos que emita en el desempeño de su mandato de legislador. Ningún Diputado, desde el día de su proclamación hasta el cese de su mandato, puede ser arrestado; excepto en el caso de ser sorprendido "in fraganti" delito que merezca pena privativa de libertad, debiéndose dar cuenta del arresto a la Cámara con información sumaria del hecho, para que resuelva sobre su inmunidad personal.`, currentText: `Ninguno de los miembros del Poder Legislativo podrá ser acusado, interrogado judicialmente ni molestado por las opiniones, discursos o votos que emita en el desempeño de su mandato de legislador. Ningún Diputado, desde el día de su proclamación hasta el cese de su mandato, puede ser arrestado; excepto en el caso de ser sorprendido "in fraganti" delito que merezca pena privativa de libertad, debiéndose dar cuenta del arresto a la Cámara con información sumaria del hecho, para que resuelva sobre su inmunidad personal.`, plainLanguageExplanation: 'Los legisladores no pueden ser acusados, interrogados judicialmente ni molestados por las opiniones, discursos o votos que emitan en el ejercicio de su mandato.', practicalEffects: [], examples: ['Un diputado que critica duramente al Ejecutivo en el recinto no puede ser procesado judicialmente por esas expresiones.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inmunidad de opinión', 'fueros legislativos', 'libertad de expresión parlamentaria'], order: 113, segments: [], amendments: [] },
  { id: 'const-formosa-art-115', lawId: 'const-formosa', number: '115', title: 'Desafuero — suspensión de diputado para ser juzgado', originalText: `Cuando se deduzca acusación por delito de acción pública o privada contra cualquier Diputado, podrá la Cámara, examinando el mérito del sumario, suspender las inmunidades del acusado poniéndolo a disposición del juez competente, por dos tercios de votos de los presentes.`, currentText: `Cuando se deduzca acusación por delito de acción pública o privada contra cualquier Diputado, podrá la Cámara, examinando el mérito del sumario, suspender las inmunidades del acusado poniéndolo a disposición del juez competente, por dos tercios de votos de los presentes.`, plainLanguageExplanation: 'Cuando un diputado es acusado de un delito, la Cámara puede examinar el sumario y, con dos tercios de sus miembros, suspenderlo en sus funciones para que sea juzgado por los tribunales ordinarios.', practicalEffects: [], examples: ['Si un diputado es imputado por corrupción, la Cámara puede votar el desafuero y así habilitarlo a ser procesado como cualquier ciudadano.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['desafuero', 'inmunidad procesal', 'suspensión de diputado', 'proceso penal'], order: 114, segments: [], amendments: [] },
  { id: 'const-formosa-art-116', lawId: 'const-formosa', number: '116', title: 'Poder disciplinario sobre personas ajenas a la Cámara', originalText: `La Cámara podrá corregir disciplinariamente a toda persona de fuera de su seno que viole sus prerrogativas o privilegios, pidiendo su enjuiciamiento ante los tribunales ordinarios y poniendo inmediatamente a su disposición a la persona que hubiere sido detenida.`, currentText: `La Cámara podrá corregir disciplinariamente a toda persona de fuera de su seno que viole sus prerrogativas o privilegios, pidiendo su enjuiciamiento ante los tribunales ordinarios y poniendo inmediatamente a su disposición a la persona que hubiere sido detenida.`, plainLanguageExplanation: 'La Cámara puede aplicar correcciones disciplinarias a personas ajenas que violen sus prerrogativas o privilegios, pudiendo incluso pedir su enjuiciamiento ante los tribunales ordinarios.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['privilegios parlamentarios', 'disciplina', 'prerrogativas legislativas'], order: 115, segments: [], amendments: [] },
  { id: 'const-formosa-art-117', lawId: 'const-formosa', number: '117', title: 'Incompatibilidades del cargo de diputado', originalText: `Es incompatible el cargo de diputado con cualquier otro de carácter nacional, provincial o municipal, salvo el de la docencia superior. Es también incompatible el cargo de diputado con otro de carácter electivo nacional, municipal o de otras provincias, como asimismo participar en empresas beneficiadas por privilegios o concesiones del Estado. El Diputado que haya aceptado algún cargo incompatible con el suyo, quedará por ese solo hecho, separado de la representación. Las comisiones de carácter transitorio del gobierno nacional, provincial o de las municipalidades, sólo podrán ser aceptadas cuando fueren honorarias y previo acuerdo de la Cámara. En caso de muerte, renuncia, destitución o inhabilidad declarada de un Diputado, su reemplazo se hará conforme con el régimen electoral.`, currentText: `Es incompatible el cargo de diputado con cualquier otro de carácter nacional, provincial o municipal, salvo el de la docencia superior. Es también incompatible el cargo de diputado con otro de carácter electivo nacional, municipal o de otras provincias, como asimismo participar en empresas beneficiadas por privilegios o concesiones del Estado. El Diputado que haya aceptado algún cargo incompatible con el suyo, quedará por ese solo hecho, separado de la representación. Las comisiones de carácter transitorio del gobierno nacional, provincial o de las municipalidades, sólo podrán ser aceptadas cuando fueren honorarias y previo acuerdo de la Cámara. En caso de muerte, renuncia, destitución o inhabilidad declarada de un Diputado, su reemplazo se hará conforme con el régimen electoral.`, plainLanguageExplanation: 'Ser diputado es incompatible con cualquier cargo público nacional, provincial o municipal (salvo docencia superior) y con contratos con el Estado. Tampoco puede ejercerse concurrentemente con cargos de los otros poderes.', practicalEffects: [], examples: ['Un diputado que asume como subsecretario del Ejecutivo debe renunciar a su banca.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['incompatibilidades', 'diputado', 'doble cargo', 'contratos con el Estado'], order: 116, segments: [], amendments: [] },
  { id: 'const-formosa-art-118', lawId: 'const-formosa', number: '118', title: 'Juramento de los diputados al asumir', originalText: `Los diputados al asumir el cargo, deberán prestar juramento de desempeñarlo fielmente, con arreglo a los preceptos de esta Constitución y de la Constitución Nacional, y por la fórmula que establecerá la misma Cámara.`, currentText: `Los diputados al asumir el cargo, deberán prestar juramento de desempeñarlo fielmente, con arreglo a los preceptos de esta Constitución y de la Constitución Nacional, y por la fórmula que establecerá la misma Cámara.`, plainLanguageExplanation: 'Al asumir, los diputados deben prestar juramento de ejercer fielmente su cargo respetando la Constitución Nacional y la Provincial.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juramento', 'asunción', 'diputado', 'Constitución'], order: 117, segments: [], amendments: [] },
  { id: 'const-formosa-art-119', lawId: 'const-formosa', number: '119', title: 'Remuneración de los diputados', originalText: `Los diputados gozarán de una remuneración determinada por la Cámara y no podrá ser aumentada sino por sanción de dos tercios de la totalidad de sus miembros, y entrará en vigencia después de dos años de haber sido promulgada. CAPITULO SEGUNDO.- Atribuciones`, currentText: `Los diputados gozarán de una remuneración determinada por la Cámara y no podrá ser aumentada sino por sanción de dos tercios de la totalidad de sus miembros, y entrará en vigencia después de dos años de haber sido promulgada. CAPITULO SEGUNDO.- Atribuciones`, plainLanguageExplanation: 'Los diputados reciben una remuneración fijada por la Cámara. Para aumentarla se requiere aprobación de dos tercios de la totalidad de sus miembros.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remuneración', 'diputados', 'salario legislativo'], order: 118, segments: [], amendments: [] },
  { id: 'const-formosa-art-120', lawId: 'const-formosa', number: '120', title: 'Atribuciones del Poder Legislativo', originalText: `Corresponde al Poder Legislativo las siguientes atribuciones: 1) Aprobar o rechazar acuerdos, convenios o tratados con la Nación, las demás Provincias o Estados Extranjeros. Por dos tercios de votos de la totalidad de sus miembros podrá aprobar tratados de integración regional con otras Provincias que atribuyan competencia y jurisdicción a órganos administrativos regionales, en condiciones de reciprocidad e igualdad, conforme a los principios de la Constitución Nacional. Las normas dictadas en su consecuencia tendrán jerarquía superior a las leyes. 2) Prestar, en período de sesiones ordinarias, acuerdos para los nombramientos que esta Constitución exija, entendiéndose prestado el acuerdo si dentro de los treinta días de recibida la comunicación, la Cámara no se hubiese expedido. 3) Establecer las bases, tipos y modalidades de recaudación de los tributos de toda clase. Su monto se fijará equitativa, proporcional y progresivamente, de acuerdo con la finalidad perseguida o con el valor de los bienes o de sus rentas. 4) Solicitar al Poder Ejecutivo un informe sobre las operaciones de créditos celebradas. 5) Preparar su presupuesto anual para el ejercicio siguiente, adecuado a las pautas contenidas en el presupuesto general y remitirlo al Poder Ejecutivo sesenta días antes de la finalización del período de sesiones ordinarias. 6) Fijar anualmente el Presupuesto General de Gastos y Cálculo de Recursos de la Administración, incluyendo en él todos los servicios ordinarios, aun cuando hayan sido autorizados por leyes especiales, como los extraordinarios, las que no serán cumplidas mientras no se hubieren consignado en el presupuesto las partidas correspondientes para su ejecución. 7) Sancionado un presupuesto, seguirá en vigencia en sus partidas ordinarias hasta la sanción de otro; la Cámara, al dictar esta ley, no podrá aumentar los sueldos ni gastos parciales proyectados por el Poder Ejecutivo. 8) Aprobar o rechazar, en sesiones ordinarias, las cuentas de inversión, que el Poder Ejecutivo remitirá dentro de los primeros sesenta días de las mismas. 9) Conceder amnistías por delitos políticos. 10) Otorgar subsidios a las municipalidades y comisiones de fomento, cuyas rentas no alcancen a cubrir sus gastos ordinarios. Acordar participación a las municipalidades o comisiones de fomento en la coparticipación federal que perciba la Provincia por tal concepto, de conformidad con la ley que se dicte al respecto. 11) Dictar la Ley Orgánica Municipal y disponer la creación de villas y ciudades. 12) Tomar juramento al Gobernador y al Vicegobernador. 13) Resolver sobre la licencia del Gobernador y del Vicegobernador para salir fuera de la Provincia, cuando sus ausencias abarquen períodos mayores a quince días o a cinco días si fueran simultáneas. 14) Determinar el personal y dotación de la Cámara. 15) Crear y suprimir empleos no establecidos en esta Constitución. 16) Legislar sobre el uso y enajenación de la tierra pública y demás bienes de la Provincia; declarar los casos de utilidad pública para la expropiación. 17) Dictar la ley general de Colonización y las demás leyes necesarias que establezcan las bases y políticas que deberá seguir la Administración para promover el fomento y diversificación de la producción, de los medios de transporte y canales navegables, estimular las organizaciones mutualistas, cooperativas y de cualquier otra forma que se asienten en el principio de la solidaridad social, promover la mejor distribución de la riqueza, la igualdad de posibilidades y el acceso a la propiedad productiva, alentar el ahorro popular y las viviendas económicas; la concesión de los servicios públicos provinciales, manteniendo el principio de la titularidad estatal del servicio, su regulación y control; facilitar la introducción y establecimiento de nuevas industrias, importación de capitales y explotación de sus ríos, conforme con el artículo 38. 18) Dictar la Ley Integral de Educación y el Estatuto Docente, de acuerdo con los principios establecidos en esta Constitución. 19) Dictar el Estatuto General del Empleado Público Provincial, conforme con los principios establecidos en esta Constitución. 20) Autorizar la cesión gratuita de tierras de la Provincia para objeto de utilidad pública nacional, provincial o municipal, con dos tercios de votos; y con unanimidad de votos de la totalidad de la Cámara cuando dicha cesión importe desmembramiento del territorio o abandono de jurisdicción dentro de los límites prescriptos por la Constitución Nacional. 21) Crear el Banco Oficial de la Provincia; aprobar las modificaciones de su Carta Orgánica y autorizar el establecimiento de otras instituciones de crédito. 22) Declarar la necesidad de reforma de esta Constitución, en la forma que en la misma se determina. 23) Dictar leyes de imprenta, que de ninguna manera signifiquen restricciones a la liberad de expresión; de procedimientos judiciales, penitenciarios, de responsabilidad de los funcionarios públicos, de policía, de materia rural o industrial, de procedimiento administrativo y contencioso administrativo; códigos: de aguas, bromatológico y de alimentos; ley de hidrocarburos, reglamentación de las profesiones liberales y de los colegios profesionales; de represión del juego; de elecciones, de jubilaciones y pensiones por servicios prestados a la Provincia, y todas las que sean necesarias para hacer efectivas las disposiciones y principios de esta Constitución. 24) Convocar a elecciones provinciales si el Poder Ejecutivo no lo hiciere con la anticipación determinada por la ley. 25) Aceptar o rechazar la renuncia del Gobernador y del Vicegobernador y, por dos tercios de la totalidad de sus miembros, declarar los casos de imposibilidad física o mental de los mismos. 26) Dictar la ley de creación del Registro del Estado Civil de las Personas y la Ley Orgánica de la Justicia. 27) Dictar el Estatuto de los Partidos Políticos, sin perjuicio del derecho de asociación y propaganda. 28) Determinar la división política de la Provincia, fijando el número de Departamentos, de acuerdo con las siguientes bases: población, accidentes naturales, vías de comunicación y extensión. 29) Participar en las licitaciones públicas con dos representantes de la Legislatura Provincial; uno por la mayoría o primera minoría, y otro por la minoría siguiente, tanto en la etapa de preadjudicación como en el control de la ejecución; así como organizar el control de gestión y seguimiento de los diversos actos, contratos y obras en ejecución a través de las comisiones legislativas, las que serán integradas por representantes de todos los bloques, en forma tal que refleje la composición de la Cámara. 30) Otorgar acuerdo legislativo para las designaciones o nombramientos expresamente establecidos en esta Constitución. 31) Invitar a los diputados y senadores nacionales para informar una vez por año y antes de que finalice el período de sesiones ordinarias, sobre su actuación legislativa como representantes del pueblo y del Estado Provincial. 32) Crear el Consejo de la Magistratura determinando su composición, el que tendrá a su cargo formular la propuesta de jueces y funcionarios del Poder Judicial, cuya designación deba efectuar la Legislatura.`, currentText: `Corresponde al Poder Legislativo las siguientes atribuciones: 1) Aprobar o rechazar acuerdos, convenios o tratados con la Nación, las demás Provincias o Estados Extranjeros. Por dos tercios de votos de la totalidad de sus miembros podrá aprobar tratados de integración regional con otras Provincias que atribuyan competencia y jurisdicción a órganos administrativos regionales, en condiciones de reciprocidad e igualdad, conforme a los principios de la Constitución Nacional. Las normas dictadas en su consecuencia tendrán jerarquía superior a las leyes. 2) Prestar, en período de sesiones ordinarias, acuerdos para los nombramientos que esta Constitución exija, entendiéndose prestado el acuerdo si dentro de los treinta días de recibida la comunicación, la Cámara no se hubiese expedido. 3) Establecer las bases, tipos y modalidades de recaudación de los tributos de toda clase. Su monto se fijará equitativa, proporcional y progresivamente, de acuerdo con la finalidad perseguida o con el valor de los bienes o de sus rentas. 4) Solicitar al Poder Ejecutivo un informe sobre las operaciones de créditos celebradas. 5) Preparar su presupuesto anual para el ejercicio siguiente, adecuado a las pautas contenidas en el presupuesto general y remitirlo al Poder Ejecutivo sesenta días antes de la finalización del período de sesiones ordinarias. 6) Fijar anualmente el Presupuesto General de Gastos y Cálculo de Recursos de la Administración, incluyendo en él todos los servicios ordinarios, aun cuando hayan sido autorizados por leyes especiales, como los extraordinarios, las que no serán cumplidas mientras no se hubieren consignado en el presupuesto las partidas correspondientes para su ejecución. 7) Sancionado un presupuesto, seguirá en vigencia en sus partidas ordinarias hasta la sanción de otro; la Cámara, al dictar esta ley, no podrá aumentar los sueldos ni gastos parciales proyectados por el Poder Ejecutivo. 8) Aprobar o rechazar, en sesiones ordinarias, las cuentas de inversión, que el Poder Ejecutivo remitirá dentro de los primeros sesenta días de las mismas. 9) Conceder amnistías por delitos políticos. 10) Otorgar subsidios a las municipalidades y comisiones de fomento, cuyas rentas no alcancen a cubrir sus gastos ordinarios. Acordar participación a las municipalidades o comisiones de fomento en la coparticipación federal que perciba la Provincia por tal concepto, de conformidad con la ley que se dicte al respecto. 11) Dictar la Ley Orgánica Municipal y disponer la creación de villas y ciudades. 12) Tomar juramento al Gobernador y al Vicegobernador. 13) Resolver sobre la licencia del Gobernador y del Vicegobernador para salir fuera de la Provincia, cuando sus ausencias abarquen períodos mayores a quince días o a cinco días si fueran simultáneas. 14) Determinar el personal y dotación de la Cámara. 15) Crear y suprimir empleos no establecidos en esta Constitución. 16) Legislar sobre el uso y enajenación de la tierra pública y demás bienes de la Provincia; declarar los casos de utilidad pública para la expropiación. 17) Dictar la ley general de Colonización y las demás leyes necesarias que establezcan las bases y políticas que deberá seguir la Administración para promover el fomento y diversificación de la producción, de los medios de transporte y canales navegables, estimular las organizaciones mutualistas, cooperativas y de cualquier otra forma que se asienten en el principio de la solidaridad social, promover la mejor distribución de la riqueza, la igualdad de posibilidades y el acceso a la propiedad productiva, alentar el ahorro popular y las viviendas económicas; la concesión de los servicios públicos provinciales, manteniendo el principio de la titularidad estatal del servicio, su regulación y control; facilitar la introducción y establecimiento de nuevas industrias, importación de capitales y explotación de sus ríos, conforme con el artículo 38. 18) Dictar la Ley Integral de Educación y el Estatuto Docente, de acuerdo con los principios establecidos en esta Constitución. 19) Dictar el Estatuto General del Empleado Público Provincial, conforme con los principios establecidos en esta Constitución. 20) Autorizar la cesión gratuita de tierras de la Provincia para objeto de utilidad pública nacional, provincial o municipal, con dos tercios de votos; y con unanimidad de votos de la totalidad de la Cámara cuando dicha cesión importe desmembramiento del territorio o abandono de jurisdicción dentro de los límites prescriptos por la Constitución Nacional. 21) Crear el Banco Oficial de la Provincia; aprobar las modificaciones de su Carta Orgánica y autorizar el establecimiento de otras instituciones de crédito. 22) Declarar la necesidad de reforma de esta Constitución, en la forma que en la misma se determina. 23) Dictar leyes de imprenta, que de ninguna manera signifiquen restricciones a la liberad de expresión; de procedimientos judiciales, penitenciarios, de responsabilidad de los funcionarios públicos, de policía, de materia rural o industrial, de procedimiento administrativo y contencioso administrativo; códigos: de aguas, bromatológico y de alimentos; ley de hidrocarburos, reglamentación de las profesiones liberales y de los colegios profesionales; de represión del juego; de elecciones, de jubilaciones y pensiones por servicios prestados a la Provincia, y todas las que sean necesarias para hacer efectivas las disposiciones y principios de esta Constitución. 24) Convocar a elecciones provinciales si el Poder Ejecutivo no lo hiciere con la anticipación determinada por la ley. 25) Aceptar o rechazar la renuncia del Gobernador y del Vicegobernador y, por dos tercios de la totalidad de sus miembros, declarar los casos de imposibilidad física o mental de los mismos. 26) Dictar la ley de creación del Registro del Estado Civil de las Personas y la Ley Orgánica de la Justicia. 27) Dictar el Estatuto de los Partidos Políticos, sin perjuicio del derecho de asociación y propaganda. 28) Determinar la división política de la Provincia, fijando el número de Departamentos, de acuerdo con las siguientes bases: población, accidentes naturales, vías de comunicación y extensión. 29) Participar en las licitaciones públicas con dos representantes de la Legislatura Provincial; uno por la mayoría o primera minoría, y otro por la minoría siguiente, tanto en la etapa de preadjudicación como en el control de la ejecución; así como organizar el control de gestión y seguimiento de los diversos actos, contratos y obras en ejecución a través de las comisiones legislativas, las que serán integradas por representantes de todos los bloques, en forma tal que refleje la composición de la Cámara. 30) Otorgar acuerdo legislativo para las designaciones o nombramientos expresamente establecidos en esta Constitución. 31) Invitar a los diputados y senadores nacionales para informar una vez por año y antes de que finalice el período de sesiones ordinarias, sobre su actuación legislativa como representantes del pueblo y del Estado Provincial. 32) Crear el Consejo de la Magistratura determinando su composición, el que tendrá a su cargo formular la propuesta de jueces y funcionarios del Poder Judicial, cuya designación deba efectuar la Legislatura.`, plainLanguageExplanation: 'Enumera las principales atribuciones del Poder Legislativo: aprobar convenios con la Nación y otras provincias, legislar en materia impositiva, aprobar el presupuesto, autorizar empréstitos y controlar al Ejecutivo.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['atribuciones legislativas', 'presupuesto', 'impuestos', 'convenios interprovinciales'], order: 119, segments: [], amendments: [] },
  { id: 'const-formosa-art-121', lawId: 'const-formosa', number: '121', title: 'Materias reglamentarias — límites al Ejecutivo', originalText: `Tendrán carácter reglamentario todas las materias distintas de las pertenecientes al ámbito de la ley, enumerados en el artículo anterior. Se prohíbe la delegación legislativa en el Poder Ejecutivo, salvo en materias determinadas de administración o de emergencia pública, con plazo fijado para su ejercicio y dentro de las bases de la delegación que la Legislatura establezca. La caducidad resultante del plazo previsto en el párrafo anterior no importará revisión de las relaciones jurídicas nacidas al amparo de las normas dictadas en consecuencia de la delegación legislativa. CAPITULO TERCERO.- Formación y Sanción de las Leyes`, currentText: `Tendrán carácter reglamentario todas las materias distintas de las pertenecientes al ámbito de la ley, enumerados en el artículo anterior. Se prohíbe la delegación legislativa en el Poder Ejecutivo, salvo en materias determinadas de administración o de emergencia pública, con plazo fijado para su ejercicio y dentro de las bases de la delegación que la Legislatura establezca. La caducidad resultante del plazo previsto en el párrafo anterior no importará revisión de las relaciones jurídicas nacidas al amparo de las normas dictadas en consecuencia de la delegación legislativa. CAPITULO TERCERO.- Formación y Sanción de las Leyes`, plainLanguageExplanation: 'Las materias que no están en el ámbito de la ley son de carácter reglamentario. Se prohíbe delegar en el Ejecutivo las atribuciones exclusivas del Legislativo salvo en situaciones de emergencia expresamente autorizadas.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['decretos reglamentarios', 'delegación legislativa', 'emergencia', 'atribuciones exclusivas'], order: 120, segments: [], amendments: [] },
  { id: 'const-formosa-art-122', lawId: 'const-formosa', number: '122', title: 'Iniciativa legislativa — origen de los proyectos de ley', originalText: `Las leyes tendrán origen en proyectos presentados por uno o más diputados, por el Poder Ejecutivo o por el Superior Tribunal de Justicia, conforme con lo que establece el capítulo Poder Judicial sobre co-legislación de dicho poder.`, currentText: `Las leyes tendrán origen en proyectos presentados por uno o más diputados, por el Poder Ejecutivo o por el Superior Tribunal de Justicia, conforme con lo que establece el capítulo Poder Judicial sobre co-legislación de dicho poder.`, plainLanguageExplanation: 'Los proyectos de ley pueden ser presentados por diputados, por el Poder Ejecutivo o por iniciativa popular. Ciertas materias (presupuesto, impuestos) son de iniciativa exclusiva del Ejecutivo.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['iniciativa legislativa', 'proyectos de ley', 'iniciativa popular', 'Poder Ejecutivo'], order: 121, segments: [], amendments: [] },
  { id: 'const-formosa-art-123', lawId: 'const-formosa', number: '123', title: 'Promulgación y publicación de las leyes', originalText: `Aprobado un proyecto por la Cámara de Diputados, pasará al Poder Ejecutivo para su promulgación y publicación, si estuviera éste conforme.`, currentText: `Aprobado un proyecto por la Cámara de Diputados, pasará al Poder Ejecutivo para su promulgación y publicación, si estuviera éste conforme.`, plainLanguageExplanation: 'Una vez aprobado el proyecto por la Cámara, pasa al Ejecutivo para su promulgación y publicación. El Ejecutivo tiene un plazo para pronunciarse; si no lo hace en tiempo, se considera promulgado.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['promulgación', 'publicación', 'ley', 'Poder Ejecutivo'], order: 122, segments: [], amendments: [] },
  { id: 'const-formosa-art-124', lawId: 'const-formosa', number: '124', title: 'Promulgación tácita por silencio del Ejecutivo', originalText: `Quedará convertido en ley todo proyecto sancionado por la Legislatura si remitido al Poder Ejecutivo, éste no lo devolviere observado dentro del término de diez días hábiles de su recepción.`, currentText: `Quedará convertido en ley todo proyecto sancionado por la Legislatura si remitido al Poder Ejecutivo, éste no lo devolviere observado dentro del término de diez días hábiles de su recepción.`, plainLanguageExplanation: 'Si el Ejecutivo no promulga ni veta un proyecto dentro del plazo constitucional, el proyecto queda promulgado automáticamente por el transcurso del tiempo (promulgación tácita).', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['promulgación tácita', 'veto', 'plazo constitucional', 'silencio del Ejecutivo'], order: 123, segments: [], amendments: [] },
  { id: 'const-formosa-art-125', lawId: 'const-formosa', number: '125', title: 'Veto del Ejecutivo — insistencia legislativa', originalText: `Rechazado por el Poder Ejecutivo, en todo o en parte, un proyecto de ley, volverá con sus objeciones a la Cámara, y si ésta insiste en su sanción, con dos tercios de votos de los presentes, será ley y pasará al Poder Ejecutivo para su promulgación. No existiendo los dos tercios para la insistencia, ni mayoría para aceptar las modificaciones propuestas por el Poder Ejecutivo, no podrá repetirse en las sesiones de ese año. Sin embargo las partes no observadas podrán ser promulgadas si tienen autonomía normativa y su aprobación parcial no altera el espíritu ni la unidad del proyecto sancionado por la Legislatura.`, currentText: `Rechazado por el Poder Ejecutivo, en todo o en parte, un proyecto de ley, volverá con sus objeciones a la Cámara, y si ésta insiste en su sanción, con dos tercios de votos de los presentes, será ley y pasará al Poder Ejecutivo para su promulgación. No existiendo los dos tercios para la insistencia, ni mayoría para aceptar las modificaciones propuestas por el Poder Ejecutivo, no podrá repetirse en las sesiones de ese año. Sin embargo las partes no observadas podrán ser promulgadas si tienen autonomía normativa y su aprobación parcial no altera el espíritu ni la unidad del proyecto sancionado por la Legislatura.`, plainLanguageExplanation: 'Si el Ejecutivo veta una ley, vuelve a la Cámara con las objeciones. Si la Cámara insiste con dos tercios de sus miembros, la ley queda promulgada. Si no alcanza ese quórum, el proyecto no puede volver a tratarse en ese año.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['veto', 'insistencia legislativa', 'promulgación', 'dos tercios'], order: 124, segments: [], amendments: [] },
  { id: 'const-formosa-art-126', lawId: 'const-formosa', number: '126', title: 'Fórmula de sanción de las leyes provinciales', originalText: `En la sanción de las leyes se usará esta fórmula: "La Legislatura de la Provincia sanciona con fuerza de ley". CAPITULO UNICO.- Reforma Constitucional`, currentText: `En la sanción de las leyes se usará esta fórmula: "La Legislatura de la Provincia sanciona con fuerza de ley". CAPITULO UNICO.- Reforma Constitucional`, plainLanguageExplanation: 'Toda ley provincial debe sancionarse con la fórmula: «La Legislatura de la Provincia sanciona con fuerza de ley».', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fórmula de sanción', 'ley provincial', 'Legislatura'], order: 125, segments: [], amendments: [] },
  { id: 'const-formosa-art-127', lawId: 'const-formosa', number: '127', title: 'Reforma constitucional — declaración de necesidad', originalText: `Esta Constitución no podrá reformarse parcial ni totalmente, sino en virtud de ley especial sancionada con acuerdo de las dos terceras partes de la totalidad de los miembros de la Legislatura, y con especificación de los artículos que hayan de reformarse. En este caso, la reforma no podrá producirse sino respecto de los artículos expresamente designados en dicha ley. La ley que declara la necesidad de la reforma constitucional, así como la que enmienda algún artículo del presente texto constitucional, en todos los casos debe contar con despacho de comisión, sin que pueda ser objeto de tratamiento de sobre-tablas.`, currentText: `Esta Constitución no podrá reformarse parcial ni totalmente, sino en virtud de ley especial sancionada con acuerdo de las dos terceras partes de la totalidad de los miembros de la Legislatura, y con especificación de los artículos que hayan de reformarse. En este caso, la reforma no podrá producirse sino respecto de los artículos expresamente designados en dicha ley. La ley que declara la necesidad de la reforma constitucional, así como la que enmienda algún artículo del presente texto constitucional, en todos los casos debe contar con despacho de comisión, sin que pueda ser objeto de tratamiento de sobre-tablas.`, plainLanguageExplanation: 'La Constitución solo puede reformarse mediante una ley especial sancionada con mayoría calificada que declare la necesidad de reforma. Sin esa declaración, ninguna convención puede modificarla.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reforma constitucional', 'declaración de necesidad', 'convención constituyente', 'mayoría calificada'], order: 126, segments: [], amendments: [] },
  { id: 'const-formosa-art-128', lawId: 'const-formosa', number: '128', title: 'Convención Constituyente — composición y límites', originalText: `Sancionada la necesidad de la reforma, ésta se hará por una Convención Constituyente compuesta de diputados elegidos directamente por el pueblo. Dicha Convención se compondrá de un número de diputados igual al de los miembros de la Cámara de Representantes, exigiéndose para ser convencional las mismas condiciones que para ser representante. A todos los efectos, los diputados convencionales constituyentes quedarán equiparados a los diputados provinciales.`, currentText: `Sancionada la necesidad de la reforma, ésta se hará por una Convención Constituyente compuesta de diputados elegidos directamente por el pueblo. Dicha Convención se compondrá de un número de diputados igual al de los miembros de la Cámara de Representantes, exigiéndose para ser convencional las mismas condiciones que para ser representante. A todos los efectos, los diputados convencionales constituyentes quedarán equiparados a los diputados provinciales.`, plainLanguageExplanation: 'Declarada la necesidad de reforma, se convoca a una Convención Constituyente compuesta por tantos diputados como la Legislatura, elegidos directamente. La Convención solo puede reformar los puntos declarados necesarios.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Convención Constituyente', 'reforma constitucional', 'elección constituyentes'], order: 127, segments: [], amendments: [] },
  { id: 'const-formosa-art-129', lawId: 'const-formosa', number: '129', title: 'Enmienda constitucional — procedimiento legislativo especial', originalText: `La enmienda o reforma de un artículo y sus concordantes puede ser sancionada por el voto de los cuatro quintos de los miembros de la Legislatura; y quedará incorporada al texto constitucional si es ratificada por el voto afirmativo de la mayoría del pueblo, que será convocado en oportunidad de la primera elección provincial que se realice. Para que el resultado del referéndum se considere válido, se requiere que los votos emitidos superen el cincuenta por ciento de los electores inscriptos en el padrón electoral de la Provincia. Enmiendas de esta naturaleza no puede llevarse a cabo, sino con intervalo de dos años. Esta reforma no es de aplicación a las prescripciones, de la Primera Parte- Capítulo Primero, al presente capítulo y al instituto de la reelección que establece esta Constitución. TERCERA PARTE.- Poder Ejecutivo CAPITULO PRIMERO.- Naturaleza y Duración`, currentText: `La enmienda o reforma de un artículo y sus concordantes puede ser sancionada por el voto de los cuatro quintos de los miembros de la Legislatura; y quedará incorporada al texto constitucional si es ratificada por el voto afirmativo de la mayoría del pueblo, que será convocado en oportunidad de la primera elección provincial que se realice. Para que el resultado del referéndum se considere válido, se requiere que los votos emitidos superen el cincuenta por ciento de los electores inscriptos en el padrón electoral de la Provincia. Enmiendas de esta naturaleza no puede llevarse a cabo, sino con intervalo de dos años. Esta reforma no es de aplicación a las prescripciones, de la Primera Parte- Capítulo Primero, al presente capítulo y al instituto de la reelección que establece esta Constitución. TERCERA PARTE.- Poder Ejecutivo CAPITULO PRIMERO.- Naturaleza y Duración`, plainLanguageExplanation: 'Un artículo y sus concordantes puede reformarse por voto de las cuatro quintas partes de los miembros de la Legislatura, sin necesidad de convención. En ese caso se somete a referéndum para su ratificación.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['enmienda constitucional', 'cuatro quintas partes', 'referéndum', 'reforma parcial'], order: 128, segments: [], amendments: [] },
  { id: 'const-formosa-art-130', lawId: 'const-formosa', number: '130', title: 'Poder Ejecutivo — Gobernador y Vicegobernador', originalText: `El Poder Ejecutivo será desempeñado por un ciudadano con el título de Gobernador de la Provincia y, en su defecto, por un Vicegobernador elegido al mismo tiempo, en la misma forma y por igual período que el Gobernador.`, currentText: `El Poder Ejecutivo será desempeñado por un ciudadano con el título de Gobernador de la Provincia y, en su defecto, por un Vicegobernador elegido al mismo tiempo, en la misma forma y por igual período que el Gobernador.`, plainLanguageExplanation: 'El Poder Ejecutivo es unipersonal y está a cargo del Gobernador de la Provincia. En caso de ausencia, enfermedad o muerte, lo reemplaza el Vicegobernador.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Poder Ejecutivo', 'Gobernador', 'Vicegobernador', 'reemplazo'], order: 129, segments: [], amendments: [] },
  { id: 'const-formosa-art-131', lawId: 'const-formosa', number: '131', title: 'Requisitos para ser Gobernador y Vicegobernador', originalText: `Para ser elegido Gobernador y Vicegobernador se requiere: 1) Ser argentino, nativo, por opción o naturalizado con quince años en el ejercicio efectivo de la ciudadanía. 2) Haber cumplido treinta años de edad y ocho de residencia previa, real y efectiva en la Provincia, cuando no se hubiere nacido en ella.`, currentText: `Para ser elegido Gobernador y Vicegobernador se requiere: 1) Ser argentino, nativo, por opción o naturalizado con quince años en el ejercicio efectivo de la ciudadanía. 2) Haber cumplido treinta años de edad y ocho de residencia previa, real y efectiva en la Provincia, cuando no se hubiere nacido en ella.`, plainLanguageExplanation: 'Para ser Gobernador o Vicegobernador se requiere ser argentino nativo o naturalizado, tener 30 años de edad, ser formoseño o con residencia de 5 años en la Provincia.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Gobernador', 'requisitos', 'ciudadanía', 'residencia', 'edad mínima'], order: 130, segments: [], amendments: [] },
  { id: 'const-formosa-art-132', lawId: 'const-formosa', number: '132', title: 'Duración del mandato del Gobernador — reelección', originalText: `El Gobernador y el Vicegobernador durarán cuatro años en el ejercicio de sus cargos, y podrán ser reelectos.`, currentText: `El Gobernador y el Vicegobernador durarán cuatro años en el ejercicio de sus cargos, y podrán ser reelectos.`, plainLanguageExplanation: 'El Gobernador y Vicegobernador duran 4 años en sus cargos y pueden ser reelectos.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Gobernador', 'mandato', 'reelección', 'cuatro años'], order: 131, segments: [], amendments: [] },
  { id: 'const-formosa-art-133', lawId: 'const-formosa', number: '133', title: 'Período de gobierno improrrogable', originalText: `El período indicado en el artículo anterior no podrá prorrogarse. En caso de interrupción solo podrá completarse dentro del plazo de su propio mandato.`, currentText: `El período indicado en el artículo anterior no podrá prorrogarse. En caso de interrupción solo podrá completarse dentro del plazo de su propio mandato.`, plainLanguageExplanation: 'El período de gobierno de 4 años no puede prorrogarse. Si se interrumpe por causas extraordinarias, solo puede completarse dentro del plazo original sin contar ese tiempo incompleto como período a los efectos de la reelección.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['período de gobierno', 'prórroga', 'interrupción', 'Gobernador'], order: 132, segments: [], amendments: [] },
  { id: 'const-formosa-art-134', lawId: 'const-formosa', number: '134', title: 'Vicegobernador — Presidente Nato y reemplazo del Gobernador', originalText: `El Vicegobernador es el Presidente Nato de la Legislatura, y reemplaza al Gobernador por el resto del período legal en caso de muerte, destitución o renuncia, o hasta que haya cesado la inhabilidad en caso de imposibilidad física o mental, suspensión o ausencia.`, currentText: `El Vicegobernador es el Presidente Nato de la Legislatura, y reemplaza al Gobernador por el resto del período legal en caso de muerte, destitución o renuncia, o hasta que haya cesado la inhabilidad en caso de imposibilidad física o mental, suspensión o ausencia.`, plainLanguageExplanation: 'El Vicegobernador preside la Legislatura como Presidente Nato y reemplaza al Gobernador en caso de muerte, destitución, renuncia o inhabilidad, por el resto del período.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Vicegobernador', 'Presidente Nato', 'reemplazo', 'Gobernador'], order: 133, segments: [], amendments: [] },
  { id: 'const-formosa-art-135', lawId: 'const-formosa', number: '135', title: 'Acefalía — reemplazo ante vacante del Vicegobernador', originalText: `En caso de muerte, renuncia, destitución o inhabilidad permanente o declarada del Vicegobernador, las funciones del Poder Ejecutivo serán desempeñadas por el Presidente de la Legislatura hasta tanto se proceda a nueva elección para completar el período legal, no pudiendo esta elección recaer en dicho funcionario. No se procederá a nueva elección cuando el tiempo que falte para completar el período gubernativo no exceda de un año. En caso de suspensión, imposibilidad física o ausencia del Vicegobernador, éste será igualmente sustituido por el Presidente de la Legislatura mientras dure el impedimento.`, currentText: `En caso de muerte, renuncia, destitución o inhabilidad permanente o declarada del Vicegobernador, las funciones del Poder Ejecutivo serán desempeñadas por el Presidente de la Legislatura hasta tanto se proceda a nueva elección para completar el período legal, no pudiendo esta elección recaer en dicho funcionario. No se procederá a nueva elección cuando el tiempo que falte para completar el período gubernativo no exceda de un año. En caso de suspensión, imposibilidad física o ausencia del Vicegobernador, éste será igualmente sustituido por el Presidente de la Legislatura mientras dure el impedimento.`, plainLanguageExplanation: 'Si el Vicegobernador también queda vacante, el Poder Ejecutivo es ejercido por el presidente de la Cámara de Diputados hasta que la Legislatura designe o se elija un nuevo Gobernador.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acefalía', 'vacante', 'Vicegobernador', 'presidente de la Cámara'], order: 134, segments: [], amendments: [] },
  { id: 'const-formosa-art-136', lawId: 'const-formosa', number: '136', title: 'Residencia del Gobernador — autorización para ausentarse', originalText: `El Gobernador y el Vicegobernador en desempeño del Poder Ejecutivo residirán en la capital de la Provincia, y sólo podrán salir de ella en el ejercicio de sus funciones, y dentro del territorio de la Provincia por un término que, en cada caso, no exceda de treinta días. En ningún caso podrán ausentarse de la Provincia sin la autorización de la Cámara, por un período superior al de quince días o de cinco días si fueran simultáneos. En el receso de ésta, cuando fuere necesario permiso previo, sólo podrán ausentarse por un motivo urgente y de interés público y por el tiempo indispensable, dando cuenta oportunamente a la misma.`, currentText: `El Gobernador y el Vicegobernador en desempeño del Poder Ejecutivo residirán en la capital de la Provincia, y sólo podrán salir de ella en el ejercicio de sus funciones, y dentro del territorio de la Provincia por un término que, en cada caso, no exceda de treinta días. En ningún caso podrán ausentarse de la Provincia sin la autorización de la Cámara, por un período superior al de quince días o de cinco días si fueran simultáneos. En el receso de ésta, cuando fuere necesario permiso previo, sólo podrán ausentarse por un motivo urgente y de interés público y por el tiempo indispensable, dando cuenta oportunamente a la misma.`, plainLanguageExplanation: 'El Gobernador y quien ejerza el Ejecutivo deben residir en la capital de la Provincia y no pueden salir del territorio sin autorización de la Legislatura, salvo casos de urgencia.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['residencia', 'Gobernador', 'ausencia', 'autorización legislativa'], order: 135, segments: [], amendments: [] },
  { id: 'const-formosa-art-137', lawId: 'const-formosa', number: '137', title: 'Juramento del Gobernador y Vicegobernador al asumir', originalText: `Al asumir sus cargos, el Gobernador y el Vicegobernador prestarán juramento de desempeñarlo conforme con la Constitución y las leyes que en su consecuencia se dicten.`, currentText: `Al asumir sus cargos, el Gobernador y el Vicegobernador prestarán juramento de desempeñarlo conforme con la Constitución y las leyes que en su consecuencia se dicten.`, plainLanguageExplanation: 'Al asumir el cargo, el Gobernador y Vicegobernador deben prestar juramento de ejercerlo conforme a la Constitución y las leyes.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juramento', 'Gobernador', 'Vicegobernador', 'asunción'], order: 136, segments: [], amendments: [] },
  { id: 'const-formosa-art-138', lawId: 'const-formosa', number: '138', title: 'Remuneración del Gobernador y Vicegobernador', originalText: `El Gobernador y el Vicegobernador gozarán de remuneración a cargo de la Provincia, la que no podrá ser alterada, salvo aumento de carácter general. No podrán ejercer empleo ni recibir emolumento alguno de la Nación o de otras provincias. Ningún funcionario del Poder Ejecutivo Provincial, de sus entes autárquicos, descentralizados, empresas del Estado o sociedades de economía mixta con mayoría estatal, podrá percibir una remuneración mayor a la del Gobernador de la Provincia.`, currentText: `El Gobernador y el Vicegobernador gozarán de remuneración a cargo de la Provincia, la que no podrá ser alterada, salvo aumento de carácter general. No podrán ejercer empleo ni recibir emolumento alguno de la Nación o de otras provincias. Ningún funcionario del Poder Ejecutivo Provincial, de sus entes autárquicos, descentralizados, empresas del Estado o sociedades de economía mixta con mayoría estatal, podrá percibir una remuneración mayor a la del Gobernador de la Provincia.`, plainLanguageExplanation: 'El Gobernador y Vicegobernador reciben remuneración a cargo de la Provincia. No puede ser reducida durante su mandato, salvo ajuste general para todos los cargos.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remuneración', 'Gobernador', 'Vicegobernador', 'intangibilidad salarial'], order: 137, segments: [], amendments: [] },
  { id: 'const-formosa-art-139', lawId: 'const-formosa', number: '139', title: 'Elección directa del Gobernador — pluralidad de sufragios', originalText: `El Gobernador y el Vicegobernador serán elegidos directamente por el pueblo y a simple pluralidad de sufragios, conforme con la ley electoral, en la fecha que lo determine, la que no podrá ser inferior a los treinta días ni superior a los ciento ochenta días de su renovación.`, currentText: `El Gobernador y el Vicegobernador serán elegidos directamente por el pueblo y a simple pluralidad de sufragios, conforme con la ley electoral, en la fecha que lo determine, la que no podrá ser inferior a los treinta días ni superior a los ciento ochenta días de su renovación.`, plainLanguageExplanation: 'El Gobernador y Vicegobernador se eligen directamente por el pueblo a simple pluralidad de votos (primera minoría), conforme a la ley electoral.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['elección directa', 'Gobernador', 'pluralidad de sufragios', 'ley electoral'], order: 138, segments: [], amendments: [] },
  { id: 'const-formosa-art-140', lawId: 'const-formosa', number: '140', title: 'Simultaneidad de las elecciones provinciales', originalText: `La elección de Gobernador y de Vicegobernador se efectuará juntamente con la de legisladores y demás autoridades electivas de la Provincia, cuando circunstancias especiales no aconsejen lo contrario. El resultado de la elección deberá ser comunicado a los candidatos electos, y el Tribunal Electoral Permanente procederá a proclamar a los elegidos. Estos comunicarán su aceptación dentro de los cinco días de recibida la comunicación y prestarán juramento ante la Legislatura el día fijado, o ante el Superior Tribunal de Justicia, en el supuesto caso de que aquélla no se constituyera en término para ese efecto antes del cese de mandato del Gobernador y del Vicegobernador salientes, a quienes se efectuará igual comunicación.`, currentText: `La elección de Gobernador y de Vicegobernador se efectuará juntamente con la de legisladores y demás autoridades electivas de la Provincia, cuando circunstancias especiales no aconsejen lo contrario. El resultado de la elección deberá ser comunicado a los candidatos electos, y el Tribunal Electoral Permanente procederá a proclamar a los elegidos. Estos comunicarán su aceptación dentro de los cinco días de recibida la comunicación y prestarán juramento ante la Legislatura el día fijado, o ante el Superior Tribunal de Justicia, en el supuesto caso de que aquélla no se constituyera en término para ese efecto antes del cese de mandato del Gobernador y del Vicegobernador salientes, a quienes se efectuará igual comunicación.`, plainLanguageExplanation: 'Las elecciones del Gobernador y Vicegobernador se realizan simultáneamente con las de legisladores y demás autoridades electivas de la Provincia.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['elecciones provinciales', 'simultaneidad', 'Gobernador', 'legisladores'], order: 139, segments: [], amendments: [] },
  { id: 'const-formosa-art-141', lawId: 'const-formosa', number: '141', title: 'Inmunidades del Gobernador y Vicegobernador', originalText: `El Gobernador y el Vicegobernador gozarán de iguales inmunidades que los legisladores.`, currentText: `El Gobernador y el Vicegobernador gozarán de iguales inmunidades que los legisladores.`, plainLanguageExplanation: 'El Gobernador y el Vicegobernador gozan de las mismas inmunidades que los legisladores: inmunidad de opinión y de arresto.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inmunidades', 'Gobernador', 'Vicegobernador', 'fueros'], order: 140, segments: [], amendments: [] },
  { id: 'const-formosa-art-142', lawId: 'const-formosa', number: '142', title: 'Atribuciones y deberes del Gobernador', originalText: `El Gobernador es el jefe de la administración y tiene las siguientes atribuciones y deberes: 1) Representar a la Provincia en sus relaciones con los demás poderes públicos y con los Estados extranjeros, la Nación o con las demás provincias, con los cuales podrá celebrar convenios y tratados para fines de utilidad común, especialmente en materia cultural, educacional, económica, de administración de justicia e integración regional, con aprobación de la Legislatura y oportuno conocimiento del Congreso Nacional. 2) Participar en la formación de las leyes con arreglo a esta Constitución, ejerciendo el derecho de iniciativa ante la Legislatura; intervenir en la discusión por sí o por medio de sus ministros, sin voto. Promulgar y publicar, o vetar las leyes total o parcialmente. 3) Expedir las instrucciones, reglamentos y decretos necesarios para la ejecución de las leyes, sin alterar su contenido ni espíritu. 4) Dictar los reglamentos necesarios para cumplir los fines previstos en esta Constitución, salvo en las materias reservadas a la ley o atribuidas a órganos de la Constitución. 5) Convocar a sesiones extraordinarias de la Legislatura cuando algún grave asunto de interés público lo requiera, especificando los asuntos por tratar, o requerir la prórroga de sus sesiones. 6) Presentar, hasta treinta días antes de finalizar las sesiones ordinarias de la Cámara de Diputados, el proyecto de ley de presupuesto general de la administración para el ejercicio siguiente. 7) Informar a la Legislatura, al iniciarse el período de sesiones ordinarias, el estado general de la administración y el movimiento de fondos que se hubiere producido dentro y fuera del presupuesto general durante el ejercicio anterior. El balance que con tal motivo se formule será publicado, cuando menos, en un diario local y en el boletín oficial de la Provincia. Publicará también en igual forma, al final de cada trimestre, un resumen claro y explicativo de los ingresos e inversiones que hayan tenido lugar durante el mismo. 8) Hacer recaudar la renta pública y decretar su inversión con arreglo a la ley, pudiendo apremiar judicialmente a los contribuyentes morosos, a los recaudadores y sus fiadores, y a todos los empleados que indebidamente retengan fondos del tesoro provincial, sin perjuicio de las sanciones que a éstos correspondan. 9) Proponer, para su nombramiento por la Legislatura, los funcionarios y magistrados cuya forma de designación establece esta Constitución, por sí solo nombrar los ministros y demás empleados cuya designación no esté sometida a otra autoridad. Todo nombramiento de funcionarios cuya forma se determine expresamente y que se haga en receso de la Legislatura, lo será sólo en comisión, cesando los mismos en sus funciones si dentro de los treinta días de iniciación del período de sesiones ordinarias no se solicitare el acuerdo correspondiente. 10) Remover los empleados de la Administración de acuerdo con las prescripciones de esta Constitución y las leyes que se dicten. 11) Convocar a elecciones en los casos y épocas determinadas en esta Constitución y las leyes respectivas. 12) Tener bajo su inspección la policía provincial de seguridad y vigilancia; la tutela del dominio público provincial; los establecimientos públicos de la Provincia, y prestar el auxilio de la fuerza pública a las autoridades y funcionarios que, por el ordenamiento jurídico vigente, estén autorizados para hacer uso de ella. 13) Celebrar contratos con empresas particulares para objeto de utilidad pública. 14) Conocer y resolver los recursos y reclamos administrativos de su competencia, siendo sus resoluciones impugnables judicialmente en el modo y forma que la ley determina. 15) El Gobernador no podrá expedir órdenes ni decretos sin la firma, por lo menos, de un Ministro. En caso de ausencia o vacancia del cargo, firmarán el respectivo Subsecretario o Ministro que, previo decreto del mismo, así lo autorice. 16) El Gobernador de la Provincia es el agente natural del Gobierno de la Nación. 17) Conceder indultos y conmutar penas por delitos sujetos a jurisdicción provincial, previo informe del Superior Tribunal, en la forma y en los casos que determine la ley. No podrá ejercer esta atribución cuando se trate de delitos de funcionarios públicos cometidos en el ejercicio de sus funciones. 18) Tomar las medidas para conservar la paz, para mantener la integridad de la hacienda pública, asegurar el funcionamiento del Estado, realizar las operaciones financieras y de créditos, celebrar convenios, preservar el orden público por todos los medios que no estén prohibidos por esta Constitución y leyes vigentes. 19) Promover lo conducente al ordenamiento y régimen de los servicios públicos. 20) Adoptar las medidas conducentes a la reforma de la Administración Pública, desconcentrar competencias, crear, organizar y transformar entes descentralizados, así como sociedades o empresas mixtas o estatales, sometidas total o parcialmente al derecho privado, destinadas a la prestación o regulación de servicios públicos esenciales, comerciales o industriales, satisfacción de necesidades públicas o a la propia actividad económica del Estado Provincial conforme al principio de subsidiariedad. CAPITULO TERCERO.- De Los Ministros`, currentText: `El Gobernador es el jefe de la administración y tiene las siguientes atribuciones y deberes: 1) Representar a la Provincia en sus relaciones con los demás poderes públicos y con los Estados extranjeros, la Nación o con las demás provincias, con los cuales podrá celebrar convenios y tratados para fines de utilidad común, especialmente en materia cultural, educacional, económica, de administración de justicia e integración regional, con aprobación de la Legislatura y oportuno conocimiento del Congreso Nacional. 2) Participar en la formación de las leyes con arreglo a esta Constitución, ejerciendo el derecho de iniciativa ante la Legislatura; intervenir en la discusión por sí o por medio de sus ministros, sin voto. Promulgar y publicar, o vetar las leyes total o parcialmente. 3) Expedir las instrucciones, reglamentos y decretos necesarios para la ejecución de las leyes, sin alterar su contenido ni espíritu. 4) Dictar los reglamentos necesarios para cumplir los fines previstos en esta Constitución, salvo en las materias reservadas a la ley o atribuidas a órganos de la Constitución. 5) Convocar a sesiones extraordinarias de la Legislatura cuando algún grave asunto de interés público lo requiera, especificando los asuntos por tratar, o requerir la prórroga de sus sesiones. 6) Presentar, hasta treinta días antes de finalizar las sesiones ordinarias de la Cámara de Diputados, el proyecto de ley de presupuesto general de la administración para el ejercicio siguiente. 7) Informar a la Legislatura, al iniciarse el período de sesiones ordinarias, el estado general de la administración y el movimiento de fondos que se hubiere producido dentro y fuera del presupuesto general durante el ejercicio anterior. El balance que con tal motivo se formule será publicado, cuando menos, en un diario local y en el boletín oficial de la Provincia. Publicará también en igual forma, al final de cada trimestre, un resumen claro y explicativo de los ingresos e inversiones que hayan tenido lugar durante el mismo. 8) Hacer recaudar la renta pública y decretar su inversión con arreglo a la ley, pudiendo apremiar judicialmente a los contribuyentes morosos, a los recaudadores y sus fiadores, y a todos los empleados que indebidamente retengan fondos del tesoro provincial, sin perjuicio de las sanciones que a éstos correspondan. 9) Proponer, para su nombramiento por la Legislatura, los funcionarios y magistrados cuya forma de designación establece esta Constitución, por sí solo nombrar los ministros y demás empleados cuya designación no esté sometida a otra autoridad. Todo nombramiento de funcionarios cuya forma se determine expresamente y que se haga en receso de la Legislatura, lo será sólo en comisión, cesando los mismos en sus funciones si dentro de los treinta días de iniciación del período de sesiones ordinarias no se solicitare el acuerdo correspondiente. 10) Remover los empleados de la Administración de acuerdo con las prescripciones de esta Constitución y las leyes que se dicten. 11) Convocar a elecciones en los casos y épocas determinadas en esta Constitución y las leyes respectivas. 12) Tener bajo su inspección la policía provincial de seguridad y vigilancia; la tutela del dominio público provincial; los establecimientos públicos de la Provincia, y prestar el auxilio de la fuerza pública a las autoridades y funcionarios que, por el ordenamiento jurídico vigente, estén autorizados para hacer uso de ella. 13) Celebrar contratos con empresas particulares para objeto de utilidad pública. 14) Conocer y resolver los recursos y reclamos administrativos de su competencia, siendo sus resoluciones impugnables judicialmente en el modo y forma que la ley determina. 15) El Gobernador no podrá expedir órdenes ni decretos sin la firma, por lo menos, de un Ministro. En caso de ausencia o vacancia del cargo, firmarán el respectivo Subsecretario o Ministro que, previo decreto del mismo, así lo autorice. 16) El Gobernador de la Provincia es el agente natural del Gobierno de la Nación. 17) Conceder indultos y conmutar penas por delitos sujetos a jurisdicción provincial, previo informe del Superior Tribunal, en la forma y en los casos que determine la ley. No podrá ejercer esta atribución cuando se trate de delitos de funcionarios públicos cometidos en el ejercicio de sus funciones. 18) Tomar las medidas para conservar la paz, para mantener la integridad de la hacienda pública, asegurar el funcionamiento del Estado, realizar las operaciones financieras y de créditos, celebrar convenios, preservar el orden público por todos los medios que no estén prohibidos por esta Constitución y leyes vigentes. 19) Promover lo conducente al ordenamiento y régimen de los servicios públicos. 20) Adoptar las medidas conducentes a la reforma de la Administración Pública, desconcentrar competencias, crear, organizar y transformar entes descentralizados, así como sociedades o empresas mixtas o estatales, sometidas total o parcialmente al derecho privado, destinadas a la prestación o regulación de servicios públicos esenciales, comerciales o industriales, satisfacción de necesidades públicas o a la propia actividad económica del Estado Provincial conforme al principio de subsidiariedad. CAPITULO TERCERO.- De Los Ministros`, plainLanguageExplanation: 'El Gobernador es el jefe de la administración provincial. Sus atribuciones incluyen representar a la Provincia, promulgar y reglamentar leyes, nombrar funcionarios, dirigir las fuerzas públicas y administrar el presupuesto.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Gobernador', 'atribuciones', 'jefe de administración', 'Poder Ejecutivo'], order: 141, segments: [], amendments: [] },
  { id: 'const-formosa-art-143', lawId: 'const-formosa', number: '143', title: 'Ministerios — número y competencias fijados por ley', originalText: `El despacho de los negocios administrativos estará a cargo de ministros secretarios y una ley especial fijará su número y deslindará las competencias y funciones de cada uno de ellos.`, currentText: `El despacho de los negocios administrativos estará a cargo de ministros secretarios y una ley especial fijará su número y deslindará las competencias y funciones de cada uno de ellos.`, plainLanguageExplanation: 'Los asuntos de gobierno se despachan a través de Ministros Secretarios. Una ley especial fija cuántos ministerios hay y cuáles son sus competencias y funciones.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Ministerios', 'ministros', 'Poder Ejecutivo', 'organización administrativa'], order: 142, segments: [], amendments: [] },
  { id: 'const-formosa-art-144', lawId: 'const-formosa', number: '144', title: 'Requisitos para ser designado Ministro', originalText: `Para ser designado Ministro se requieren las mismas condiciones que para ser elegido Diputado.`, currentText: `Para ser designado Ministro se requieren las mismas condiciones que para ser elegido Diputado.`, plainLanguageExplanation: 'Para ser Ministro se requieren los mismos requisitos que para ser Diputado provincial: ciudadanía argentina, 21 años de edad y 6 años de residencia en la Provincia.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Ministro', 'requisitos', 'ciudadanía', 'edad', 'residencia'], order: 143, segments: [], amendments: [] },
  { id: 'const-formosa-art-145', lawId: 'const-formosa', number: '145', title: 'Responsabilidad individual y solidaria de los Ministros', originalText: `Cada Ministro es responsable de los actos que legaliza y solidariamente, de los que resuelve con sus colegas, no pudiendo por sí solo tomar resoluciones, con excepción de lo concerniente al régimen administrativo y económico de su propio departamento.`, currentText: `Cada Ministro es responsable de los actos que legaliza y solidariamente, de los que resuelve con sus colegas, no pudiendo por sí solo tomar resoluciones, con excepción de lo concerniente al régimen administrativo y económico de su propio departamento.`, plainLanguageExplanation: 'Cada Ministro es individualmente responsable de los actos que legaliza con su firma, y solidariamente responsable de los que resuelve junto a sus colegas. No puede tomar decisiones por sí solo, excepto en lo inherente al régimen económico de su ministerio.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad ministerial', 'refrendo', 'solidaridad ministerial'], order: 144, segments: [], amendments: [] },
  { id: 'const-formosa-art-146', lawId: 'const-formosa', number: '146', title: 'Ministros ante la Legislatura — participación sin voto', originalText: `Los ministros tienen la facultad de concurrir a las sesiones de la Legislatura y la obligación de informar ante ella y tomar parte en los debates, sin voto.`, currentText: `Los ministros tienen la facultad de concurrir a las sesiones de la Legislatura y la obligación de informar ante ella y tomar parte en los debates, sin voto.`, plainLanguageExplanation: 'Los Ministros pueden asistir a las sesiones de la Legislatura, tienen la obligación de informar ante ella y pueden participar en los debates, pero no tienen derecho a votar.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Ministros', 'Legislatura', 'informes', 'debates', 'sin voto'], order: 145, segments: [], amendments: [] },
  { id: 'const-formosa-art-147', lawId: 'const-formosa', number: '147', title: 'Remuneración de los Ministros — intangibilidad', originalText: `Los ministros recibirán un sueldo establecido por la ley, que no podrá ser alterado en beneficio o perjuicio de las personas que desempeñan los cargos, sino por otra ley. CUARTA PARTE CAPITULO PRIMERO.- Fiscal De Estado`, currentText: `Los ministros recibirán un sueldo establecido por la ley, que no podrá ser alterado en beneficio o perjuicio de las personas que desempeñan los cargos, sino por otra ley. CUARTA PARTE CAPITULO PRIMERO.- Fiscal De Estado`, plainLanguageExplanation: 'Los Ministros reciben un sueldo fijado por ley que no puede modificarse en beneficio o perjuicio de quienes estén ejerciendo el cargo, salvo por otra ley.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remuneración', 'Ministros', 'intangibilidad salarial'], order: 146, segments: [], amendments: [] },
  { id: 'const-formosa-art-148', lawId: 'const-formosa', number: '148', title: 'Fiscal de Estado — designación y funciones', originalText: `Habrá un Fiscal de Estado nombrado por el Poder Ejecutivo con acuerdo legislativo. La ley determinará la forma en que ha de ejercer sus funciones.`, currentText: `Habrá un Fiscal de Estado nombrado por el Poder Ejecutivo con acuerdo legislativo. La ley determinará la forma en que ha de ejercer sus funciones.`, plainLanguageExplanation: 'El Fiscal de Estado es nombrado por el Ejecutivo con acuerdo de la Legislatura. La ley determina cómo ejerce sus funciones de defensa del Estado provincial.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Fiscal de Estado', 'designación', 'acuerdo legislativo', 'patrimonio fiscal'], order: 147, segments: [], amendments: [] },
  { id: 'const-formosa-art-149', lawId: 'const-formosa', number: '149', title: 'Atribuciones del Fiscal de Estado — defensa del fisco', originalText: `Corresponde al Fiscal de Estado la defensa del patrimonio del fisco provincial y será parte necesaria y legítima en los juicios contencioso-administrativos y en todos aquellos en que se controviertan intereses de la Provincia. CAPITULO SEGUNDO.- Tribunal De Cuentas`, currentText: `Corresponde al Fiscal de Estado la defensa del patrimonio del fisco provincial y será parte necesaria y legítima en los juicios contencioso-administrativos y en todos aquellos en que se controviertan intereses de la Provincia. CAPITULO SEGUNDO.- Tribunal De Cuentas`, plainLanguageExplanation: 'El Fiscal de Estado defiende el patrimonio del fisco provincial y es parte necesaria en los juicios contencioso-administrativos y en todo juicio en que la Provincia sea parte.', practicalEffects: [], examples: ['Cuando el Estado provincial es demandado por un particular, el Fiscal de Estado actúa como representante legal del fisco en el juicio.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Fiscal de Estado', 'fisco provincial', 'juicios contencioso-administrativos', 'representación del Estado'], order: 148, segments: [], amendments: [] },
  { id: 'const-formosa-art-150', lawId: 'const-formosa', number: '150', title: 'Tribunal de Cuentas — composición y autoridades', originalText: `El Tribunal de Cuentas tiene jurisdicción en toda la Provincia y estará integrado por un presidente abogado y dos vocales contadores públicos; todos inamovibles y designados por la Legislatura a propuesta del Poder Ejecutivo. Los mismos podrán ser enjuiciados y removidos en la misma forma y en los mismos casos que los jueces del Superior Tribunal de Justicia; gozando de iguales prerrogativas y privilegios. Tiene independencia funcional y la facultad de proyectar su presupuesto de gastos adecuado a las pautas contenidas en el presupuesto general, de dictar su reglamento interno y de procedimiento para el ejercicio de sus facultades y la de designar y remover a su personal conforme con las previsiones que establezca el Estatuto General para el Empleado Público Provincial normado en el artículo 88.`, currentText: `El Tribunal de Cuentas tiene jurisdicción en toda la Provincia y estará integrado por un presidente abogado y dos vocales contadores públicos; todos inamovibles y designados por la Legislatura a propuesta del Poder Ejecutivo. Los mismos podrán ser enjuiciados y removidos en la misma forma y en los mismos casos que los jueces del Superior Tribunal de Justicia; gozando de iguales prerrogativas y privilegios. Tiene independencia funcional y la facultad de proyectar su presupuesto de gastos adecuado a las pautas contenidas en el presupuesto general, de dictar su reglamento interno y de procedimiento para el ejercicio de sus facultades y la de designar y remover a su personal conforme con las previsiones que establezca el Estatuto General para el Empleado Público Provincial normado en el artículo 88.`, plainLanguageExplanation: 'El Tribunal de Cuentas controla la hacienda pública en toda la Provincia. Se integra por un Presidente abogado y dos Vocales contadores públicos, todos inamovibles y designados por el Ejecutivo con acuerdo legislativo.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Tribunal de Cuentas', 'control externo', 'hacienda pública', 'inamovilidad'], order: 149, segments: [], amendments: [] },
  { id: 'const-formosa-art-151', lawId: 'const-formosa', number: '151', title: 'Atribuciones del Tribunal de Cuentas', originalText: `El Tribunal de Cuentas tendrá las siguientes atribuciones: 1) El control externo de la gestión económica, financiera y patrimonial de la hacienda pública provincial y municipal; el examen de las cuentas de percepción e inversión de las rentas públicas; aprobarlas o desaprobarlas; y el análisis de los hechos, actos u omisiones de los que pudieren derivarse perjuicios patrimoniales para la hacienda pública. En todos los casos, con competencia exclusiva y excluyente, declarar las responsabilidades que resulten, e indicar los responsables, los importes y las causas, con los alcances respectivos. 2) Podrá intervenir preventivamente, por sí o por funcionarios delegados, los actos administrativos que se refieren a la hacienda pública, y observarlos cuando contraríen o violen esta Constitución, o las leyes y reglamentos dictados en consecuencia. El acto observado se suspenderá en su ejecución y sólo podrá cumplirse cuando hubiera insistencia del Poder Ejecutivo en acuerdo de ministros, o de los respectivos presidentes de la Honorable Legislatura y del Superior Tribunal de Justicia o Intendentes, debiendo remitirse, en estos casos, los antecedentes al Tribunal de Cuentas. 3) Ordenar auditorías a las dependencias provinciales y municipales públicas, privadas o mixtas que administren fondos públicos, en las que el Estado Provincial tenga intereses o hubiera garantizado materialmente su solvencia o utilidad, o acordado concesiones, privilegios o subsidios para su instalación o funcionamiento. Respecto de las empresas estatales o mixtas creadas por el Estado Provincial para la prestación de servicios comerciales o industriales, bajo un régimen de derecho público o privado, el control del Tribunal de Cuentas se efectuará exclusivamente mediante la designación de un síndico. CAPITULO TERCERO.- Fiscalía de Investigaciones Administrativas`, currentText: `El Tribunal de Cuentas tendrá las siguientes atribuciones: 1) El control externo de la gestión económica, financiera y patrimonial de la hacienda pública provincial y municipal; el examen de las cuentas de percepción e inversión de las rentas públicas; aprobarlas o desaprobarlas; y el análisis de los hechos, actos u omisiones de los que pudieren derivarse perjuicios patrimoniales para la hacienda pública. En todos los casos, con competencia exclusiva y excluyente, declarar las responsabilidades que resulten, e indicar los responsables, los importes y las causas, con los alcances respectivos. 2) Podrá intervenir preventivamente, por sí o por funcionarios delegados, los actos administrativos que se refieren a la hacienda pública, y observarlos cuando contraríen o violen esta Constitución, o las leyes y reglamentos dictados en consecuencia. El acto observado se suspenderá en su ejecución y sólo podrá cumplirse cuando hubiera insistencia del Poder Ejecutivo en acuerdo de ministros, o de los respectivos presidentes de la Honorable Legislatura y del Superior Tribunal de Justicia o Intendentes, debiendo remitirse, en estos casos, los antecedentes al Tribunal de Cuentas. 3) Ordenar auditorías a las dependencias provinciales y municipales públicas, privadas o mixtas que administren fondos públicos, en las que el Estado Provincial tenga intereses o hubiera garantizado materialmente su solvencia o utilidad, o acordado concesiones, privilegios o subsidios para su instalación o funcionamiento. Respecto de las empresas estatales o mixtas creadas por el Estado Provincial para la prestación de servicios comerciales o industriales, bajo un régimen de derecho público o privado, el control del Tribunal de Cuentas se efectuará exclusivamente mediante la designación de un síndico. CAPITULO TERCERO.- Fiscalía de Investigaciones Administrativas`, plainLanguageExplanation: 'El Tribunal de Cuentas controla la gestión económica, financiera y patrimonial del Estado provincial, verifica la legalidad del gasto público y puede observar o anular actos que contravengan normas.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Tribunal de Cuentas', 'control externo', 'gasto público', 'legalidad fiscal'], order: 150, segments: [], amendments: [] },
  { id: 'const-formosa-art-152', lawId: 'const-formosa', number: '152', title: 'Fiscal de Investigaciones Administrativas', originalText: `Habrá un Fiscal de Investigaciones Administrativas, a quien le corresponde la promoción de la investigación de las conductas administrativas de los funcionarios y agentes de la administración pública, de los entes descentralizados y autárquicos; y de las empresas y sociedades del Estado o controladas por éste. En los casos en que intervenga la Fiscalía controlará la existencia de beneficiarios de las acciones imputadas y, cuando corresponda, investigará a éstos, conforme con las circunstancias de cada caso. La ley establecerá la organización, funciones, competencia, procedimiento y situación institucional de la Fiscalía de Investigaciones Administrativas. Para ser designado Fiscal de Investigaciones Administrativas, se requieren las mismas exigencias y procedimientos que para ser miembro del Superior Tribunal de Justicia, teniendo iguales incompatibilidades, prohibiciones, prerrogativas e inmunidades. CAPITULO CUARTO.- Defensor Del Pueblo`, currentText: `Habrá un Fiscal de Investigaciones Administrativas, a quien le corresponde la promoción de la investigación de las conductas administrativas de los funcionarios y agentes de la administración pública, de los entes descentralizados y autárquicos; y de las empresas y sociedades del Estado o controladas por éste. En los casos en que intervenga la Fiscalía controlará la existencia de beneficiarios de las acciones imputadas y, cuando corresponda, investigará a éstos, conforme con las circunstancias de cada caso. La ley establecerá la organización, funciones, competencia, procedimiento y situación institucional de la Fiscalía de Investigaciones Administrativas. Para ser designado Fiscal de Investigaciones Administrativas, se requieren las mismas exigencias y procedimientos que para ser miembro del Superior Tribunal de Justicia, teniendo iguales incompatibilidades, prohibiciones, prerrogativas e inmunidades. CAPITULO CUARTO.- Defensor Del Pueblo`, plainLanguageExplanation: 'El Fiscal de Investigaciones Administrativas investiga la conducta de los funcionarios y agentes de la administración pública provincial, con independencia del Ejecutivo.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Fiscal de Investigaciones Administrativas', 'anticorrupción', 'funcionarios', 'control interno'], order: 151, segments: [], amendments: [] },
  { id: 'const-formosa-art-153', lawId: 'const-formosa', number: '153', title: 'Defensor del Pueblo — derechos humanos colectivos y difusos', originalText: `Habrá un Defensor del Pueblo, a quien le corresponde la defensa de los derechos humanos colectivos o difusos, frente a los actos, hechos u omisiones de la Administración Pública Provincial; la supervisión de la eficacia en la prestación de los servicios públicos; y el control en la aplicación de las leyes y demás disposiciones. Sus funciones serán reglamentadas por ley, y su actuación se fundará en los principios de informalismo, gratuidad, impulsión de oficio, sumariedad y accesibilidad. El Defensor del Pueblo tiene legitimación procesal. Su designación se efectuará por el mismo procedimiento que para los miembros del Superior Tribunal de Justicia. Gozará de las inmunidades y privilegios de los legisladores y deberá reunir los mismos requisitos que éstos para ser nombrado, durará cinco años en sus funciones y no podrá ser separado de ella, sino por las causales y el procedimiento establecido respecto al juicio político. CAPITULO QUINTO.- Acción De Transparencia`, currentText: `Habrá un Defensor del Pueblo, a quien le corresponde la defensa de los derechos humanos colectivos o difusos, frente a los actos, hechos u omisiones de la Administración Pública Provincial; la supervisión de la eficacia en la prestación de los servicios públicos; y el control en la aplicación de las leyes y demás disposiciones. Sus funciones serán reglamentadas por ley, y su actuación se fundará en los principios de informalismo, gratuidad, impulsión de oficio, sumariedad y accesibilidad. El Defensor del Pueblo tiene legitimación procesal. Su designación se efectuará por el mismo procedimiento que para los miembros del Superior Tribunal de Justicia. Gozará de las inmunidades y privilegios de los legisladores y deberá reunir los mismos requisitos que éstos para ser nombrado, durará cinco años en sus funciones y no podrá ser separado de ella, sino por las causales y el procedimiento establecido respecto al juicio político. CAPITULO QUINTO.- Acción De Transparencia`, plainLanguageExplanation: 'El Defensor del Pueblo protege los derechos humanos colectivos o difusos frente a actos u omisiones de la Administración Pública. Actúa con independencia funcional y puede investigar y recomendar sin necesidad de mandato judicial.', practicalEffects: [], examples: ['Un vecino puede recurrir al Defensor del Pueblo si un organismo provincial contamina el agua de su barrio sin respuesta oficial.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Defensor del Pueblo', 'derechos difusos', 'ombudsman', 'Administración Pública'], order: 152, segments: [], amendments: [] },
  { id: 'const-formosa-art-154', lawId: 'const-formosa', number: '154', title: 'Declaración jurada de bienes — magistrados y funcionarios', originalText: `Todo magistrado, legislador o funcionario, sea por elección o por designación, antes de jurar o asumir el cargo, deberá efectuar una declaración jurada de bienes ante la Fiscalía de Investigaciones Administrativas; caso contrario, no podrá acceder al mismo; idéntica declaración realizará una vez concluida su función, so pena de no poder reingresar en la administración pública provincial en cualquier carácter, ni obtener beneficios de ninguna índole del Estado o como consecuencia de la función cumplida. Cualquier ciudadano, con interés legítimo, sin que ello implique imputación de delito, podrá solicitar ante el Fiscal de Investigaciones Administrativas, por un procedimiento sumario y gratuito que organizará la ley, que el magistrado, legislador o funcionario que indique, dé explicación sobre el origen de sus bienes, hasta cuatro años después de cesado en su mandato o empleo. Se cumplimenta con esta obligación efectuando una explicación o declaración anual. CAPITULO SEXTO.- Consejo Económico Social`, currentText: `Todo magistrado, legislador o funcionario, sea por elección o por designación, antes de jurar o asumir el cargo, deberá efectuar una declaración jurada de bienes ante la Fiscalía de Investigaciones Administrativas; caso contrario, no podrá acceder al mismo; idéntica declaración realizará una vez concluida su función, so pena de no poder reingresar en la administración pública provincial en cualquier carácter, ni obtener beneficios de ninguna índole del Estado o como consecuencia de la función cumplida. Cualquier ciudadano, con interés legítimo, sin que ello implique imputación de delito, podrá solicitar ante el Fiscal de Investigaciones Administrativas, por un procedimiento sumario y gratuito que organizará la ley, que el magistrado, legislador o funcionario que indique, dé explicación sobre el origen de sus bienes, hasta cuatro años después de cesado en su mandato o empleo. Se cumplimenta con esta obligación efectuando una explicación o declaración anual. CAPITULO SEXTO.- Consejo Económico Social`, plainLanguageExplanation: 'Antes de asumir, todo magistrado, legislador o funcionario (electo o designado) debe presentar una declaración jurada de bienes. También debe presentarla al cesar en el cargo.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['declaración jurada', 'bienes', 'funcionarios públicos', 'transparencia'], order: 153, segments: [], amendments: [] },
  { id: 'const-formosa-art-155', lawId: 'const-formosa', number: '155', title: 'Consejo Económico Social — composición y funciones consultivas', originalText: `El Consejo Económico Social estará integrado por los representantes de los sectores de la producción, del trabajo, de los profesionales, entidades socio-culturales y funcionará mediante delegados designados por las organizaciones más representativas, con personería reconocida por autoridad competente, en la forma que determine la ley. El Consejo es un órgano permanente de consulta y asesoramiento de los distintos poderes públicos en el campo social y económico. Los municipios podrán crear en sus jurisdicciones organismos de análogas funciones y características. CAPITULO SEPTIMO.- Juicio Político`, currentText: `El Consejo Económico Social estará integrado por los representantes de los sectores de la producción, del trabajo, de los profesionales, entidades socio-culturales y funcionará mediante delegados designados por las organizaciones más representativas, con personería reconocida por autoridad competente, en la forma que determine la ley. El Consejo es un órgano permanente de consulta y asesoramiento de los distintos poderes públicos en el campo social y económico. Los municipios podrán crear en sus jurisdicciones organismos de análogas funciones y características. CAPITULO SEPTIMO.- Juicio Político`, plainLanguageExplanation: 'El Consejo Económico Social integra representantes de sectores productivos, laborales, profesionales y socioculturales. Es un órgano consultivo que puede emitir opiniones y recomendaciones sobre políticas económicas y sociales.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Consejo Económico Social', 'participación ciudadana', 'órgano consultivo', 'sectores productivos'], order: 154, segments: [], amendments: [] },
  { id: 'const-formosa-art-156', lawId: 'const-formosa', number: '156', title: 'Juicio político — funcionarios sujetos a este procedimiento', originalText: `Están sujetos a juicio político el Gobernador, el Vicegobernador y sus ministros; los ministros y el Procurador General del Superior Tribunal de Justicia; el Fiscal de Estado; el Presidente y Vocales del Tribunal de Cuentas; el Fiscal de Investigaciones Administrativas y el Defensor del Pueblo, por mal desempeño en el ejercicio de sus funciones o por presunto delito doloso, incapacidad física o mental sobrevinientes después de haber declarado la Cámara por dos tercios de votos de los presentes, y con citación y audiencia del interesado, si la pidiera, haber lugar a la formación de causa. Pueden ser denunciadas ante la Cámara de Representantes las personas sujetas a este juicio por algunos de sus miembros o cualquier habitante de la Provincia.`, currentText: `Están sujetos a juicio político el Gobernador, el Vicegobernador y sus ministros; los ministros y el Procurador General del Superior Tribunal de Justicia; el Fiscal de Estado; el Presidente y Vocales del Tribunal de Cuentas; el Fiscal de Investigaciones Administrativas y el Defensor del Pueblo, por mal desempeño en el ejercicio de sus funciones o por presunto delito doloso, incapacidad física o mental sobrevinientes después de haber declarado la Cámara por dos tercios de votos de los presentes, y con citación y audiencia del interesado, si la pidiera, haber lugar a la formación de causa. Pueden ser denunciadas ante la Cámara de Representantes las personas sujetas a este juicio por algunos de sus miembros o cualquier habitante de la Provincia.`, plainLanguageExplanation: 'Están sujetos a juicio político el Gobernador, el Vicegobernador, los Ministros, los magistrados del Tribunal Superior, el Fiscal de Estado y el Contador Mayor, por mal desempeño, delito o conducta indigna.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'destitución', 'Gobernador', 'magistrados', 'mal desempeño'], order: 155, segments: [], amendments: [] },
  { id: 'const-formosa-art-157', lawId: 'const-formosa', number: '157', title: 'Procedimiento del juicio político — comisión y despacho', originalText: `Presentada a la Legislatura la petición de juicio político, pasará a estudio de una comisión especial que formulará despacho, en el período de sesiones en que fuere presentado, sobre su procedencia o rechazo.`, currentText: `Presentada a la Legislatura la petición de juicio político, pasará a estudio de una comisión especial que formulará despacho, en el período de sesiones en que fuere presentado, sobre su procedencia o rechazo.`, plainLanguageExplanation: 'Cuando se pide un juicio político, pasa a una comisión especial que elabora su dictamen en el mismo período de sesiones. El acusado puede ser oído y presentar pruebas. La aprobación de la acusación requiere dos tercios de los votos de la Cámara.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'comisión especial', 'acusación', 'dos tercios'], order: 156, segments: [], amendments: [] },
  { id: 'const-formosa-art-158', lawId: 'const-formosa', number: '158', title: 'Juicio político del Gobernador — STJ preside sin voto', originalText: `Cuando el acusado fuere el Gobernador o el Vicegobernador, el Presidente del Superior Tribunal de Justicia presidirá las sesiones de la Legislatura pero no tendrá voto en el fallo.`, currentText: `Cuando el acusado fuere el Gobernador o el Vicegobernador, el Presidente del Superior Tribunal de Justicia presidirá las sesiones de la Legislatura pero no tendrá voto en el fallo.`, plainLanguageExplanation: 'Cuando se juzga al Gobernador o Vicegobernador, el Presidente del Superior Tribunal de Justicia preside las sesiones de la Legislatura pero no tiene derecho a voto.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'Gobernador', 'Superior Tribunal de Justicia', 'presidente'], order: 157, segments: [], amendments: [] },
  { id: 'const-formosa-art-159', lawId: 'const-formosa', number: '159', title: 'Suspensión del funcionario acusado durante el juicio político', originalText: `Recibida la acusación se podrá, por dos tercios de votos, suspender al acusado en el desempeño de sus funciones. En tal caso, si el acusado fuere el Gobernador o el Vicegobernador en ejercicio del Poder Ejecutivo, será reemplazado por el Presidente de la Legislatura.`, currentText: `Recibida la acusación se podrá, por dos tercios de votos, suspender al acusado en el desempeño de sus funciones. En tal caso, si el acusado fuere el Gobernador o el Vicegobernador en ejercicio del Poder Ejecutivo, será reemplazado por el Presidente de la Legislatura.`, plainLanguageExplanation: 'Con dos tercios de los votos, la Legislatura puede suspender al acusado durante el juicio político. Si el acusado es el Gobernador, lo reemplaza el Vicegobernador; si es el Vicegobernador, el Presidente de la Cámara asume el Ejecutivo.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['suspensión', 'juicio político', 'dos tercios', 'Gobernador', 'reemplazo'], order: 158, segments: [], amendments: [] },
  { id: 'const-formosa-art-160', lawId: 'const-formosa', number: '160', title: 'Fallo del juicio político — plazo de 60 días', originalText: `El fallo de la Legislatura será dado dentro de los sesenta días de iniciado el juicio, prorrogando sus sesiones ordinarias a ese solo efecto, si fuere necesario. Vencido dicho término sin haber recaído sentencia, el acusado quedará de hecho absuelto y reintegrado a su cargo, si hubiese sido suspendido.`, currentText: `El fallo de la Legislatura será dado dentro de los sesenta días de iniciado el juicio, prorrogando sus sesiones ordinarias a ese solo efecto, si fuere necesario. Vencido dicho término sin haber recaído sentencia, el acusado quedará de hecho absuelto y reintegrado a su cargo, si hubiese sido suspendido.`, plainLanguageExplanation: 'La Legislatura debe dictar sentencia dentro de los 60 días de iniciado el juicio político. Si el plazo vence sin fallo, el acusado queda absuelto y se sobreentiende que no hay mérito para la acusación.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'fallo', 'plazo', 'absolución', 'sesenta días'], order: 159, segments: [], amendments: [] },
  { id: 'const-formosa-art-161', lawId: 'const-formosa', number: '161', title: 'Condena en juicio político — destitución e inhabilitación', originalText: `Si la Legislatura hallare culpable al acusado, decretará su destitución, pudiendo además declararlo incapaz de ocupar cargo alguno de honor o a sueldo de la Provincia, sin perjuicio de las responsabilidades civiles o criminales a que hubiere lugar.`, currentText: `Si la Legislatura hallare culpable al acusado, decretará su destitución, pudiendo además declararlo incapaz de ocupar cargo alguno de honor o a sueldo de la Provincia, sin perjuicio de las responsabilidades civiles o criminales a que hubiere lugar.`, plainLanguageExplanation: 'Si la Legislatura declara culpable al acusado, lo destituye del cargo. Además puede inhabilitarlo para ocupar cargos públicos. Esto no obsta la responsabilidad penal que sigue ante los tribunales ordinarios.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'destitución', 'inhabilitación', 'responsabilidad penal'], order: 160, segments: [], amendments: [] },
  { id: 'const-formosa-art-162', lawId: 'const-formosa', number: '162', title: 'Mayoría calificada para sentencia condenatoria en juicio político', originalText: `Para dictar sentencia condenatoria se requiere mayoría de dos tercios de votos de la totalidad de los miembros de la Legislatura. La ley reglamentará estas bases.`, currentText: `Para dictar sentencia condenatoria se requiere mayoría de dos tercios de votos de la totalidad de los miembros de la Legislatura. La ley reglamentará estas bases.`, plainLanguageExplanation: 'Para destituir en un juicio político se necesitan dos tercios de votos del total de los miembros de la Legislatura. Una ley reglamenta el procedimiento.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio político', 'dos tercios', 'condena', 'mayoría calificada'], order: 161, segments: [], amendments: [] },
  { id: 'const-formosa-art-163', lawId: 'const-formosa', number: '163', title: 'Autonomía funcional del Poder Judicial', originalText: `El Poder Judicial de la Provincia goza de autonomía funcional, y es de su resorte exclusivo la interpretación y aplicación de esta Constitución, y de las leyes que en su consecuencia se dicten.`, currentText: `El Poder Judicial de la Provincia goza de autonomía funcional, y es de su resorte exclusivo la interpretación y aplicación de esta Constitución, y de las leyes que en su consecuencia se dicten.`, plainLanguageExplanation: 'El Poder Judicial es autónomo y tiene a su cargo exclusivo interpretar y aplicar la Constitución y las leyes. Ningún otro poder puede interferir en sus funciones jurisdiccionales.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Poder Judicial', 'autonomía', 'independencia judicial', 'interpretación de la Constitución'], order: 162, segments: [], amendments: [] },
  { id: 'const-formosa-art-164', lawId: 'const-formosa', number: '164', title: 'Superior Tribunal de Justicia — composición', originalText: `El Poder Judicial de la Provincia será ejercido por un Superior Tribunal de Justicia y demás tribunales que las leyes establezcan. El Superior Tribunal estará integrado por no menos de tres miembros y un Procurador General, designados por la Legislatura a propuesta del Poder Ejecutivo.`, currentText: `El Poder Judicial de la Provincia será ejercido por un Superior Tribunal de Justicia y demás tribunales que las leyes establezcan. El Superior Tribunal estará integrado por no menos de tres miembros y un Procurador General, designados por la Legislatura a propuesta del Poder Ejecutivo.`, plainLanguageExplanation: 'El Poder Judicial se ejerce por el Superior Tribunal de Justicia y los demás tribunales que la ley establezca. El STJ se integra por el número de miembros que fije la ley, uno de los cuales es el Procurador General.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Superior Tribunal de Justicia', 'Poder Judicial', 'Procurador General', 'composición'], order: 163, segments: [], amendments: [] },
  { id: 'const-formosa-art-165', lawId: 'const-formosa', number: '165', title: 'Requisitos para ser Ministro del STJ o Procurador General', originalText: `Para ser Ministro o Procurador General del Superior Tribunal de Justicia se requiere ser ciudadano argentino nativo o por opción, naturalizado, con quince años de ejercicio de la ciudadanía, tener título de abogado expedido por universidad argentina, treinta años de edad y seis años, por lo menos, en el ejercicio activo de la profesión o de la magistratura y de residencia inmediata en la Provincia.`, currentText: `Para ser Ministro o Procurador General del Superior Tribunal de Justicia se requiere ser ciudadano argentino nativo o por opción, naturalizado, con quince años de ejercicio de la ciudadanía, tener título de abogado expedido por universidad argentina, treinta años de edad y seis años, por lo menos, en el ejercicio activo de la profesión o de la magistratura y de residencia inmediata en la Provincia.`, plainLanguageExplanation: 'Para ser Ministro del Superior Tribunal o Procurador General se requiere: ciudadanía argentina, 15 años de ejercicio profesional o de la magistratura, y 35 años de edad.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['STJ', 'Procurador General', 'requisitos', 'magistratura', 'abogado'], order: 164, segments: [], amendments: [] },
  { id: 'const-formosa-art-166', lawId: 'const-formosa', number: '166', title: 'Inamovilidad de los Ministros del STJ y Procurador General', originalText: `Los ministros del Superior Tribunal de Justicia y Procurador General son inamovibles mientras dure su buena conducta; gozan de idénticas prerrogativas e inmunidades que los legisladores y están sujetos a juicio político en la forma establecida por esta Constitución.`, currentText: `Los ministros del Superior Tribunal de Justicia y Procurador General son inamovibles mientras dure su buena conducta; gozan de idénticas prerrogativas e inmunidades que los legisladores y están sujetos a juicio político en la forma establecida por esta Constitución.`, plainLanguageExplanation: 'Los Ministros del STJ y el Procurador General son inamovibles mientras duren en su buena conducta. Gozan de las mismas prerrogativas e inmunidades que los legisladores y solo pueden ser removidos por juicio político.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inamovilidad', 'STJ', 'juicio político', 'independencia judicial'], order: 165, segments: [], amendments: [] },
  { id: 'const-formosa-art-167', lawId: 'const-formosa', number: '167', title: 'Inamovilidad de jueces y funcionarios del Poder Judicial', originalText: `Los demás miembros del Superior Tribunal de Justicia, los jueces letrados, fiscales y defensores, son inamovibles mientras dure su buena conducta; gozan de idénticas prerrogativas e inmunidades que los legisladores y están sujetos a remoción por jurado de enjuiciamiento.`, currentText: `Los demás miembros del Superior Tribunal de Justicia, los jueces letrados, fiscales y defensores, son inamovibles mientras dure su buena conducta; gozan de idénticas prerrogativas e inmunidades que los legisladores y están sujetos a remoción por jurado de enjuiciamiento.`, plainLanguageExplanation: 'Los jueces letrados, fiscales y defensores son inamovibles mientras duren en su buena conducta. Gozan de las mismas prerrogativas e inmunidades que los legisladores. Solo pueden ser removidos por el procedimiento previsto para su caso.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inamovilidad judicial', 'jueces', 'fiscales', 'defensores', 'independencia judicial'], order: 166, segments: [], amendments: [] },
  { id: 'const-formosa-art-168', lawId: 'const-formosa', number: '168', title: 'Requisitos para jueces, fiscales y defensores', originalText: `Los jueces, letrados, fiscales, asesores, defensores oficiales y de pobres, ausentes e incapaces, deberán tener veinticinco años de edad como mínimo, tres en ejercicio activo de la profesión o magistratura y demás condiciones exigidas para ser miembros del Superior Tribunal de Justicia.`, currentText: `Los jueces, letrados, fiscales, asesores, defensores oficiales y de pobres, ausentes e incapaces, deberán tener veinticinco años de edad como mínimo, tres en ejercicio activo de la profesión o magistratura y demás condiciones exigidas para ser miembros del Superior Tribunal de Justicia.`, plainLanguageExplanation: 'Para ser juez, fiscal o defensor se requiere tener 25 años de edad, 3 años de ejercicio profesional y título de abogado.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juez', 'fiscal', 'defensor', 'requisitos', 'abogado'], order: 167, segments: [], amendments: [] },
  { id: 'const-formosa-art-169', lawId: 'const-formosa', number: '169', title: 'Designación de jueces y funcionarios judiciales', originalText: `Los jueces letrados y demás funcionarios mencionados en el Artículo precedente serán designados por la Cámara de Representantes a propuesta del Superior Tribunal de Justicia, mientras no exista Consejo de la Magistratura creado por ley. El Superior Tribunal de Justicia creará Juzgados de Paz de Menor Cuantía en toda la Provincia, atendiendo a la extensión territorial de cada departamento y su población. Determinará los requisitos que deben llenar los jueces y la remuneración que se les asignará. Estos serán designados por el Superior Tribunal de Justicia y removidos en caso de inconducta o impedimento, previo sumario administrativo. La jurisdicción y competencia de los jueces de paz de menor cuantía serán determinadas por el Superior Tribunal de Justicia, por acordada, que les podrá asignar atribuciones administrativas. Los jueces de Paz de Menor Cuantía durarán en sus funciones cuatro años, pudiendo ser reelectos. CAPITULO SEGUNDO.- Atribuciones`, currentText: `Los jueces letrados y demás funcionarios mencionados en el Artículo precedente serán designados por la Cámara de Representantes a propuesta del Superior Tribunal de Justicia, mientras no exista Consejo de la Magistratura creado por ley. El Superior Tribunal de Justicia creará Juzgados de Paz de Menor Cuantía en toda la Provincia, atendiendo a la extensión territorial de cada departamento y su población. Determinará los requisitos que deben llenar los jueces y la remuneración que se les asignará. Estos serán designados por el Superior Tribunal de Justicia y removidos en caso de inconducta o impedimento, previo sumario administrativo. La jurisdicción y competencia de los jueces de paz de menor cuantía serán determinadas por el Superior Tribunal de Justicia, por acordada, que les podrá asignar atribuciones administrativas. Los jueces de Paz de Menor Cuantía durarán en sus funciones cuatro años, pudiendo ser reelectos. CAPITULO SEGUNDO.- Atribuciones`, plainLanguageExplanation: 'Los jueces y demás funcionarios judiciales son designados por la Cámara de Diputados a propuesta del Superior Tribunal de Justicia.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['designación de jueces', 'Superior Tribunal de Justicia', 'Cámara de Diputados', 'nombramiento judicial'], order: 168, segments: [], amendments: [] },
  { id: 'const-formosa-art-170', lawId: 'const-formosa', number: '170', title: 'Atribuciones del Superior Tribunal de Justicia', originalText: `Son atribuciones del Superior Tribunal de Justicia: 1) Conocer y resolver originaria y exclusivamente en las cuestiones de competencia entre los poderes públicos de la Provincia, y en las que susciten entre las municipalidades, y entre éstas y el Estado Provincial. 2) Ejercer la jurisdicción ordinaria y de apelación para conocer y resolver acerca de la constitucionalidad de leyes, decretos, ordenanzas o reglamentos que estatuyan sobre materia regida por esta Constitución y se controviertan por parte interesada. 3) Decidir en las cuestiones de jurisdicción y competencia entre los tribunales de justicia de la Provincia. 4) Conocer en los recursos que deduzcan contra los fallos de los demás tribunales, en la forma que se autorice por las leyes de procedimientos. 5) Conocer originariamente en las causas contencioso-administrativas, cuando las autoridades administrativas denieguen o retarden en el reconocimiento de los derechos reclamados por parte interesada. En estas causas, el Superior Tribunal tiene la facultad de mandar cumplir sus decisiones directamente por las oficinas o empleados correspondientes, si la autoridad administrativa no las cumpliere en el término que le fijase la sentencia. Los empleados comisionados para la ejecución de las decisiones del Superior Tribunal de Justicia quedarán personalmente obligados al mismo, siendo responsable de la falta de cumplimiento de las órdenes que a tal fin se les imparta. 6) Fijar el presupuesto del Poder Judicial adecuado a las pautas contenidas en el presupuesto general y remitirlo al Poder Ejecutivo, para que éste lo incorpore al proyecto de presupuesto respectivo, sesenta días antes de finalizar las sesiones ordinarias del año anterior de la Cámara de Diputados. 7) Dictar su propio reglamento y ejercer la superintendencia de toda la administración de justicia. 8) Proponer a la Legislatura cuanto estime pertinente en lo referente a la administración de justicia, pudiendo designar a alguno de sus miembros para que concurra al seno de las comisiones legislativas a fundar el proyecto, aportar datos e informes relativos al mismo. 9) Nombrar y remover los funcionarios y empleados subalternos cuya forma de designación no esté establecida en esta Constitución, de conformidad a la ley que se dicte.`, currentText: `Son atribuciones del Superior Tribunal de Justicia: 1) Conocer y resolver originaria y exclusivamente en las cuestiones de competencia entre los poderes públicos de la Provincia, y en las que susciten entre las municipalidades, y entre éstas y el Estado Provincial. 2) Ejercer la jurisdicción ordinaria y de apelación para conocer y resolver acerca de la constitucionalidad de leyes, decretos, ordenanzas o reglamentos que estatuyan sobre materia regida por esta Constitución y se controviertan por parte interesada. 3) Decidir en las cuestiones de jurisdicción y competencia entre los tribunales de justicia de la Provincia. 4) Conocer en los recursos que deduzcan contra los fallos de los demás tribunales, en la forma que se autorice por las leyes de procedimientos. 5) Conocer originariamente en las causas contencioso-administrativas, cuando las autoridades administrativas denieguen o retarden en el reconocimiento de los derechos reclamados por parte interesada. En estas causas, el Superior Tribunal tiene la facultad de mandar cumplir sus decisiones directamente por las oficinas o empleados correspondientes, si la autoridad administrativa no las cumpliere en el término que le fijase la sentencia. Los empleados comisionados para la ejecución de las decisiones del Superior Tribunal de Justicia quedarán personalmente obligados al mismo, siendo responsable de la falta de cumplimiento de las órdenes que a tal fin se les imparta. 6) Fijar el presupuesto del Poder Judicial adecuado a las pautas contenidas en el presupuesto general y remitirlo al Poder Ejecutivo, para que éste lo incorpore al proyecto de presupuesto respectivo, sesenta días antes de finalizar las sesiones ordinarias del año anterior de la Cámara de Diputados. 7) Dictar su propio reglamento y ejercer la superintendencia de toda la administración de justicia. 8) Proponer a la Legislatura cuanto estime pertinente en lo referente a la administración de justicia, pudiendo designar a alguno de sus miembros para que concurra al seno de las comisiones legislativas a fundar el proyecto, aportar datos e informes relativos al mismo. 9) Nombrar y remover los funcionarios y empleados subalternos cuya forma de designación no esté establecida en esta Constitución, de conformidad a la ley que se dicte.`, plainLanguageExplanation: 'El Superior Tribunal de Justicia conoce en cuestiones de competencia entre poderes, en recursos de inconstitucionalidad, en causas contencioso-administrativas y en los demás asuntos que establezca la ley.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['STJ', 'atribuciones', 'inconstitucionalidad', 'contencioso-administrativo', 'competencia'], order: 169, segments: [], amendments: [] },
  { id: 'const-formosa-art-171', lawId: 'const-formosa', number: '171', title: 'Juicio oral, público y contradictorio en fuero penal y laboral', originalText: `Establécese el juicio oral, público y contradictorio en los fueros penal y del trabajo, en forma y casos que la ley determine.`, currentText: `Establécese el juicio oral, público y contradictorio en los fueros penal y del trabajo, en forma y casos que la ley determine.`, plainLanguageExplanation: 'La Constitución ordena el juicio oral, público y contradictorio en materia penal y laboral. La ley determina la forma y los casos en que se aplica.', practicalEffects: [], examples: ['Una persona acusada de un delito en Formosa tiene derecho a ser juzgada de forma oral y pública, pudiendo controlar la prueba de la acusación.'], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio oral', 'publicidad', 'contradictorio', 'fuero penal', 'fuero laboral'], order: 170, segments: [], amendments: [] },
  { id: 'const-formosa-art-172', lawId: 'const-formosa', number: '172', title: 'Prohibición de actividad política a miembros del Poder Judicial', originalText: `Ningún miembro del Poder Judicial podrá actuar o intervenir en forma directa y ostensible en política.`, currentText: `Ningún miembro del Poder Judicial podrá actuar o intervenir en forma directa y ostensible en política.`, plainLanguageExplanation: 'Ningún miembro del Poder Judicial puede actuar o intervenir en política de forma directa y pública. Garantiza la imparcialidad e independencia judicial.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['independencia judicial', 'prohibición política', 'Poder Judicial', 'imparcialidad'], order: 171, segments: [], amendments: [] },
  { id: 'const-formosa-art-173', lawId: 'const-formosa', number: '173', title: 'Incompatibilidades y remuneración de magistrados judiciales', originalText: `Los magistrados judiciales no podrán ejercer profesión o empleo alguno, salvo la docencia superior. Gozarán durante el desempeño de su cargo de un sueldo que no podrá ser disminuido en ningún concepto.`, currentText: `Los magistrados judiciales no podrán ejercer profesión o empleo alguno, salvo la docencia superior. Gozarán durante el desempeño de su cargo de un sueldo que no podrá ser disminuido en ningún concepto.`, plainLanguageExplanation: 'Los magistrados judiciales no pueden ejercer ningún empleo o profesión (salvo docencia superior). Su remuneración no puede ser reducida durante el mandato, garantizando su independencia económica.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['magistrados', 'incompatibilidades', 'remuneración', 'intangibilidad salarial', 'docencia'], order: 172, segments: [], amendments: [] },
  { id: 'const-formosa-art-174', lawId: 'const-formosa', number: '174', title: 'Jurisprudencia obligatoria del STJ — interpretación vinculante', originalText: `La interpretación que el Superior Tribunal haga de esta Constitución, de las leyes, tratados y de los convenios colectivos de trabajo provincial, es obligatoria para los jueces y tribunales inferiores. La legislación establecerá la forma en que podrá requerirse y procederse a la revisión de la jurisprudencia del Superior Tribunal. CAPITULO TERCERO.- Jurado De Enjuiciamiento`, currentText: `La interpretación que el Superior Tribunal haga de esta Constitución, de las leyes, tratados y de los convenios colectivos de trabajo provincial, es obligatoria para los jueces y tribunales inferiores. La legislación establecerá la forma en que podrá requerirse y procederse a la revisión de la jurisprudencia del Superior Tribunal. CAPITULO TERCERO.- Jurado De Enjuiciamiento`, plainLanguageExplanation: 'La interpretación que el Superior Tribunal de Justicia haga de la Constitución, leyes y convenios colectivos es obligatoria para todos los jueces y tribunales inferiores de la Provincia.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['jurisprudencia obligatoria', 'STJ', 'interpretación vinculante', 'jueces inferiores'], order: 173, segments: [], amendments: [] },
  { id: 'const-formosa-art-175', lawId: 'const-formosa', number: '175', title: 'Remoción de jueces — acusación por delito doloso o mal desempeño', originalText: `Los jueces y demás funcionarios del Poder Judicial, cuya forma de remoción no esté expresamente determinada por esta Constitución, podrán ser acusados por presuntos delitos dolosos o por mal desempeño del cargo ante un jurado de enjuiciamiento, compuesto por el Presidente del Superior Tribunal de Justicia, el Fiscal de Estado, tres legisladores provinciales, preferentemente letrados, dos por la mayoría y uno por la primera minoría y dos abogados de la matrícula. Estos últimos deberán reunir las mismas cualidades exigidas para integrar el Superior Tribunal de Justicia, quien los designa en sorteo público. Una ley especial determinará el procedimiento y demás condiciones para el funcionamiento de este jurado. El alcance de sus fallos será el mismo que el previsto en el artículo 161.`, currentText: `Los jueces y demás funcionarios del Poder Judicial, cuya forma de remoción no esté expresamente determinada por esta Constitución, podrán ser acusados por presuntos delitos dolosos o por mal desempeño del cargo ante un jurado de enjuiciamiento, compuesto por el Presidente del Superior Tribunal de Justicia, el Fiscal de Estado, tres legisladores provinciales, preferentemente letrados, dos por la mayoría y uno por la primera minoría y dos abogados de la matrícula. Estos últimos deberán reunir las mismas cualidades exigidas para integrar el Superior Tribunal de Justicia, quien los designa en sorteo público. Una ley especial determinará el procedimiento y demás condiciones para el funcionamiento de este jurado. El alcance de sus fallos será el mismo que el previsto en el artículo 161.`, plainLanguageExplanation: 'Los jueces cuya remoción no esté reglada específicamente en la Constitución pueden ser acusados por delitos dolosos o mal desempeño ante el Superior Tribunal de Justicia, que actúa como jurado de enjuiciamiento.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remoción de jueces', 'mal desempeño', 'delito doloso', 'juicio político judicial'], order: 174, segments: [], amendments: [] },
  { id: 'const-formosa-art-176', lawId: 'const-formosa', number: '176', title: 'Causales de mal desempeño del cargo judicial', originalText: `A los fines del Artículo anterior, se considera como mal desempeño del cargo: 1) Ignorancia manifiesta del derecho, o carencia de alguna aptitud esencial para el ejercicio de la función judicial, reiteradamente demostradas. 2) Incompetencia o negligencia reiteradamente demostradas en el ejercicio de sus funciones. 3) Morosidad manifiesta y reiterada. 4) Desorden de conducta o ejercicio de actividades incompatibles con el decoro y dignidad de la función judicial. 5) Inhabilidad física o mental que obsten el ejercicio adecuado del cargo. 6) Graves incumplimientos en las obligaciones de su cargo, impuestas por la Constitución, leyes, reglamentos, acordadas o resoluciones judiciales, o infracción reiterada de sus normas prohibitivas. La interpretación de estas causales será de carácter restrictivo a los efectos de la admisibilidad del enjuiciamiento; debiéndose guardar la discreción que preserve la dignidad del magistrado. CAPITULO CUARTO.- Régimen Municipal`, currentText: `A los fines del Artículo anterior, se considera como mal desempeño del cargo: 1) Ignorancia manifiesta del derecho, o carencia de alguna aptitud esencial para el ejercicio de la función judicial, reiteradamente demostradas. 2) Incompetencia o negligencia reiteradamente demostradas en el ejercicio de sus funciones. 3) Morosidad manifiesta y reiterada. 4) Desorden de conducta o ejercicio de actividades incompatibles con el decoro y dignidad de la función judicial. 5) Inhabilidad física o mental que obsten el ejercicio adecuado del cargo. 6) Graves incumplimientos en las obligaciones de su cargo, impuestas por la Constitución, leyes, reglamentos, acordadas o resoluciones judiciales, o infracción reiterada de sus normas prohibitivas. La interpretación de estas causales será de carácter restrictivo a los efectos de la admisibilidad del enjuiciamiento; debiéndose guardar la discreción que preserve la dignidad del magistrado. CAPITULO CUARTO.- Régimen Municipal`, plainLanguageExplanation: 'Se considera mal desempeño: ignorancia manifiesta del derecho, carencia de aptitud para el cargo, conducta moral reprensible, condena penal por delito doloso, abandono del cargo e incapacidad física o psíquica sobreviniente.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mal desempeño', 'causales remoción', 'juez', 'incompetencia', 'condena penal'], order: 175, segments: [], amendments: [] },
  { id: 'const-formosa-art-177', lawId: 'const-formosa', number: '177', title: 'Régimen Municipal — representación local obligatoria', originalText: `El Régimen Municipal de la Provincia será organizado de manera que todo centro poblado tenga representantes de sus intereses en las municipalidades o comisiones de fomento, cuya creación tendrá por base la densidad de la población respectiva que para unas y otras determina esta Constitución.`, currentText: `El Régimen Municipal de la Provincia será organizado de manera que todo centro poblado tenga representantes de sus intereses en las municipalidades o comisiones de fomento, cuya creación tendrá por base la densidad de la población respectiva que para unas y otras determina esta Constitución.`, plainLanguageExplanation: 'Todo centro poblado de la Provincia debe tener representación local en una municipalidad o comisión de fomento. Su creación y supresión se establece por ley.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['régimen municipal', 'municipalidad', 'comisión de fomento', 'representación local'], order: 176, segments: [], amendments: [] },
  { id: 'const-formosa-art-178', lawId: 'const-formosa', number: '178', title: 'Municipalidades y comisiones de fomento — umbral de población', originalText: `Los centros poblados a partir de mil habitantes tendrán municipalidades, y los con menos de mil, comisiones de fomento. La ley determinará sus respectivos límites y podrá aumentar la base demográfica anteriormente mencionada después de cada censo general, para ser considerada municipalidad.`, currentText: `Los centros poblados a partir de mil habitantes tendrán municipalidades, y los con menos de mil, comisiones de fomento. La ley determinará sus respectivos límites y podrá aumentar la base demográfica anteriormente mencionada después de cada censo general, para ser considerada municipalidad.`, plainLanguageExplanation: 'Los centros de más de 1.000 habitantes tienen municipalidades; los de menos, comisiones de fomento. La ley puede aumentar el mínimo poblacional requerido para tener municipalidad.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['municipalidad', 'comisión de fomento', 'mil habitantes', 'umbral poblacional'], order: 177, segments: [], amendments: [] },
  { id: 'const-formosa-art-179', lawId: 'const-formosa', number: '179', title: 'Bases de la Ley Orgánica Municipal — Intendente y Concejo Deliberante', originalText: `La Ley Orgánica Municipal y las Cartas Orgánicas Municipales se sujetarán a las siguientes bases: 1) Cada Municipalidad se compondrá de un Departamento Ejecutivo, a cargo de un Intendente, y de otro Deliberativo, desempeñado por un Concejo. 2) El gobierno municipal deberá ser representativo, participativo y social. El Concejo deberá ser elegido conforme con lo que para los cuerpos colegiados se establece. El intendente será elegido por el voto directo conforme con el Régimen Electoral. 3) Para ser intendente se requieren cuatro años de residencia previa, real y efectiva en el ejido municipal, si no se ha nacido en el mismo; y las demás condiciones exigidas para ser diputado provincial, no causa interrupción la ausencia motivada por el ejercicio de funciones políticas al servicio del Gobierno Federal o Provincial. 4) El Concejo Municipal se integrará conforme con la siguiente base poblacional: -A partir de 1.000 y hasta 15.000 habitantes: cuatro concejales. -A partir de 15.001 y hasta 30.000 habitantes: seis concejales. -A partir de 30.001 y hasta 60.000 habitantes: ocho concejales. -A partir de 60.001 y hasta 100.000 habitantes: diez concejales. Más de 100.000 habitantes: doce concejales, más dos por cada 80.000 habitantes o fracción no inferior a 60.000. Después de cada censo, la Legislatura establecerá el número de concejales para cada localidad, pudiendo aumentar la base demográfica mencionada. La Legislatura podrá establecer diversas categorías de municipios en función de su cantidad de habitantes y fijar las remuneraciones máximas que podrán percibir sus autoridades electas en forma porcentual relacionada con el tope previsto en el artículo 138. 5) Para ser Concejal se requieren las mismas condiciones que para ser Intendente. 6) Los Concejos Municipales son jueces en cuanto a la validez de la elección, derechos y títulos de sus miembros. 7) Las autoridades municipales y los miembros de las Comisiones de Fomento durarán cuatro años en sus cargos, y podrán ser reelectos. El Concejal o miembro de Comisión de Fomento que reemplaza al titular, completa el mandato. 8) El Concejo se renovará por mitad cada dos años. Al constituirse el primer Concejo se determinará por sorteo los concejales que cesarán en el primer bienio. 9) Habiendo paridad de votos para la designación del Presidente del Concejo Deliberante, ejercerá el cargo el primer titular de la lista de concejales pertenecientes al partido triunfante en esa categoría. 10) El Presidente del Concejo reemplazará al Intendente en caso de muerte, renuncia, destitución, inhabilidad declarada o ausencia transitoria. 11) El Intendente hará cumplir las ordenanzas dictadas por el Concejo y anualmente le dará cuenta de su administración. Ejercerá la representación de la Municipalidad y tendrá las demás facultades que le acuerde la ley. 12) La ley orgánica comunal determinará el funcionamiento de las localidades con menos de 1.000 habitantes respetando los principios de la representación democrática.`, currentText: `La Ley Orgánica Municipal y las Cartas Orgánicas Municipales se sujetarán a las siguientes bases: 1) Cada Municipalidad se compondrá de un Departamento Ejecutivo, a cargo de un Intendente, y de otro Deliberativo, desempeñado por un Concejo. 2) El gobierno municipal deberá ser representativo, participativo y social. El Concejo deberá ser elegido conforme con lo que para los cuerpos colegiados se establece. El intendente será elegido por el voto directo conforme con el Régimen Electoral. 3) Para ser intendente se requieren cuatro años de residencia previa, real y efectiva en el ejido municipal, si no se ha nacido en el mismo; y las demás condiciones exigidas para ser diputado provincial, no causa interrupción la ausencia motivada por el ejercicio de funciones políticas al servicio del Gobierno Federal o Provincial. 4) El Concejo Municipal se integrará conforme con la siguiente base poblacional: -A partir de 1.000 y hasta 15.000 habitantes: cuatro concejales. -A partir de 15.001 y hasta 30.000 habitantes: seis concejales. -A partir de 30.001 y hasta 60.000 habitantes: ocho concejales. -A partir de 60.001 y hasta 100.000 habitantes: diez concejales. Más de 100.000 habitantes: doce concejales, más dos por cada 80.000 habitantes o fracción no inferior a 60.000. Después de cada censo, la Legislatura establecerá el número de concejales para cada localidad, pudiendo aumentar la base demográfica mencionada. La Legislatura podrá establecer diversas categorías de municipios en función de su cantidad de habitantes y fijar las remuneraciones máximas que podrán percibir sus autoridades electas en forma porcentual relacionada con el tope previsto en el artículo 138. 5) Para ser Concejal se requieren las mismas condiciones que para ser Intendente. 6) Los Concejos Municipales son jueces en cuanto a la validez de la elección, derechos y títulos de sus miembros. 7) Las autoridades municipales y los miembros de las Comisiones de Fomento durarán cuatro años en sus cargos, y podrán ser reelectos. El Concejal o miembro de Comisión de Fomento que reemplaza al titular, completa el mandato. 8) El Concejo se renovará por mitad cada dos años. Al constituirse el primer Concejo se determinará por sorteo los concejales que cesarán en el primer bienio. 9) Habiendo paridad de votos para la designación del Presidente del Concejo Deliberante, ejercerá el cargo el primer titular de la lista de concejales pertenecientes al partido triunfante en esa categoría. 10) El Presidente del Concejo reemplazará al Intendente en caso de muerte, renuncia, destitución, inhabilidad declarada o ausencia transitoria. 11) El Intendente hará cumplir las ordenanzas dictadas por el Concejo y anualmente le dará cuenta de su administración. Ejercerá la representación de la Municipalidad y tendrá las demás facultades que le acuerde la ley. 12) La ley orgánica comunal determinará el funcionamiento de las localidades con menos de 1.000 habitantes respetando los principios de la representación democrática.`, plainLanguageExplanation: 'Cada municipio tiene un Departamento Ejecutivo (Intendente) y un Concejo Deliberante elegido por el pueblo. La ley orgánica regula su funcionamiento, presupuesto, contrataciones y empleo municipal.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Intendente', 'Concejo Deliberante', 'Ley Orgánica Municipal', 'gobierno municipal'], order: 178, segments: [], amendments: [] },
  { id: 'const-formosa-art-180', lawId: 'const-formosa', number: '180', title: 'Carta Orgánica Municipal — autonomía plena con plan regulador', originalText: `Los municipios con plan regulador, aprobado por su Concejo Deliberante, podrán dictarse su propia Carta Orgánica, conforme con el sistema republicano y representativo, respetando los principios establecidos en esta Constitución. A los efectos de dictarse la Carta Orgánica, se convocará una Convención Municipal. Los miembros de la misma serán electos por el sistema proporcional y su número no excederá del doble de la composición del Concejo Deliberante. La iniciativa para convocar a la Convención Municipal corresponde al Departamento Ejecutivo, previa ordenanza que lo autorice. Para ser convencional comunal se requerirá idénticas calidades que para ser Concejal, con los mismos derechos y sujetos a iguales incompatibilidades e inhabilidades. La Legislatura Provincial sancionará la Ley Orgánica Comunal para los municipios que no tengan Carta Orgánica.`, currentText: `Los municipios con plan regulador, aprobado por su Concejo Deliberante, podrán dictarse su propia Carta Orgánica, conforme con el sistema republicano y representativo, respetando los principios establecidos en esta Constitución. A los efectos de dictarse la Carta Orgánica, se convocará una Convención Municipal. Los miembros de la misma serán electos por el sistema proporcional y su número no excederá del doble de la composición del Concejo Deliberante. La iniciativa para convocar a la Convención Municipal corresponde al Departamento Ejecutivo, previa ordenanza que lo autorice. Para ser convencional comunal se requerirá idénticas calidades que para ser Concejal, con los mismos derechos y sujetos a iguales incompatibilidades e inhabilidades. La Legislatura Provincial sancionará la Ley Orgánica Comunal para los municipios que no tengan Carta Orgánica.`, plainLanguageExplanation: 'Los municipios que cuenten con plan regulador aprobado por su Concejo pueden dictarse su propia Carta Orgánica (constitución municipal), respetando el sistema republicano y los principios de esta Constitución.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['Carta Orgánica Municipal', 'autonomía municipal', 'plan regulador', 'municipio'], order: 179, segments: [], amendments: [] },
  { id: 'const-formosa-art-181', lawId: 'const-formosa', number: '181', title: 'Recursos propios del municipio', originalText: `Son recursos propios del municipio: 1) El impuesto inmobiliario y gravámenes sobre tierras libres de mejoras. 2) Las tasas por utilización superficial, aérea o subterránea de la vía pública o espacios de jurisdicción del municipio. 3) Las contribuciones por mejoras provenientes de obras municipales. 4) La renta de bienes propios y la contraprestación por uso diferenciado de los bienes municipales. 5) La coparticipación de los impuestos que recauda la Nación o la Provincia, que el Poder Ejecutivo debe transferir en un envío mensual a período vencido, conforme la alícuota que fije la ley. 6) Lo que se prevea de los recursos coparticipados, constituyéndose un fondo compensador que adjudicará la Legislatura por medio del presupuesto a los municipios, teniendo en cuenta la menor densidad poblacional y mayor brecha de desarrollo relativo. 7) Los empréstitos locales o de fuera de la Provincia, éstos últimos con acuerdo de la Legislatura. Ningún empréstito podrá gestionarse sobre el crédito general del municipio, cuando el total de los servicios de amortización e intereses comprometan en más del veinticinco por ciento de los recursos ordinarios afectados. 8) El porcentaje que establecerá la ley, originado en la explotación de los recursos renovables y no renovables ubicados dentro del ejido, que perciba la Provincia. 9) Los demás impuestos, tasas, patentes u otros gravámenes o contribuciones determinadas por las normas municipales en los límites de su competencia.`, currentText: `Son recursos propios del municipio: 1) El impuesto inmobiliario y gravámenes sobre tierras libres de mejoras. 2) Las tasas por utilización superficial, aérea o subterránea de la vía pública o espacios de jurisdicción del municipio. 3) Las contribuciones por mejoras provenientes de obras municipales. 4) La renta de bienes propios y la contraprestación por uso diferenciado de los bienes municipales. 5) La coparticipación de los impuestos que recauda la Nación o la Provincia, que el Poder Ejecutivo debe transferir en un envío mensual a período vencido, conforme la alícuota que fije la ley. 6) Lo que se prevea de los recursos coparticipados, constituyéndose un fondo compensador que adjudicará la Legislatura por medio del presupuesto a los municipios, teniendo en cuenta la menor densidad poblacional y mayor brecha de desarrollo relativo. 7) Los empréstitos locales o de fuera de la Provincia, éstos últimos con acuerdo de la Legislatura. Ningún empréstito podrá gestionarse sobre el crédito general del municipio, cuando el total de los servicios de amortización e intereses comprometan en más del veinticinco por ciento de los recursos ordinarios afectados. 8) El porcentaje que establecerá la ley, originado en la explotación de los recursos renovables y no renovables ubicados dentro del ejido, que perciba la Provincia. 9) Los demás impuestos, tasas, patentes u otros gravámenes o contribuciones determinadas por las normas municipales en los límites de su competencia.`, plainLanguageExplanation: 'Son recursos propios del municipio: el impuesto inmobiliario, tasas por uso de la vía pública, tasas por servicios, multas y la coparticipación que le corresponda.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['recursos municipales', 'impuesto inmobiliario', 'tasas', 'coparticipación', 'finanzas municipales'], order: 180, segments: [], amendments: [] },
  { id: 'const-formosa-art-182', lawId: 'const-formosa', number: '182', title: 'Atribuciones del gobierno municipal', originalText: `Son atribuciones del gobierno entender y resolver en todos los asuntos de interés comunal que no hayan sido expresamente delegados en la Constitución Nacional o en la presente, y de conformidad con la Carta Orgánica del municipio.`, currentText: `Son atribuciones del gobierno entender y resolver en todos los asuntos de interés comunal que no hayan sido expresamente delegados en la Constitución Nacional o en la presente, y de conformidad con la Carta Orgánica del municipio.`, plainLanguageExplanation: 'El municipio tiene competencia sobre todos los asuntos de interés comunal no delegados a la Nación o la Provincia. Puede legislar, administrar y prestar servicios en su ejido.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['atribuciones municipales', 'autonomía municipal', 'interés comunal', 'competencia'], order: 181, segments: [], amendments: [] },
  { id: 'const-formosa-art-183', lawId: 'const-formosa', number: '183', title: 'Inembargabilidad de bienes municipales — límite del 10%', originalText: `En ningún caso podrá hacerse ejecución o embargo de las rentas y bienes municipales, salvo en las primeras y en una proporción no mayor del diez por ciento. Cuando la municipalidad fuere condenada al pago de una deuda, la corporación arbitrará, dentro del término de los tres meses siguientes a la notificación de la sentencia respectiva, la forma de verificarlo.`, currentText: `En ningún caso podrá hacerse ejecución o embargo de las rentas y bienes municipales, salvo en las primeras y en una proporción no mayor del diez por ciento. Cuando la municipalidad fuere condenada al pago de una deuda, la corporación arbitrará, dentro del término de los tres meses siguientes a la notificación de la sentencia respectiva, la forma de verificarlo.`, plainLanguageExplanation: 'Las rentas y bienes municipales no pueden ser embargados, salvo las rentas en proporción no mayor al 10%. Si el municipio incumple obligaciones contractuales, la Provincia puede retener de la coparticipación y transferir al acreedor.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['embargo municipal', 'bienes municipales', 'coparticipación', 'inembargabilidad'], order: 182, segments: [], amendments: [] },
  { id: 'const-formosa-art-184', lawId: 'const-formosa', number: '184', title: 'Intervención provincial a municipios — causales y procedimiento', originalText: `La Provincia podrá intervenir la Municipalidad por ley emanada de la Legislatura, sancionada por dos tercios de votos: 1) En caso de acefalía total, para asegurar la constitución de sus autoridades. 2) Para regularizar sus finanzas, cuando el municipio no cumpliere con sus empréstitos o los servicios públicos fundamentales.`, currentText: `La Provincia podrá intervenir la Municipalidad por ley emanada de la Legislatura, sancionada por dos tercios de votos: 1) En caso de acefalía total, para asegurar la constitución de sus autoridades. 2) Para regularizar sus finanzas, cuando el municipio no cumpliere con sus empréstitos o los servicios públicos fundamentales.`, plainLanguageExplanation: 'La Provincia puede intervenir un municipio mediante ley aprobada con dos tercios de votos, solo en casos de acefalía total, violación grave de la Constitución o imposibilidad de ejercer sus funciones normalmente.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['intervención municipal', 'acefalía', 'dos tercios', 'Provincia', 'municipio'], order: 183, segments: [], amendments: [] },
  { id: 'const-formosa-art-185', lawId: 'const-formosa', number: '185', title: 'Conflictos entre autoridades municipales — STJ como árbitro único', originalText: `Los conflictos que se susciten entre las autoridades del municipio serán resueltos en única instancia por el Superior Tribunal de Justicia Provincial.`, currentText: `Los conflictos que se susciten entre las autoridades del municipio serán resueltos en única instancia por el Superior Tribunal de Justicia Provincial.`, plainLanguageExplanation: 'Los conflictos entre autoridades de un mismo municipio (p.ej., Intendente vs. Concejo Deliberante) los resuelve en única instancia el Superior Tribunal de Justicia Provincial.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conflictos municipales', 'STJ', 'Intendente', 'Concejo Deliberante'], order: 184, segments: [], amendments: [] },
  { id: 'const-formosa-art-186', lawId: 'const-formosa', number: '186', title: 'Iniciativa y referéndum municipal', originalText: `La Ley Orgánica Comunal otorgará al electorado municipal el ejercicio del derecho de iniciativa y referéndum.`, currentText: `La Ley Orgánica Comunal otorgará al electorado municipal el ejercicio del derecho de iniciativa y referéndum.`, plainLanguageExplanation: 'La Ley Orgánica Municipal debe garantizar al electorado local los derechos de iniciativa (proponer normas) y referéndum (ratificar o rechazar normas aprobadas).', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['iniciativa popular', 'referéndum', 'democracia directa', 'municipio'], order: 185, segments: [], amendments: [] },
  { id: 'const-formosa-art-187', lawId: 'const-formosa', number: '187', title: 'Representación política basada en la población', originalText: `La representación política tendrá como base la población, y con arreglo a ella se ejercerá el derecho electoral, conforme a la ley.`, currentText: `La representación política tendrá como base la población, y con arreglo a ella se ejercerá el derecho electoral, conforme a la ley.`, plainLanguageExplanation: 'La representación política tiene como base la cantidad de habitantes. El derecho electoral se ejerce conforme a la ley, garantizando proporcionalidad entre población y representantes.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['representación política', 'población', 'derecho electoral', 'proporcionalidad'], order: 186, segments: [], amendments: [] },
  { id: 'const-formosa-art-188', lawId: 'const-formosa', number: '188', title: 'Sufragio — derecho y deber ciudadano', originalText: `El sufragio electoral es un derecho inherente a la calidad de ciudadano argentino, y un deber que desempeñará con arreglo a las prescripciones de esta Constitución y a la ley de la materia que dicte la Legislatura.`, currentText: `El sufragio electoral es un derecho inherente a la calidad de ciudadano argentino, y un deber que desempeñará con arreglo a las prescripciones de esta Constitución y a la ley de la materia que dicte la Legislatura.`, plainLanguageExplanation: 'El sufragio es tanto un derecho como una obligación del ciudadano argentino. Debe ejercerse conforme a la Constitución y la ley electoral.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sufragio', 'derecho a votar', 'obligación cívica', 'ciudadanía'], order: 187, segments: [], amendments: [] },
  { id: 'const-formosa-art-189', lawId: 'const-formosa', number: '189', title: 'Voto universal, secreto y obligatorio', originalText: `El voto será universal, secreto y obligatorio, y el escrutinio público en la forma que la ley determine.`, currentText: `El voto será universal, secreto y obligatorio, y el escrutinio público en la forma que la ley determine.`, plainLanguageExplanation: 'El voto en Formosa es universal (todos los ciudadanos), secreto (nadie puede conocer el voto ajeno) y obligatorio. El escrutinio es público, garantizando transparencia en el resultado electoral.', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['voto universal', 'voto secreto', 'voto obligatorio', 'escrutinio público', 'sufragio'], order: 188, segments: [], amendments: [] },
];
